// OTOMATİK ÜRETİLDİ — kaynak: rules-md/*.md. ELLE DÜZENLEMEYİN.
// Yeniden üretmek için: node scripts/gen-bundled-rules.mjs
// Kod incelemenin başlangıç kural dosyaları; tarayıcıda localStorage'a tohumlanır.

export const BUNDLED_RULES: Record<string, string> = {
  "01-react-code-review.md": "# React Code Review Dokumani\n\n> TAKBIS mikro-frontend ekosistemi (`taraf-web`, `islem-yonetimi-web`, `fen-kayit-web` ve diger `<is-alani>-web` repolari) icin React kod review standartlari.\n> Bu dokuman, code review ve kod revizyonu sirasinda **referans** olarak kullanilir. Her standart icin uc soruyu yanitlar:\n> **(a) NEDEN onemli — (b) Review'da NASIL tespit edilir — (c) NASIL duzeltilir (revizyon, mumkunse before/after).**\n> Tum ornekler gercek repo dosyalarindan alinmistir; iddialar gercek koda dayanir.\n\n---\n\n## Icindekiler\n\n1. [Amac & Kapsam](#1-amac--kapsam)\n2. [Arka Plan / Mimari Ozet](#2-arka-plan--mimari-ozet)\n3. [Standartlar & Konvansiyonlar](#3-standartlar--konvansiyonlar)\n   - [3.1 Component Yapisi & Dosya Organizasyonu](#31-component-yapisi--dosya-organizasyonu)\n   - [3.2 State Yonetimi](#32-state-yonetimi)\n   - [3.3 Hook Kullanimi](#33-hook-kullanimi)\n   - [3.4 Performans](#34-performans)\n   - [3.5 Okunabilirlik & TypeScript](#35-okunabilirlik--typescript)\n   - [3.6 Tekrar Kullanilabilirlik](#36-tekrar-kullanilabilirlik)\n   - [3.7 Routing (react-router 6)](#37-routing-react-router-6)\n   - [3.8 Axios Servis Katmani](#38-axios-servis-katmani)\n   - [3.9 RTK Query apiSlice Deseni](#39-rtk-query-apislice-deseni)\n   - [3.10 MUI 6 Tema, sx ve styled](#310-mui-6-tema-sx-ve-styled)\n   - [3.11 Form, Maskeleme ve Dogrulama](#311-form-maskeleme-ve-dogrulama)\n   - [3.12 i18n (react-i18next)](#312-i18n-react-i18next)\n   - [3.13 Erisilebilirlik (a11y)](#313-erisilebilirlik-a11y)\n4. [Sik Hatalar & Anti-Pattern'ler (before/after)](#4-sik-hatalar--anti-patternler-beforeafter)\n5. [Hizli Referans (Review Checklist)](#5-hizli-referans-review-checklist)\n6. [Ilgili Dosyalar & Capraz-Linkler](#6-ilgili-dosyalar--capraz-linkler)\n\n---\n\n## 1. Amac & Kapsam\n\nBu dokuman, TAKBIS frontend mikro-servislerinde acilan PR'larin **tutarli, olculebilir ve gerekceli** bir sekilde gozden gecirilmesini saglar. Kapsadigi alanlar:\n\n- **Component yapisi**: dosya organizasyonu (`features/services/components/pages/hooks` deseni), container/presentational ayrimi, isimlendirme, tek-sorumluluk, bilesen boyutu.\n- **State yonetimi**: Redux Toolkit slice vs RTK Query `apiSlice` vs yerel `useState`/`useReducer`/`useContext`; turetilmis state; global/lokal sinir; immutability.\n- **Hook kullanimi**: hook kurallari, `useEffect` dogru kullanim + cleanup + bagimlilik dizileri, custom hook tasarimi, kosullu hook yasagi.\n- **Performans**: `React.memo`/`useMemo`/`useCallback`, gereksiz re-render, `react-window` sanallastirma, kod bolme (`lazy`+`Suspense`), referans kararliligi.\n- **Okunabilirlik**: JSX sadeligi, erken donus, isimlendirme, TS tipleme, `any` yasagi, ESLint `--max-warnings 0`.\n- **Tekrar kullanilabilirlik**: paylasilan bilesen/hook, `golge-ui` bilesenlerinden yararlanma, prop/kompozisyon tasarimi, kopyalama-karsiti.\n\nEk alanlar: react-router 6 (korumali rota, lazy), axios servis katmani, RTK Query deseni, MUI 6 tema/sx/styled, form maskeleme + dogrulama, i18n, erisilebilirlik.\n\n**Hedef kitle**: PR review yapan gelistirici ve teknik liderler. **Cikti**: review yorumlari icin gerekceli, kopyalanabilir oneri ve revizyon onerileri.\n\n---\n\n## 2. Arka Plan / Mimari Ozet\n\n### 2.1 Teknoloji Yigini (dogrulanmis surumler)\n\n| Alan | taraf-web | islem-yonetimi-web | fen-kayit-web |\n| --- | --- | --- | --- |\n| React | `^18.3.1` | `^18.2.0` | 18.x |\n| TypeScript | `^5.8.3` | `~5.8.2` | 5.x |\n| Vite | `^6.3.5` | `^6.2.0` | 6.x |\n| MUI | `@mui/material ^6.3.1` | `^6.1.7` | 6.x |\n| Redux Toolkit | `^2.2.3` | `^2.2.3` | 2.x |\n| react-router-dom | `^6.26.1` | `^6.26.1` | 6.x |\n| axios | `^1.7.7` | `^1.7.2` | 1.x |\n| golge-ui | `1.16.10` | `1.16.10` | 1.16.x |\n| ESLint | `^8.56.0` (legacy `.eslintrc.cjs`) | `^9.39.2` (flat `eslint.config.js`) | flat config |\n| i18n | yok | `react-i18next ^15.1.3`, `i18next ^25.4.1` | — |\n\n> **Surum notu (zorunlu):** Kesin surumleri DAIMA ilgili `package.json`'dan dogrula. ESLint surumu repodan repoya degisir (taraf-web legacy `.eslintrc.cjs`, islem-yonetimi-web flat config). Inceleme yaparken hangi config'in gecerli oldugunu kontrol et.\n\n### 2.2 Mikro-Frontend Mimarisi\n\n- **Module Federation** (`@module-federation/vite`): `dis-portal-mf-shell` = host/shell, her `<is-alani>-web` = remote.\n- Cikis noktasi `main.tsx` -> `App.tsx` (sadece `<Routes>`) -> `InnerAppDev.tsx` (yetki + layout) deseni tum repolarda tekrar eder.\n- **Standalone tespiti**: `taraf-web` `isStandaloneRun()` ile shell icinde mi yoksa bagimsiz mi calistigini ayirt eder (`InnerAppDev.tsx`).\n- **golge-ui** ortak UI/altyapi kutuphanesi. Export alt-yollari: `.`, `./utils`, `./eimza`, `./theme`, `./router`, `./styles`. Onemli export'lar (gercek, `golge-ui/dist/index.d.ts`'ten):\n  - `GolgeApi` (axios factory), `golgeRtkApiHeaders` (RTK Query `prepareHeaders`), `golgeErrorMiddleware`\n  - `GolgeApp`, `GolgeAppBar`, `GolgeMain`, `GolgeFooter`, `GolgeCrudLayout`, `GolgeDraggableDialog`, `GolgeInfoCard`, `GolgeTreeView`\n  - `enqueueSnackbar`, `useGolgeSecurity` (yetki: `hasAuthority`, `logout`)\n  - `golge-ui/theme` -> `GolgeThemeProvider`; `golge-ui/router` -> `GolgeRouter` + re-export `react-router-dom`\n\n### 2.3 Klasor Deseni\n\n**Hafif/orta repo (`taraf-web`):** duz `src/` deseni:\n```\nsrc/\n  app/        store.ts, hooks.ts (typed useAppDispatch/useAppSelector), *Slice.ts\n  features/   RTK Query apiSlice'lar (tuzelKisiBilgileriApiSlice.ts, ext/deger/degerApiSlice.ts)\n  services/   axios tabanli API (GercekKisiApi.ts, api.tsx = client factory)\n  components/ paylasilan/alan bilesenleri (snackbar/, takbisBelge/, dataGrid/)\n  pages/      ekran bilesenleri (Kisi.tsx, KisiListesi/, YeniKisi/)\n  hooks/      custom hook (useResponsive.ts, useSearchKamu.tsx)\n  contexts/   React Context (AuthTokenContext, KisiContext, YeniKisiContext)\n  layouts/    TarafLayout, KisiLayout, SideBarMenu\n  enums/, constants/, types/, utils/, _mock/\n```\n\n**Buyuk repo (`islem-yonetimi-web`):** **feature-sliced** yapi:\n```\nsrc/\n  app/        store.ts (combineReducers + 25+ reducerPath), middlewares.ts, hooks.ts\n  features/   <domain>/ (islem-tanimlari/, kural-motoru/, formul-motoru/, ...)\n              her domain: *ApiSlice.ts + pages/ + components/ + shared/(constants,types,utils) + context/ + hooks/ + i18n/\n  shared/     cross-domain: hooks/ (useLocalStorage, useBreakpoint, tasks/), lib/ (validation, errorHandling, performance), types/\n  styles/, types/, utils/, shims/\n```\n\n> Review kurali: **Repo deseni hangisiyse ona uy.** `taraf-web`'e feature-sliced klasor, ya da `islem-yonetimi-web`'e duz `services/` eklemek tutarsizlik yaratir.\n\n---\n\n## 3. Standartlar & Konvansiyonlar\n\n### 3.1 Component Yapisi & Dosya Organizasyonu\n\n#### S-3.1.1 Tek sorumluluk ve bilesen boyutu\n**(a) Neden:** 300+ satirlik, hem veri cekme hem is mantigi hem cok sekmeli UI iceren bilesenler test edilemez ve re-render maliyeti yuksektir.\n**(b) Tespit:** Bir `.tsx` dosyasi >250-300 satir, 5+ `useState`, ic ice 3+ kosullu JSV blogu iceriyorsa. Bir bilesenin hem `fetch` hem prezentasyon yaptigini gor.\n**(c) Duzeltme:** Container (veri/mantik) ile presentational (sadece prop alip render) ayir; tekrar eden alt-bloklari ayri dosyaya cikar. `islem-yonetimi-web` bunu dogru yapar: `IslemTanimTree.tsx` (mantik/sanallastirma) + `TreeNodeItem.tsx` (`memo`'lu satir) + `TreeNodeRow` ayri bilesenler.\n\n#### S-3.1.2 Container / Presentational ayrimi\n**(a) Neden:** Saf prezentasyon bilesenleri `React.memo` ile kolayca optimize edilir; mantikla karisinca memo etkisiz kalir.\n**(b) Tespit:** Render fonksiyonu icinde dogrudan `apiSlice` hook + `useEffect` + buyuk JSX.\n**(c) Duzeltme:** Veri cekme custom hook'a (`useTaskFiltering`, `useSearchKamu`), prezentasyon saf bilesene. Ornek: `taraf-web/src/hooks/useSearchKamu.tsx` arama mantigini sarar, tuketici bilesen sadece `searchKurum` cagirir.\n\n#### S-3.1.3 Isimlendirme konvansiyonu\n**(a) Neden:** Tutarli isim, dosya/sembol aramasini hizlandirir.\n**(b)/(c) Kurallar (gercek koddan dogrulanmis):**\n\n| Tur | Konvansiyon | Gercek ornek |\n| --- | --- | --- |\n| Bilesen dosyasi & export | `PascalCase` | `Kisi.tsx` → `export default function Kisi(...)` |\n| Custom hook | `useXxx` (camelCase) | `useResponsive.ts`, `useSearchKamu.tsx`, `useLocalStorage.ts` |\n| RTK Query slice | `xxxApiSlice` / `xxxApi` | `tuzelKisiBilgileriApiSlice`, `tipDegerVarlikApi` |\n| Redux slice | `xxxSlice` + `xxxReducer` default export | `geldigiBilesenSlice.ts` |\n| axios servis | `XxxApi.ts` + fonksiyon `fiilNesne` | `GercekKisiApi.ts` → `getGercekKisiById`, `ekleGercekKisi` |\n| Context | `XxxContext` + `XxxProvider` + `useXxx` | `KisiContext.tsx` → `KisiProvider`, `useKisi` |\n\n> Domain dili **Turkce**'dir; alan adlari Turkce (`tcKimlikNo`, `basvuruRef`), React/teknik terimler Ingilizce kalir.\n\n#### S-3.1.4 Hook iceren dosya uzantisi\n**(b) Tespit:** JSX donen hook/util `.ts` uzantili (`useSearchKamu.tsx` dogru cunku JSX/`ReactNode` icerir, `useResponsive.ts` dogru cunku JSX yok).\n**(c) Duzeltme:** JSX iceren dosya `.tsx`, salt mantik `.ts`.\n\n✅ **Dogru** (taraf-web `app/hooks.ts` — tiplenmis Redux hook'lari tek yerde):\n```ts\nimport { TypedUseSelectorHook, useDispatch, useSelector } from 'react-redux';\nimport { RootState, AppDispatch } from './store';\nexport const useAppDispatch = () => useDispatch<AppDispatch>();\nexport const useAppSelector: TypedUseSelectorHook<RootState> = useSelector;\n```\n❌ **Yanlis:** Her bilesende `useDispatch<AppDispatch>()` tekrar yazmak veya tiplenmemis `useSelector` kullanmak.\n\n---\n\n### 3.2 State Yonetimi\n\n#### S-3.2.1 Dogru state mekanizmasini sec\n**(a) Neden:** Yanlis katman secimi (her seyi Redux'a, ya da sunucu verisini `useState`'e) gereksiz boilerplate, stale-data ve cift-kaynak sorunu yaratir.\n**(b) Tespit:** Asagidaki karar tablosuna gore sapma ara.\n**(c) Karar tablosu:**\n\n| Veri turu | Mekanizma | Gerekce / gercek ornek |\n| --- | --- | --- |\n| **Sunucu verisi** (CRUD, liste, detay) | **RTK Query `apiSlice`** | Cache, dedupe, invalidation otomatik. `islemTanimlariApi`, `varlikApiSlice` |\n| **Global UI/akis durumu** (secili sekme, \"geldigi bilesen\") | **Redux slice** | `geldigiBilesenSlice` |\n| **Form/ekran-lokal durum** | `useState` / `useReducer` | `Kisi.tsx`: `gorunumUserPage`, `secilenKisi` |\n| **Karmasik lokal state makinesi** | `useReducer` | `DuzenleyenSelect.tsx` arama state'i (`dispatch({ type: 'FETCH_START' })`) |\n| **Alt-agaca yayilan, nadiren degisen deger** | `useContext` | `TreeContext`, `GeldigiBilesenContext` |\n| **Tarayici kalici durum** | `useLocalStorage` (shared hook) | `islem-yonetimi-web/shared/hooks/useLocalStorage.ts` |\n\n#### S-3.2.2 Sunucu verisini `useState`'e kopyalama\n**(a) Neden:** RTK Query/axios sonucunu `useState`'e kopyalamak senkronizasyon ve stale-data hatasi dogurur.\n**(b) Tespit:** `const { data } = useGetXQuery(); const [items, setItems] = useState([]); useEffect(() => setItems(data), [data])` kalibi.\n**(c) Duzeltme:** Dogrudan `data`'yi kullan; turetilmis deger gerekiyorsa `useMemo` ile turet (asagi bkz).\n\n#### S-3.2.3 Turetilmis state'i state olarak tutma\n**(a) Neden:** Hesaplanabilir degeri ayrica state'te tutmak iki kaynagi senkron tutma yuku getirir.\n**(b) Tespit:** `useEffect` icinde baska state'ten yeni state set ediliyor.\n**(c) Duzeltme — render'da turet (gercek ornek, `useTaskFiltering.ts`):**\n```ts\n// Sunucudan gelen tasklar useMemo ile donusturulur, ayri state tutulmaz\nconst banaAtananTasks = useMemo(\n  () => banaAtananCamundaTasks.map((ct) =>\n    camundaTaskToTask(ct, processVariablesMap[ct.processInstanceId], TaskStatus.IN_PROGRESS)),\n  [banaAtananCamundaTasks, processVariablesMap]\n);\n```\n\n#### S-3.2.4 Immutability (RTK / Immer)\n**(a) Neden:** RTK reducer'lari Immer ile calisir; reducer disinda state'i mutasyona ugratmak buglara yol acar.\n**(b) Tespit:** Reducer **icinde** `state.x = y` dogru (Immer); reducer **disinda** `obj.x = y` ile store/props mutasyonu yanlis.\n**(c) Dogru (gercek, `geldigiBilesenSlice.ts`):**\n```ts\nreducers: {\n  setGeldigiBilesen: (state, action: PayloadAction<GeldigiBilesenType>) => {\n    state.geldigiBilesen = action.payload; // Immer: guvenli\n  },\n}\n```\n\n#### S-3.2.5 Global vs lokal sinir + cift state-kaynagi yasagi\n**(a) Neden:** Ayni durumu hem Context hem Redux'ta tutmak (\"iki kaynak\") en sik kok-neden hatadir.\n**(b) Tespit:** Bir kayit/secim hem React Context'te hem store'da tutuluyor; ya da bir deger hem React state hem **modul-seviye mutable** degiskende tutuluyor.\n**(c) Gercek anti-pattern — `AuthTokenContext.tsx` (kod icinde TODO ile isaretli):**\n```tsx\nlet authToken: string | null = null;              // modul-seviye kaynak (axios bunu okur)\nexport const getAuthToken = (): string | null => authToken;\n// + ayni token Context state'inde de tutulur, useEffect ile senkronlanir\n```\n> Risk: token degisiminden hemen sonra atilan istek **eski** token tasiyabilir (senkronizasyon useEffect'e bagli). **Cozum:** tek kaynak (provider mount'ta senkron set, ya da store'dan `getState`). `KisiContext.tsx` ve `TuzelKisiContext.tsx` benzer sekilde Redux varken ayri Context tutar — **secili kayit** Redux'a tasinmali.\n\n---\n\n### 3.3 Hook Kullanimi\n\n#### S-3.3.1 Hook Kurallari (Rules of Hooks) — `error` seviyesi\n**(a) Neden:** Kosullu/dongusel hook cagrisi React'in hook sirasi varsayimini bozar, calisma-zamani crash uretir. `react-hooks/rules-of-hooks` her iki repoda da **`error`**.\n**(b) Tespit:** Hook cagrisi `if`/`for`/`.map`/`.reduce`/erken-`return` sonrasinda. ESLint yakalar; `eslint-disable react-hooks/rules-of-hooks` yorumu **kirmizi bayrak**.\n**(c) Gercek ihlal — `taraf-web/src/hooks/useResponsive.ts` `useWidth()`:**\n```ts\n// ❌ YANLIS: useMediaQuery .reduce callback'i icinde cagriliyor (kosullu hook)\nkeys.reduce<Breakpoint | null>((output, key) => {\n  // eslint-disable-next-line react-hooks/rules-of-hooks\n  const matches = useMediaQuery(theme.breakpoints.up(key));\n  return !output && matches ? key : output;\n}, null)\n```\n```ts\n// ✅ DOGRU: tum breakpoint'ler ust-seviyede kosulsuz hesaplanir, sonra duz mantikla secilir\nconst xs = useMediaQuery(theme.breakpoints.up('xs'));\nconst sm = useMediaQuery(theme.breakpoints.up('sm'));\nconst md = useMediaQuery(theme.breakpoints.up('md'));\nconst lg = useMediaQuery(theme.breakpoints.up('lg'));\nconst xl = useMediaQuery(theme.breakpoints.up('xl'));\n// ...sonra duz if/return ile en buyuk eslesen breakpoint dondurulur\n```\n> Ayni dosyada `useResponsive()` dogru desen sergiler: tum `useMediaQuery` cagrilari kosulsuz yapilir, secim sonradan `if`'lerle olur (yorum: \"Hook must be called unconditionally\").\n\n#### S-3.3.2 `useEffect` — dogru kullanim, cleanup, bagimlilik dizisi\n**(a) Neden:** Eksik cleanup => listener/abort sizinti; eksik/fazla bagimlilik => stale closure ya da sonsuz dongu.\n**(b) Tespit:** `addEventListener`/`setInterval`/`AbortController`/subscription olup cleanup donmeyen effect; `// eslint-disable react-hooks/exhaustive-deps` yorumu; effect icinde set edilen state'in bagimlilikta olmasi (sonsuz dongu).\n**(c) Dogru — cleanup donen effect (gercek, `InnerAppDev.tsx`):**\n```tsx\nuseEffect(() => {\n  const handleAuthError = () => { (async () => { await logout(); })(); };\n  window.addEventListener('taraf:auth-error', handleAuthError);\n  return () => window.removeEventListener('taraf:auth-error', handleAuthError); // cleanup\n}, [logout]);\n```\n**(c) Dogru — `AbortController` ile istek iptali (gercek, `DuzenleyenSelect.tsx`):**\n```tsx\nabortControllerRef.current?.abort();\nabortControllerRef.current = new AbortController();\n// ...\nconst result = await fetchOptions(text, page, size, abortControllerRef.current.signal);\n// catch icinde:\nif ((err as Error).name !== 'AbortError') { /* gercek hatayi isle */ }\n```\n> Review notu: `useEffect` icinde `async` fonksiyon dogrudan verilmez (cleanup yerine Promise doner). Ic IIFE veya ic `async function` + cagri kullanilir (yukaridaki `handleAuthError` ornegi).\n\n#### S-3.3.3 Custom hook tasarimi\n**(a) Neden:** Tekrar eden mantik (storage, arama, filtre, responsive) hook'a cikarilirsa test edilebilir ve paylasilir olur.\n**(b) Tespit:** Iki+ bilesende ayni `useState`+`useEffect` blogu kopyalanmis.\n**(c) Iyi ornekler (gercek):**\n- `useLocalStorage<T>` (`islem-yonetimi-web/shared/hooks`): SSR guard, JSON parse, cross-tab `storage` event listener + cleanup, `useCallback`'li `setValue`/`removeValue`. **Referans sablon.**\n- `useTaskFiltering` (`shared/hooks/tasks`): `useMemo` ile turetilmis listeler, `useCallback`'li handler, alt-hook kompozisyonu (`useTaskAuthority`, `useTaskFetching`, `useTaskGrouping`).\n- `useSearchKamu` (`taraf-web`): `useLazySearchKamuQuery` sarmalar, `useCallback([searchKamu])` ile referans kararliligi.\n\n#### S-3.3.4 Custom hook'ta hata yutma\n**(a) Neden:** Yeni `Error` firlatirken orijinal hatayi `cause` ile gecmemek tani yetenegini kaybettirir (SonarQube S2737/benzeri).\n**(b) Tespit:** `catch (e) { throw new Error('...') }` — `e` kullanilmiyor.\n**(c) Duzeltme (gercek, `useSearchKamu.tsx` TODO):**\n```ts\n// ❌  throw new Error('Kamu arama işlemi başarısız oldu');\n// ✅  throw new Error('Kamu arama işlemi başarısız oldu', { cause: error });\n```\n\n---\n\n### 3.4 Performans\n\n#### S-3.4.1 `useMemo` / `useCallback` — dogru yerde, dogru bagimlilikla\n**(a) Neden:** Pahali hesaplamayi (`.map`/`.filter` zincirleri) ve `memo`'lu cocuga gecen fonksiyon/objeyi sabitlemek gereksiz re-render'i onler. Asiri kullanim ise gurultu yaratir (her ilkel deger icin `useMemo` gereksiz).\n**(b) Tespit:**\n- `memo`'lu cocuga **inline** `() => {}` / `{...}` / `[...]` prop geciliyor → her render yeni referans → memo etkisiz.\n- Pahali liste donusumu her render'da `useMemo`siz calisiyor.\n- Tersine: `useMemo(() => a + b, [a, b])` gibi ilkel-aritmetik gereksiz.\n**(c) Dogru (gercek, `IslemTanimTree.tsx`):**\n```ts\nconst filteredTree   = useMemo(() => /* arama filtresi */, [tree, searchQuery]);\nconst flatItems      = useMemo(() => flatten(filteredTree, expandedIds), [filteredTree, expandedIds]);\nconst handleToggle   = useCallback((id: string) => /* ... */, []);\nconst treeContextValue = useMemo(() => ({ selectedId, expandedIds, onToggle, /* ... */ }), [/* deps */]);\nconst rowProps       = useMemo<TreeRowProps>(() => ({ flatItems }), [flatItems]);\n```\n> `treeContextValue`'nun `useMemo` ile sarilmasi **kritik**: Context value her render'da yeni obje olursa tum tuketiciler re-render olur.\n\n#### S-3.4.2 `React.memo` ile saf bilesen\n**(a) Neden:** Sik render edilen liste/agac satirlari icin `memo`, prop degismedikce render'i atlar.\n**(b) Tespit:** Buyuk listede satir bilesi `memo`'suz; ya da `memo`'lu ama her render degisen prop (inline fn) aliyor.\n**(c) Dogru (gercek, `TreeNodeItem.tsx`):**\n```tsx\nconst TreeNodeRow = memo(function TreeNodeRow({ node, level, hasChildren, hasBaslamaSekiller, style }: {...}) {\n  // ... satir render\n});\n```\n\n#### S-3.4.3 Sanallastirma (`react-window`)\n**(a) Neden:** Yuzlerce-binlerce satirli liste/agac DOM'a tam basilirsa scroll/initial-render coker.\n**(b) Tespit:** Buyuk dinamik liste `.map` ile dogrudan render ediliyor, sanallastirma yok.\n**(c) Dogru (gercek, `IslemTanimTree.tsx` — `react-window` v2 `List`):**\n```tsx\nimport { List } from 'react-window';\n<List<TreeRowProps>\n  rowComponent={TreeRow}\n  rowCount={flatItems.length}\n  rowHeight={ROW_HEIGHT}\n  rowProps={rowProps}\n  style={{ height: '100%', overflow: 'auto' }}\n/>\n```\n> Not: `islem-yonetimi-web` `react-window ^2.2.6` kullanir (yeni `List` API, `rowComponent`/`rowProps`). Eski `FixedSizeList` API'siyle karistirma.\n\n#### S-3.4.4 Kod bolme (`lazy` + `Suspense`)\n**(a) Neden:** Agir, nadiren acilan ekranlar (PDF viewer, BPMN/DMN editor, Monaco) ana bundle'i sismeden ayri chunk'a alinmali.\n**(b) Tespit:** Buyuk bagimlilik (`bpmn-js`, `monaco-editor`, `@react-pdf-viewer`) statik `import` ile ana yola bagli; rota seviyesinde `lazy` yok.\n**(c) Duzeltme:**\n```tsx\nconst BpmnEditor = React.lazy(() => import('./features/islem-bpmn/BpmnEditor'));\n<Suspense fallback={<GolgeLoader />}>\n  <BpmnEditor />\n</Suspense>\n```\n> Mevcut repolarda rota seviyesinde `lazy` **az** kullanilir (`fen-kayit`/`taraf` `<Routes>` icinde statik element). Agir alt-ekranlar icin review'da `lazy` onerilebilir.\n\n#### S-3.4.5 Referans kararliligi (Context value, prop objeleri)\n**(a) Neden:** Provider `value={{...}}` inline ise her render'da yeni referans → tum tuketiciler re-render.\n**(b) Tespit:** `<Ctx.Provider value={{ a, b }}>` inline obje; handler'lar `useCallback`'siz.\n**(c) Dogru (gercek, `GeldigiBilesenContext.tsx`): `updateBilesen`/`updateBasvuruRef` `useCallback([])` ile sabit; ama value objesi inline — buyuk agaclarda `useMemo` ile sarmak iyilestirme olur (review onerisi).**\n\n---\n\n### 3.5 Okunabilirlik & TypeScript\n\n#### S-3.5.1 ESLint `--max-warnings 0` — uyarisiz birlestirme\n**(a) Neden:** Tum repolarda `lint` script'i `--max-warnings 0` (sifir uyari). Uyari = CI kirmizi.\n**(b) Tespit (gercek script'ler):**\n```\n\"lint\": \"eslint . --ext ts,tsx --report-unused-disable-directives --max-warnings 0\"\n```\nPR'da yeni `eslint-disable` direktifi, yeni `: any`, kullanilmayan degisken/import.\n**(c) Duzeltme:** Uyariyi kapatmak yerine kok-nedeni gider. `--report-unused-disable-directives` gereksiz `eslint-disable`'lari da hata yapar — olu disable'lari kaldir.\n\n> Aktif kurallar (dogrulanmis):\n> - `react-hooks/rules-of-hooks: 'error'` (her iki repo)\n> - `react-hooks/exhaustive-deps: 'warn'`\n> - `@typescript-eslint/no-explicit-any: 'warn'`\n> - `no-console: 'warn'` (islem-yonetimi'de `warn/error/debug/group/table` izinli)\n> - islem-yonetimi ek: `prefer-const: 'error'`, `no-var: 'error'`, `eqeqeq: 'error'` (`null` ignore), `no-non-null-assertion: 'warn'`\n\n#### S-3.5.2 `any` yasagi ve TS strict\n**(a) Neden:** `any` tip guvenligini kaldirir; tuketiciler derin opsiyonel zincirle korumasiz erisir. `tsconfig.json`: `strict: true`, `noUnusedLocals/Parameters: true`, `noFallthroughCasesInSwitch: true`.\n**(b) Tespit:** `: any`, `as any`, `Promise<any>`. (taraf-web'de su an ~29 `any`/`as any` eslesmesi var — hepsi TODO ile isaretli teknik borc.)\n**(c) Duzeltme (gercek ornekler):**\n```ts\n// ❌ varlikApiSlice.ts\ntransformResponse: (response: any) => ({ tipVarlikListe: response?.content ?? [] })\n// ✅\ninterface VarlikPageResponse { content: VarlikDto[] }\ntransformResponse: (r: VarlikPageResponse) => ({ tipVarlikListe: r?.content ?? [] })\n```\n```ts\n// ❌ KisiContext.tsx\ninterface KisiContextType { kisi: any; setKisi: any; }\n// ✅  (state zaten GercekKisiDto | null)\ninterface KisiContextType {\n  kisi: GercekKisiDto | null;\n  setKisi: React.Dispatch<React.SetStateAction<GercekKisiDto | null>>;\n}\n```\n> `unknown` + tip-daraltma, `any`'ye tercih edilir. Gercek dogru kullanim: `lowercaseKeys(obj: unknown)` (`IslemTanimlariApiSlice.ts`), `logger.error(message?: unknown, ...)` (`utils/logger.ts`).\n\n#### S-3.5.3 Erken donus (early return) & JSX sadeligi\n**(a) Neden:** Derin ic-ice ternary ve cok kosullu JSX okunamaz.\n**(b) Tespit:** 3+ kademeli `cond ? (...) : cond2 ? (...) : (...)`; render basinda guard yok.\n**(c) Dogru (gercek, `InnerAppDev.tsx`): yetki yoksa erken donus:**\n```tsx\nif (yetkiliKullanici === false) {\n  return <UnauthorizedScreen />;\n}\n// ana render asagida\n```\n\n#### S-3.5.4 `console.*` yerine merkezi logger\n**(a) Neden:** `no-console: 'warn'` ve uretimde gurultu/sizinti. taraf-web `utils/logger.ts` sadece `import.meta.env.DEV`'de loglar.\n**(b) Tespit:** Kaynak kodda dogrudan `console.log/error`.\n**(c) Duzeltme:** `import { logger } from '../utils/logger'; logger.error(...)`. (islem-yonetimi tarafinda `shared/lib` ve middleware `notistack` ile kullanici-yonelik hatayi yonetir; ham `console`'dan kacin.)\n\n#### S-3.5.5 Sabit kodlu URL/deger\n**(a) Neden:** Kaynak koda gomulu URL ortamlar arasi tasinabilirligi bozar (SonarQube S1075).\n**(b) Tespit:** Literal `https://...test.com.tr/...`.\n**(c) Duzeltme (gercek, `tipDegerVarlikApi.ts` TODO): `.env`'e `VITE_REACT_APP_TIPDEGER_VARLIK_API_URL` ekle, `env.envTipdegerVarlikApiUrl` uzerinden coz; fallback literal'i kaldir.**\n\n---\n\n### 3.6 Tekrar Kullanilabilirlik\n\n#### S-3.6.1 `golge-ui` bilesenlerini once kullan\n**(a) Neden:** Ortak UI/altyapi `golge-ui`'de hazirdir; yeniden yazmak tutarsizlik ve bakim yuku dogurur.\n**(b) Tespit:** El yapimi modal/snackbar/api-client/tema saglayicisi, oysa `golge-ui` karsiligi var.\n**(c) Kullan (gercek import'lar):**\n```tsx\nimport { GolgeModal, GolgeApp, enqueueSnackbar, useGolgeSecurity, golgeRtkApiHeaders } from 'golge-ui';\nimport { GolgeThemeProvider } from 'golge-ui/theme';\nimport { GolgeApi } from 'golge-ui'; // axios factory\n```\nGercek kullanim: `Kisi.tsx` `GolgeModal`, `main.tsx` `GolgeApp` + `GolgeThemeProvider`, `api.tsx` `GolgeApi`, tum apiSlice'lar `golgeRtkApiHeaders`.\n\n#### S-3.6.2 Kopyalama-karsiti: tekrar eden donusum/handler'i ortak yardimciya cikar\n**(a) Neden:** Ayni eslemenin/handler'in N kez kopyalanmasi tek-nokta-degisim ilkesini bozar.\n**(b) Tespit (gercek TODO'lar):**\n- `GercekKisiApi.ts`: `{ content, totalElements, totalPages, number } → { liste, kayitSayisi, sayfaSayisi, sayfaNo }` donusumu 6+ kez tekrar → **`toListeResponse(pageResponse)`** yardimcisina cikarilmali.\n- `api.tsx`: 404 → `showSnackBar(..., WARNING)` kalibi 20+ serviste try/catch ile tekrar → interceptor'a tasinmali (~200 satir azalir).\n- `tuzelKisiBilgileriApiSlice` + 4 kardesi: ayni `baseQuery`/header, sadece `/mersis/*` endpoint farkli → tek `mersisApi` + `injectEndpoints`.\n**(c) Duzeltme:** Ortak fonksiyon/interceptor/`injectEndpoints`. **Tekrar sayisini PR aciklamasinda belirt.**\n\n#### S-3.6.3 Prop/kompozisyon tasarimi\n**(a) Neden:** Cok sayida boolean prop yerine kompozisyon (`children`, slot) daha esnek ve okunur.\n**(b) Tespit:** 6+ boolean prop alan bilesen; `prop drilling` 3+ seviye.\n**(c) Duzeltme:** Context (`TreeContext` ornegi) veya kompozisyon. `Kisi.tsx` callback prop'lari (`guncelleGosterGizleNav`, `basilanButonGoruntuleMi`) — cok sayida ise context'e tasimayi degerlendir.\n\n#### S-3.6.4 Paylasilan hook/lib konumu\n**(a) Neden:** Cross-domain mantik feature icinde kalirsa cogaltilir.\n**(b) Tespit:** Iki feature ayni hook'u kopyalamis.\n**(c) Duzeltme:** `islem-yonetimi-web`'de `src/shared/{hooks,lib,types}` altina; `taraf-web`'de `src/hooks` veya `src/utils` altina. Ortak ekosistem mantigi varsa kutuphaneye (`golge-ui`, `fen-kayit-lib`) terfi degerlendir.\n\n---\n\n### 3.7 Routing (react-router 6)\n\n#### S-3.7.1 Standart yerlesim\n**(a) Neden:** Tutarli `App → InnerApp` deseni shell/standalone gecisini kolaylastirir.\n**(b)/(c) Gercek desen:**\n```tsx\n// taraf-web App.tsx — sadece <Routes>, tek wildcard\n<Routes><Route path=\"*\" element={<InnerAppDev />} /></Routes>\n```\n```tsx\n// fen-kayit-web App.tsx — parametreli + yonlendirme\n<Routes>\n  <Route path=\"/basvuru/:basvuruNo/*\" element={<InnerAppDev/>}/>\n  <Route path=\"/*\" element={<Navigate to=\"/sorgulama\"/>}/>\n  <Route path=\"/sorgulama\" element={<Sorgulama/>}/>\n</Routes>\n```\n> `react-router-dom`'u dogrudan veya `golge-ui/router` (re-export + `GolgeRouter`) uzerinden import et. Iki kaynagi karistirma.\n\n#### S-3.7.2 Korumali rota (yetki) deseni\n**(a) Neden:** Yetkisiz kullanici hassas ekrani gormemeli.\n**(b) Tespit:** Rota render'i `hasAuthority` kontrolu olmadan.\n**(c) Gercek desen — `useGolgeSecurity().hasAuthority` ile guard:**\n```tsx\n// InnerAppDev.tsx (taraf): yetki cozulene kadar bekle, yoksa Unauthorized\nconst { hasAuthority } = useGolgeSecurity();\nuseEffect(() => { /* hasAuthority(Permission.X) -> setYetkiliKullanici */ }, [hasAuthority]);\nif (yetkiliKullanici === false) return <UnauthorizedScreen />;\n```\n```tsx\n// fen-kayit InnerAppDev: yetki + veri hazir olunca rota agacini ac\nif (await hasAuthority('KDS_FK_GORUNTULE')) { getFenKayit().then(() => setRoutesReady(true)); }\n{ routesReady && <Routes>...</Routes> }\n```\n> Review notu: `hasAuthority` **async**; yetki cozulmeden rota render edilmemeli (yukaridaki `routesReady`/`yetkiliKullanici` guard'lari). Rol kodlari `Permission` sabitlerinde (`constants/Permission`), backend `IY_*`/`KDS_*` desenleriyle uyumlu.\n\n#### S-3.7.3 Rota seviyesinde `lazy`\nAgir alt-ekranlar icin `React.lazy` + `<Suspense>` (bkz. S-3.4.4). Mevcut repolarda yaygin degil; agir editorler (BPMN/DMN/Monaco/PDF) icin onerilir.\n\n---\n\n### 3.8 Axios Servis Katmani\n\n#### S-3.8.1 Merkezi client factory + interceptor\n**(a) Neden:** Auth header, base URL, ortak hata isleme tek yerde toplanmali; her serviste tekrar edilmemeli.\n**(b) Tespit:** `axios.create()` bilesende elle cagriliyor; her cagrida `Authorization` header'i elle ekleniyor.\n**(c) Gercek desen — `services/api.tsx` (`getClient`) `golge-ui`'nin `GolgeApi`'sini sarar:**\n```tsx\nexport const getClient = (options = {}): AxiosInstance => {\n  const client = GolgeApi({ ...options, headers: { 'Content-Type': 'application/json', ...(options.headers||{}) } });\n  client.interceptors.request.use((req) => {\n    const token = getAuthToken();\n    if (token) { req.headers.Authorization = `Bearer ${token}`; }\n    return req;\n  }, (e) => Promise.reject(e));\n  client.interceptors.response.use(r => r, (error) => {\n    switch (error.response?.status) {\n      case 401: showSnackBar(MSG.KIMLIK_DOGRULAMA_HATASI, TYPE.ERROR);\n                window.dispatchEvent(new CustomEvent('taraf:auth-error', { detail:{status:401} })); break;\n      case 403: showSnackBar(MSG.ERISIM_ENGELLENDI, TYPE.WARNING); /* ... */ break;\n      case 500: showSnackBar(MSG.TEKNIK_BIR_HATA_OLUSTU, TYPE.ERROR); break;\n    }\n    return Promise.reject(error);\n  });\n  return client;\n};\n```\n```tsx\n// tarafClient.tsx — tek instance, baseURL env'den\nconst tarafClient = getClient({ baseURL: env.envBaseUrl });\n```\n\n#### S-3.8.2 Tekil instance kullan, header'i elle ekleme\n**(b) Tespit (gercek TODO, `GercekKisiApi.ts`):** `getNviKisi`/`getNviKisiAdres` cagrilarinda `Accept`/`Content-Type` **elle** veriliyor — oysa ortak client zaten `Content-Type` ekliyor.\n**(c) Duzeltme:** Fazla header tanimlarini kaldir; ortak `tarafClient` kullan.\n\n#### S-3.8.3 Hata isleme — tutarli ve merkezi\n**(a) Neden:** Her serviste `try/catch + if 404 showSnackBar` kopyasi (~200 satir borc).\n**(b) Tespit (gercek, `GercekKisiApi.ts`):**\n```ts\ncatch (error: unknown) {\n  if (isAxiosError(error) && error.response?.status === 404) {\n    showSnackBar(error.response?.data?.message, TYPE.WARNING);\n  }\n}\n```\n**(c) Duzeltme:** 404 default handling'i response interceptor'a tasi (TODO ile isaretli) veya `handleApiError(error)` yardimcisi. Servisler sadece is-mantigina odaklanir.\n\n#### S-3.8.4 Istek iptali (cancellation)\n**(a) Neden:** Hizli yazimlı arama/autocomplete'te eski istekler yeni sonucu ezebilir; unmount sonrasi setState uyarisi cikar.\n**(b) Tespit:** Arama bileseninde `AbortController` yok; effect cleanup'ta `.abort()` cagrilmiyor.\n**(c) Dogru (gercek, `DuzenleyenSelect.tsx` + `YeniAdresIletisim.tsx`):** `abortControllerRef` ile onceki istegi iptal, `catch`'te `AbortError` ayikla, effect cleanup'ta `controller.abort()`.\n\n---\n\n### 3.9 RTK Query apiSlice Deseni\n\n#### S-3.9.1 Standart slice kurulumu\n**(a) Neden:** Tutarli `createApi` + `golgeRtkApiHeaders` + `tagTypes` cache/invalidation'i ongorulebilir kilar.\n**(b)/(c) Gercek temel slice (`tipDegerVarlikApi.ts`):**\n```ts\nconst tipDegerVarlikApi = createApi({\n  reducerPath: 'tipDegerVarlikApi',\n  baseQuery: fetchBaseQuery({ baseUrl: TIP_DEGER_VARLIK_API_URL, prepareHeaders: golgeRtkApiHeaders }),\n  tagTypes: ['Varlik','Deger','VarlikFilter','VarlikArama','VarlikFilterList'],\n  endpoints: () => ({}),\n});\n```\n> `prepareHeaders: golgeRtkApiHeaders` **zorunlu** (auth header propagasyonu). Elle `Authorization` ekleme.\n\n#### S-3.9.2 `injectEndpoints` ile tek-API genisletme (cogalmayi onle)\n**(a) Neden:** Her endpoint icin ayri `createApi` => ayri `reducerPath`/cache/middleware kaydi => store sismesi.\n**(b) Tespit (gercek TODO, `tuzelKisiBilgileriApiSlice.ts`):** Bes ayri slice (`tuzelKisiBilgileri`, `sermaye`, `ortak`, `unvan`, `temsilci`) ayni `baseQuery`/header, sadece `/mersis/*` endpoint farkli — **bes ayri reducer/middleware**.\n**(c) Dogru (gercek, `degerApiSlice.ts` / `varlikApiSlice.ts`):**\n```ts\nexport const varlikApiSlice = tipDegerVarlikApi.injectEndpoints({\n  endpoints: (builder) => ({ /* ... */ }),\n});\n```\n\n#### S-3.9.3 `query` vs `mutation` dogru secimi\n**(a) Neden:** Salt-okuma veri `mutation` ile tanimlanirsa cache devre disi kalir, ayni girdiyle gereksiz tekrar istek atilir.\n**(b) Tespit (gercek TODO, `tuzelKisiBilgileriApiSlice.ts`):** `fetchTuzelKisiBilgileri` salt-okuma oldugu halde `builder.mutation`.\n**(c) Duzeltme:** Salt-okuma → `builder.query` + `providesTags`; yazma → `builder.mutation` + `invalidatesTags`.\n\n#### S-3.9.4 `transformResponse` ve tagleme\n**(a) Neden:** Backend zarfini (`content`, snake_case) frontend tipine donusturmek tek yerde olmali; tag'lar dogru invalidation saglar.\n**(b)/(c) Gercek (`IslemTanimlariApiSlice.ts`):** `transformResponse` ile `lowercaseKeys`/`transformListResponse`; `providesTags`/`invalidatesTags` ile `Table`/`Lookup`/`Enum`/`IslemTanim` esleme.\n> **Lossy donusum uyarisi:** `lowercaseKeys` geri-donusturulemez; tip tanimlari bu forma gore yazilir (dosyadaki yorum). Donusum degistirilirse tum field referanslari kirilir — review'da bunu vurgula.\n> **Gereksiz invalidation kacin:** `createRecord` icinde tag invalidation kaldirilmis, yerine lokal store guncellemesi yapilmis (yorum: \"cift render dongusune neden oluyordu\"). Invalidation maliyetini gozet.\n\n#### S-3.9.5 Store kaydi tamlik kontrolu\n**(a) Neden:** Her `createApi` icin `reducer` **ve** `middleware` store'a eklenmeli; eksik middleware cache/invalidation'i bozar.\n**(b) Tespit (gercek, `taraf-web/app/store.ts`):** `tuzelKisiBilgileriApiSlice` reducer'i kayitli ama formatlama bozuk; **her** slice'in hem `[x.reducerPath]: x.reducer` hem `.concat(x.middleware)` satiri olmali.\n**(c) Dogru (gercek, `islem-yonetimi-web/app/store.ts`):** `combineReducers` + `getDefaultMiddleware().concat(...)` ile 25+ api tutarli kayitli; ek `rtkQueryErrorLogger` middleware merkezi hata gosterimi yapar.\n\n#### S-3.9.6 Merkezi RTK Query hata middleware'i\n**(a) Neden:** Tum mutation/query hatalarini tek yerde kullaniciya gostermek (notistack) tutarli UX saglar.\n**(b)/(c) Gercek (`app/middlewares.ts` `rtkQueryErrorLogger`):** `isRejectedWithValue` ile backend hata zarfini (`error`/`code`/`message`) ayrıştirir; `AbortError` ve `meta.condition` (skip) durumlarini **gostermez** (gereksiz hata gurultusu engellenir).\n\n---\n\n### 3.10 MUI 6 Tema, sx ve styled\n\n#### S-3.10.1 Tema saglayicisi ve lokalizasyon\n**(a) Neden:** Tek tema kaynagi (golge tema) + tarih lokalizasyonu tutarli gorunum/format saglar.\n**(b)/(c) Gercek (`main.tsx`):** `GolgeThemeProvider` (golge-ui/theme) + `LocalizationProvider` (`AdapterDayjs`, `adapterLocale=\"tr\"`, `trTR` localeText). Ayri/ozel `createTheme` ekleme — golge temasini kullan/genislet.\n\n#### S-3.10.2 `sx` vs `styled` secimi\n**(a) Neden:** Tek-seferlik/duruma-bagli stil `sx`; tekrar kullanilan/varyantli stil `styled`.\n**(b) Tespit:** Ayni `sx={{...}}` blogu cok yerde kopyalanmis (→ `styled`'a cikar); ya da basit tek-seferlik stil icin gereksiz `styled` bileseni.\n**(c) Dogru `styled` (gercek, `components/controls/YeniKisiItem.ts`):**\n```ts\nimport { styled } from '@mui/material/styles';\nexport const YeniKisiItem = styled(Paper)(({ theme }) => ({\n  backgroundColor: theme.palette.mode === 'dark' ? '#1A2027' : '#fff',\n  ...theme.typography.body2, padding: theme.spacing(1), color: theme.palette.text.secondary,\n}));\n```\n**(c) Dogru `sx` (gercek, `Kisi.tsx`):** responsive deger objeleri `sx={{ p: { xs: 2, sm: 3 }, width: { xs: 'calc(100vw - 16px)', md: '56%' } }}`.\n> Tema degeri kullan: `theme.spacing()`, `theme.palette.*`, breakpoint objeleri. Sabit hex/px gomulu degerleri (tema disi) review'da sorgula.\n\n#### S-3.10.3 `as any` ile `sx` tip kacisi\n**(b) Tespit (gercek, fen-kayit `InnerAppDev.tsx`):** `sx={{ '--header-sub-content-height': ... } as any}` — CSS degisken icin tip kacisi.\n**(c) Duzeltme:** CSS custom property'leri `CSSProperties` ile `style` uzerinden ya da `sx` icin dogru tiple ver; `as any`'den kacin.\n\n#### S-3.10.4 Grid2 ve responsive\nGercek: `import Grid from '@mui/material/Grid2'; <Grid size={{ xs: 12, md: 12, lg: 12, xl: 12 }}>` (MUI 6 Grid2 API). Eski `<Grid item xs>` API'siyle karistirma.\n\n---\n\n### 3.11 Form, Maskeleme ve Dogrulama\n\n> Not: Incelenen repolarda `react-imask` bagimliligi **bulunamadi**; maskeleme MUI alanlari + manuel donusum ve `libphonenumber-js` (islem-yonetimi) ile yapilir. Asagidaki kurallar genel form standardidir; `react-imask` eklenirse onerilen desen verilmistir.\n\n#### S-3.11.1 Maskelenmis girdi (TC Kimlik, telefon, vergi no)\n**(a) Neden:** Sabit-format alanlar (11 hane TC, telefon) maskelenirse hatali giris en bastan engellenir.\n**(b) Tespit:** Serbest `TextField` + manuel `replace`/`slice` ile elle maskeleme tekrarlanmis.\n**(c) Onerilen desen (`react-imask` eklenirse):**\n```tsx\nimport { IMaskInput } from 'react-imask';\nconst TcMask = React.forwardRef<HTMLInputElement, any>((props, ref) => (\n  <IMaskInput {...props} mask=\"00000000000\" inputRef={ref} onAccept={(v)=>props.onChange({target:{name:props.name,value:v}})} unmask />\n));\n<TextField name=\"tcKimlikNo\" InputProps={{ inputComponent: TcMask as any }} />\n```\n> Mevcut alternatif: `libphonenumber-js` (islem-yonetimi) telefon dogrulama/format icin kullanilir.\n\n#### S-3.11.2 Dogrulama ve gonderim\n**(a) Neden:** Istemci dogrulamasi kullaniciya hizli geri-bildirim verir; ama **backend dogrulamasi tek gercek kaynaktir** (golge `*Constraint` + jakarta `@Valid`).\n**(b) Tespit:** Sadece istemci dogrulamasina guvenen kritik akis; ya da hic istemci dogrulamasi olmadan ham gonderim.\n**(c) Duzeltme:** Zorunlu/desen kontrollerini istemcide yap, backend hata zarfini (`message`/`error`) RTK Query middleware veya axios interceptor ile kullaniciya goster.\n\n#### S-3.11.3 Form state'i lokal tut\nForm alanlari ekran-lokal `useState`/`useReducer` ile tutulur (S-3.2.1). Form verisini Redux global store'a koymak gereksizdir; submit'te RTK Query `mutation`/axios servisi cagrilir.\n\n---\n\n### 3.12 i18n (react-i18next)\n\n> Sadece `islem-yonetimi-web` i18n kullanir (`react-i18next ^15.1.3`). `taraf-web`/`fen-kayit-web`'de metinler dogrudan Turkce gomulu (domain dili Turkce).\n\n#### S-3.12.1 Namespace'li, feature-bazli kurulum\n**(a) Neden:** Buyuk uygulamada ceviriler feature namespace'lerine bolunmeli; tek dev sozluk yonetilemez.\n**(b)/(c) Gercek (`features/kural-motoru/i18n/index.ts`):**\n```ts\ni18n.use(LanguageDetector).use(initReactI18next).init({\n  resources: { tr: { kuralMotoru: tr }, en: { kuralMotoru: en } },\n  fallbackLng: 'tr', ns: ['kuralMotoru'], defaultNS: 'kuralMotoru',\n  interpolation: { escapeValue: false },\n  detection: { order: ['localStorage','navigator'], caches: ['localStorage'], lookupLocalStorage: 'kuralMotoruLng' },\n});\n```\n**(b) Tespit:** Bilesende sabit string oysa o feature i18n kullaniyor; eksik ceviri anahtari; `fallbackLng` yok.\n**(c) Duzeltme:** `const { t } = useTranslation('kuralMotoru'); t('anahtar')`. Yeni metin icin `tr` **ve** `en` dosyalarina anahtar ekle.\n\n---\n\n### 3.13 Erisilebilirlik (a11y)\n\n#### S-3.13.1 Klavye erisimi ve odak\n**(a) Neden:** Tum etkilesimli ogeler klavyeyle erisilebilir olmali.\n**(b) Tespit:** `onClick` olan `<div>` ama `tabIndex`/`onKeyDown`/`role` yok.\n**(c) Dogru (gercek, `IslemTanimTree.tsx`):** `tabIndex={0}` + `onKeyDown={handleTreeKeyDown}` + `:focus-visible` gorsel odak (`sx`). MUI'nin `IconButton`/`Tooltip`/`Button` bilesenleri erisilebilirligi hazir verir — ham `<div onClick>` yerine bunlari kullan.\n\n#### S-3.13.2 Etiket ve metin alternatifleri\n**(b) Tespit:** Sadece ikonlu buton (`IconButton`) icin `aria-label`/`title` yok; `TextField` icin `label` yok.\n**(c) Duzeltme:** `IconButton` -> `Tooltip` + `aria-label`; `TextField` -> `label`/`aria-label`. Gercek: `TreeNodeItem.tsx` ikon butonlari `Tooltip` ile sarili.\n\n#### S-3.13.3 Modal odak yonetimi\n**(b)/(c) Gercek (`Kisi.tsx`):** `GolgeModal` `disableEnforceFocus` ve `paperProps` ile odak/yerlesim yonetir. Modal acilinca odak icine alinmali, kapaninca tetikleyiciye donmeli (golge-ui yonetir; ozel modal yazarken bu davranisi koru).\n\n---\n\n## 4. Sik Hatalar & Anti-Pattern'ler (before/after)\n\n### AP-1 — `.reduce`/`.map` icinde hook cagrisi\n```ts\n// ❌ ANTI-PATTERN (useResponsive.ts useWidth) — rules-of-hooks ihlali, disable ile gizlenmis\nkeys.reduce((out, key) => {\n  // eslint-disable-next-line react-hooks/rules-of-hooks\n  const m = useMediaQuery(theme.breakpoints.up(key)); return !out && m ? key : out;\n}, null)\n```\n```ts\n// ✅ DUZELTME — tum hook'lar kosulsuz ust seviyede\nconst up = {\n  xl: useMediaQuery(theme.breakpoints.up('xl')),\n  lg: useMediaQuery(theme.breakpoints.up('lg')),\n  md: useMediaQuery(theme.breakpoints.up('md')),\n  sm: useMediaQuery(theme.breakpoints.up('sm')),\n};\nreturn up.xl ? 'xl' : up.lg ? 'lg' : up.md ? 'md' : up.sm ? 'sm' : 'xs';\n```\n\n### AP-2 — Cift state-kaynagi (Context state + modul global)\n```tsx\n// ❌ AuthTokenContext.tsx — token hem state hem modul-global; axios eski token tasiyabilir\nlet authToken: string | null = null;\n```\n```tsx\n// ✅ Tek kaynak: Redux store'dan oku (getState) ya da provider mount'ta senkron set,\n//    axios interceptor ayni tek kaynaktan token cekmeli.\n```\n\n### AP-3 — `any` ile tip guvenligi kaybi\n```ts\n// ❌ transformResponse: (response: any) => ({ tipVarlikListe: response?.content ?? [] })\n// ✅ interface VarlikPageResponse { content: VarlikDto[] }\n//    transformResponse: (r: VarlikPageResponse) => ({ tipVarlikListe: r?.content ?? [] })\n```\n\n### AP-4 — Salt-okuma veri icin `mutation`\n```ts\n// ❌ fetchTuzelKisiBilgileri: builder.mutation({ query: (b) => ({ url:'/mersis/...', method:'POST', body:b }) })\n// ✅ builder.query(...) + providesTags  → cache + dedupe devreye girer\n```\n\n### AP-5 — Tekrar eden zarf donusumu\n```ts\n// ❌ 6+ serviste: const { content, totalElements, totalPages, number } = res.data;\n//    return { liste: content, kayitSayisi: totalElements, sayfaSayisi: totalPages, sayfaNo: number };\n// ✅ const toListeResponse = (p) => ({ liste:p.content, kayitSayisi:p.totalElements, sayfaSayisi:p.totalPages, sayfaNo:p.number });\n```\n\n### AP-6 — Cleanup'siz effect / iptalsiz arama\n```tsx\n// ❌ useEffect(() => { window.addEventListener('x', h); }, []);  // remove yok\n// ✅ useEffect(() => { window.addEventListener('x', h); return () => window.removeEventListener('x', h); }, [h]);\n//    Arama icin AbortController + cleanup'ta .abort()\n```\n\n### AP-7 — Memo'lu cocuga inline prop / inline Context value\n```tsx\n// ❌ <Ctx.Provider value={{ a, b, onX: () => ... }}>   // her render yeni referans\n// ✅ const value = useMemo(() => ({ a, b, onX }), [a, b, onX]); <Ctx.Provider value={value}>\n//    onX = useCallback(..., [deps])\n```\n\n### AP-8 — `eslint-disable` ile uyari gizleme\n```ts\n// ❌ // eslint-disable-next-line @typescript-eslint/no-explicit-any\n//    const x: any = ...\n// ✅ Kok-nedeni gider; --report-unused-disable-directives gereksiz disable'lari da hata yapar (max-warnings 0).\n```\n\n### AP-9 — Hata yutma (cause kaybi)\n```ts\n// ❌ catch (error) { throw new Error('İşlem başarısız'); }\n// ✅ catch (error) { throw new Error('İşlem başarısız', { cause: error }); }\n```\n\n### AP-10 — `useRef` ile yaratilan debounce'un stale closure'i\n```tsx\n// ❌ const debounced = useRef(debounce(performSearch, t)).current;  // ilk render closure'unu kalici yakalar\n// ✅ const debounced = useMemo(() => debounce(performSearch, t), [performSearch, t]); // + unmount'ta debounced.cancel()\n```\n> Gercek: `DuzenleyenSelect.tsx` bu durumu TODO ile isaretlemis (`react-hooks/exhaustive-deps`).\n\n---\n\n## 5. Hizli Referans (Review Checklist)\n\n**Component & dosya**\n- [ ] Dosya repo desenine uygun konumda (`taraf` duz / `islem-yonetimi` feature-sliced).\n- [ ] Bilesen <250-300 satir; tek sorumluluk; container/presentational ayrik.\n- [ ] Isimlendirme: PascalCase bilesen, useXxx hook, XxxApiSlice, XxxApi.ts, XxxContext/XxxProvider/useXxx. — Yasak: /export\\s+default\\s+function\\s+[a-z]/\n\n**State**\n- [ ] Sunucu verisi RTK Query'de (slice'a kopyalanmamis). — Yasak: /dispatch\\s*\\(\\s*set[A-Z][A-Za-z0-9]*\\s*\\(\\s*[A-Za-z0-9_]*[Dd]ata\\b/\n- [ ] Turetilmis deger useMemo ile render'da; ayri state degil. — Yasak: /useEffect\\s*\\(\\s*\\(\\s*\\)\\s*=>\\s*\\{?\\s*set[A-Z][A-Za-z0-9]*\\s*\\(/\n- [ ] Cift state-kaynagi yok (Context+Redux ya da state+modul-global ayni veri).\n- [ ] Reducer disinda mutasyon yok; Immer sadece reducer icinde. — Yasak: /\\bprops\\.[A-Za-z0-9_]+(?:\\.[A-Za-z0-9_]+)*\\s*(?:=[^=>]|\\.(?:push|pop|splice|shift|unshift|sort|reverse)\\s*\\()/\n\n**Hook**\n- [ ] Hook'lar kosulsuz, ust seviyede (.map/.reduce/if/erken-return sonrasi yok). — Yasak: /(?:\\bif\\s*\\([^)]*\\)\\s*\\{?\\s*|\\.\\s*(?:map|forEach|reduce|filter)\\s*\\(\\s*\\([^)]*\\)\\s*=>\\s*\\{?\\s*)(?:const\\s+[^=]*=\\s*)?use[A-Z]/\n- [ ] useEffect cleanup donuyor (listener/timer/abort/subscription). — Yasak: /useEffect\\s*\\(\\s*\\(\\s*\\)\\s*=>\\s*\\{(?:(?!return)[^}])*(?:addEventListener|setInterval)\\s*\\((?:(?!return)[^}])*\\}\\s*,/\n- [ ] Bagimlilik dizileri tam; gereksiz exhaustive-deps disable yok. — Yasak: /eslint-disable[^\\n]*exhaustive-deps/\n- [ ] Custom hook tek-sorumluluk; `useCallback`/`useMemo` ile kararli ciktilar.\n\n**Performans**\n- [ ] Pahali liste donusumu useMemo'lu; satir bileseni memo'lu. — Yasak: /\\{\\s*[A-Za-z0-9_.]+\\s*\\.(?:filter|sort|slice|reduce|concat)\\s*\\([^)]*\\)\\s*\\.map\\s*\\(/\n- [ ] memo'lu cocuga/Provider value'ya inline fn/obj gecmiyor. — Yasak: /\\.Provider\\s+value=\\{\\{/\n- [ ] Buyuk liste `react-window` ile sanallastirilmis.\n- [ ] Agir ekran lazy+Suspense (BPMN/DMN/Monaco/PDF). — Yasak: /import\\s+[^;]*from\\s*[\"']{1}(?:bpmn-js|dmn-js|monaco-editor|@monaco-editor|react-pdf|pdfjs-dist)/\n\n**Okunabilirlik & TS**\n- [ ] `: any`/`as any` yok (gerekiyorsa `unknown` + daraltma).\n- [ ] Erken donus; JSX'te 3+ kademeli ternary yok. — Yasak: /\\?(?![.?])[^?]{1,60}\\?(?![.?])[^?]{1,60}\\?(?![.?])/\n- [ ] `console.*` yerine `logger`; sabit kodlu URL yok.\n- [ ] npm run lint (max-warnings 0) ve tsc temiz. — Yasak: /@ts-(?:ignore|nocheck)\\b|eslint-disable\\b/\n\n**Tekrar kullanilabilirlik**\n- [ ] golge-ui karsiligi varken yeniden yazilmamis (Modal/Snackbar/Api/Theme). — Yasak: /import\\s+\\{[^}]*\\b(?:Snackbar|Dialog|Modal)\\b[^}]*\\}\\s*from\\s*[\"']@mui\\/material/\n- [ ] Tekrar eden donusum/handler ortak yardimciya/`injectEndpoints`'e cikarilmis.\n\n**Routing / axios / RTK Query**\n- [ ] Korumali rota hasAuthority ile; yetki cozulmeden render yok. — Yasak: /\\b(?:user|currentUser|profile)\\??\\.(?:role|roles|authorities|yetki|yetkiler)\\b\\s*(?:===|!==|\\.includes\\s*\\()/\n- [ ] Tekil axios tarafClient; header elle eklenmemis; iptal (AbortController) var. — Yasak: /\\baxios\\s*\\.\\s*(?:get|post|put|patch|delete|create)\\s*\\(/\n- [ ] apiSlice golgeRtkApiHeaders kullanir; query/mutation dogru; reducer **ve** middleware store'da kayitli. — Yasak: /headers\\.set\\s*\\(\\s*[\"']Authorization/\n\n**MUI / form / i18n / a11y**\n- [ ] Tema degeri (theme.spacing/palette, breakpoint objeleri) kullanilmis; sx as any yok. — Yasak: /(?:sx|style)=\\{\\{[^}]*#[0-9a-fA-F]{3,8}\\b/\n- [ ] Form lokal state'te; kritik dogrulama backend'de de var.\n- [ ] (islem-yonetimi) metin t() ile, tr+en anahtarlari eklenmis. — Yasak: /\\s(?:label|placeholder|helperText)=\"[^\"{}]{3,}\"/\n- [ ] Etkilesimli <div> yerine MUI bileseni; aria-label/Tooltip/tabIndex mevcut. — Yasak: /<(?:div|span)[^>]*\\sonClick\\s*=/\n\n---\n\n## 6. Ilgili Dosyalar & Capraz-Linkler\n\n**taraf-web (duz desen — temel referanslar)**\n- `src/services/api.tsx` — axios `getClient` factory + interceptor (auth, 401/403/500). **S-3.8**\n- `src/services/tarafClient.tsx` — tekil instance.\n- `src/services/GercekKisiApi.ts` — axios servis deseni + tekrar/`any`/header TODO'lari. **S-3.6.2 / S-3.8 / AP-5**\n- `src/app/store.ts`, `src/app/hooks.ts` — store kurulumu + tiplenmis hook'lar. **S-3.9.5**\n- `src/app/geldigiBilesenSlice.ts` — Redux slice (Immer). **S-3.2.4**\n- `src/features/tipDegerVarlikApi.ts` — RTK Query temel slice. **S-3.9.1**\n- `src/features/ext/{deger,varlik}/*ApiSlice.ts` — `injectEndpoints`, `query`/`mutation`, `transformResponse`, `any` TODO. **S-3.9.2 / AP-3**\n- `src/features/tuzelKisiBilgileriApiSlice.ts` — slice cogalma + `mutation` yanlis-kullanim TODO. **S-3.9.2/3 / AP-4**\n- `src/hooks/useResponsive.ts` — `useResponsive` (dogru) vs `useWidth` (rules-of-hooks ihlali). **S-3.3.1 / AP-1**\n- `src/hooks/useSearchKamu.tsx` — custom hook + hata-cause TODO. **S-3.3.3/4 / AP-9**\n- `src/contexts/AuthTokenContext.tsx` — cift state-kaynagi anti-pattern. **S-3.2.5 / AP-2**\n- `src/contexts/{Kisi,GeldigiBilesen}Context.tsx` — Context + `useCallback`; Redux'a tasima onerisi. **S-3.2.5 / S-3.4.5**\n- `src/components/takbisBelge/DuzenleyenSelect.tsx` — `useReducer` + `AbortController` + debounce TODO. **S-3.8.4 / AP-10**\n- `src/pages/Kisi.tsx` — ekran-lokal state, `useCallback`, `GolgeModal`. **S-3.2.1 / S-3.6.1**\n- `src/InnerAppDev.tsx`, `src/App.tsx`, `src/main.tsx` — yetki guard, routing, provider agaci. **S-3.7.2 / S-3.10.1**\n- `src/components/controls/YeniKisiItem.ts` — `styled`. **S-3.10.2**\n- `src/utils/logger.ts` — merkezi logger. **S-3.5.4**\n- `.eslintrc.cjs`, `tsconfig.json` — lint/strict kurallar. **S-3.5.1/2**\n\n**islem-yonetimi-web (feature-sliced — buyuk uygulama referanslari)**\n- `src/app/store.ts` — `combineReducers` + 25+ apiSlice. **S-3.9.5**\n- `src/app/middlewares.ts` — `rtkQueryErrorLogger` (merkezi hata + abort/skip ayikla). **S-3.9.6**\n- `src/features/islem-tanimlari/IslemTanimlariApiSlice.ts` — `transformResponse`/`lowercaseKeys`, tag invalidation, lossy-donusum uyarisi. **S-3.9.4**\n- `src/features/islem-tanimlari/components/islem-tanim/IslemTanimTree.tsx` — `useMemo`/`useCallback`, Context value memo, `react-window` `List`, a11y `tabIndex`/`onKeyDown`. **S-3.4.1/2/3 / S-3.13.1**\n- `src/features/islem-tanimlari/components/islem-tanim/TreeNodeItem.tsx` — `memo`'lu satir bileseni. **S-3.4.2**\n- `src/shared/hooks/useLocalStorage.ts` — referans custom hook (SSR guard, cross-tab event + cleanup). **S-3.3.3**\n- `src/shared/hooks/tasks/useTaskFiltering.ts` — `useMemo` turetilmis state, hook kompozisyonu. **S-3.2.3 / S-3.3.3**\n- `src/shared/lib/performance.ts` — olcum/`debounce`/`throttle` yardimcilari. **S-3.4**\n- `src/features/kural-motoru/i18n/index.ts` — namespace'li i18next kurulumu. **S-3.12.1**\n- `eslint.config.js` (flat) — ESLint 9 kural seti. **S-3.5.1**\n\n**fen-kayit-web**\n- `src/App.tsx`, `src/InnerAppDev.tsx` — parametreli routing, `routesReady` yetki-guard, `useLayoutEffect`, `as any` sx TODO. **S-3.7 / S-3.10.3**\n\n**golge-ui (ortak kutuphane — `taraf-web/node_modules/golge-ui/dist`)**\n- `dist/index.d.ts` — `GolgeApi`, `golgeRtkApiHeaders`, `golgeErrorMiddleware`, `GolgeApp/AppBar/Main/Footer`, `GolgeModal`, `GolgeCrudLayout`, `GolgeTreeView`, `enqueueSnackbar`, `useGolgeSecurity`.\n- `dist/router/index.d.ts` — `GolgeRouter` + `react-router-dom` re-export. **S-3.7.1**\n- `package.json` exports: `.`, `./utils`, `./eimza`, `./theme`, `./router`, `./styles`. **S-3.6.1**\n\n> **Capraz dokuman:** Backend kontrat tarafi (Feign `*RestClient` ↔ controller) icin backend code-review dokumanina bakiniz. Frontend servis/DTO tipleri, backend `client` modulundeki DTO'larla **uyumlu** olmalidir (orn. sayfalama zarfi `content/totalElements` ↔ Spring `Page`).\n",
  "02-spring-boot-code-review.md": "# Spring Boot Code Review Dokümanı\n\n> **Amaç:** Bu doküman, TKGM TAKBİS platformundaki Spring Boot (Java 21, Jakarta EE, `golge` framework) backend servislerinin **kod review** ve **kod revizyonu** sürecinde kullanılacak referans standardıdır.\n> Her standart için **(a) NEDEN önemli**, **(b) review'da NASIL TESPİT edilir**, **(c) NASIL DÜZELTİLİR** (mümkün olduğunca before/after kod) verilmiştir.\n> Tüm örnekler gerçek koddan alınmıştır; sınıf adları, anotasyonlar ve dosya yolları doğrulanmıştır.\n\n---\n\n## 1. Amaç & Kapsam\n\nBu doküman aşağıdaki katmanların review standartlarını kapsar:\n\n| Bölüm | Katman | Ana kural (özet) |\n|------|--------|------------------|\n| 4 | Controller | İnce; `server` modülündeki `*RestClient` (`@RequestMapping`) arayüzünü `implements`; sadece DTO döner |\n| 5 | Service | Arayüz + impl; `golge` generic service extend; `@Transactional` sınırı burada |\n| 6 | Repository | `golge` JPA repository; native sorgu enjeksiyon karşıtı |\n| 7 | DTO | `common` modülde; validation anotasyonları; Composite DTO |\n| 8 | Mapper | MapStruct / `golge` mapper; null stratejisi; update mapping |\n| 9 | Exception Handling | `golge` exception tipleri; `GolgeErrorDetail`; global handler |\n| 10 | Validation | jakarta `@Valid`/`@Validated`; `*Constraint` + i18n mesaj |\n| 11 | Transaction | propagation/readOnly/rollbackFor; self-invocation tuzağı |\n| 12 | Ek Standartlar | constructor injection, Java 21 idiom, Kafka, config, güvenlik, Feign |\n\n**Kapsam dışı:** Entity tasarımı, Liquibase, Elasticsearch indeksleme, frontend. (Ayrı dokümanlar.)\n\n---\n\n## 2. Arka Plan / Mimari Ozet\n\n- **Stack:** Java 21, Spring Boot 3.x (Jakarta EE), Gradle multi-project. Kurum içi `golge` (gölge = shadow) framework: paket `tr.com.test.golge.*`. **golge framework sürümü:** Gradle cache'inde **hem 1.9.0 hem 1.8.1 mevcuttur**; aktif sürüm `taraf-api/gradle.properties`'te explicit değildir — `golge-spring-boot` plugin'inin yönettiği BOM (ekosistem/parent) üzerinden gelir. Bu doküman örnekleri cache'teki 1.9.0 jar'larından javap/unzip ile çıkarılmıştır; sürümü daima ilgili modülün BOM'undan doğrula. **Not:** `gradle.properties`'teki **plugin** sürümleri (`golgeSpringBootPluginVersion=1.7.2`, `golgeHibernatePluginVersion=1.7.0`, `golgeDevToolPluginVersion=1.2.2`) ile **framework modül** sürümleri (1.8.x/1.9.x) farklı şeylerdir; karıştırma.\n- **Repo yerleşimi:** Her iş alanı `<ad>-api` üç alt-modülden oluşur:\n  - **`client`** — `@FeignClient` ile işaretli **published Feign client** (`<Ad>FeignClient`, ör. `TarafFeignClient`, `IslemYonetimiFeignClient`, `BasvuruFeignClient`). JAR olarak publish edilir; **diğer servisler bunu bağımlılık alır**. Burası diğer servislerin çağırdığı, curated/sınırlı bir uç alt kümesidir.\n  - **`common`** — paylaşılan DTO'lar (`golge-data-orm-dto` BOM).\n  - **`server`** — çalıştırılabilir Spring Boot app. **`*RestClient` / `*SearchClient` server-tarafı REST arayüzleri buradadır** (`server/.../controller/`), `client` modülünde değil.\n- **KRİTİK KONVANSİYON (iki ayrı kavram, karıştırma):**\n  - **(a) Server `*RestClient` arayüzü** (`server/.../controller/` içinde, ör. `GercekKisiOperationalRestClient`): `@RequestMapping`/`@PostMapping`/`@GetMapping` ile **path/HTTP metot tanımlar**; `@FeignClient` **değildir**. Controller bu arayüzü `@Override` ile `implements` eder ve sadece gövdeyi yazar. Yani controller = bu **server-tarafı REST arayüzünün** implementasyonu.\n  - **(b) Client `<Ad>FeignClient`** (`client/` içinde): `@FeignClient(name=..., url=\"${...}\")` ile işaretli, **diğer servislerin bağımlılık aldığı gerçek published Feign client**. Ayrı bir sınıftır ve genellikle endpoint'lerin curated bir alt kümesini yayınlar; `(a)`'daki server arayüzüyle aynı sınıf değildir.\n  - **Yanılgı uyarısı:** \"Controller `client` modülündeki Feign arayüzünü implement eder\" / \"tek kontrat hem çağıran (Feign) hem sunan (controller) tarafından paylaşılır\" **DOĞRU DEĞİLDİR**. Controller, `server` modülündeki `*RestClient` (`@RequestMapping`) arayüzünü implement eder; bu arayüz `client` modülündeki `@FeignClient` ile karıştırılmamalıdır. Çağıran ve sunan taraf ayrı arayüzler kullanır; path uyumu derleme zamanında değil, kontrat disiplini ile sağlanır.\n\n**İncelenen referans servisler:**\n- `taraf-api/server` — `tr.gov.tkgm.takbis.taraf.server.*` (doğrulanmış referans)\n- `islem-yonetimi-api/server` — `tr.gov.tkgm.takbis.islemyonetimi.server.*`\n- `basvuru-api/server` — `tr.gov.tkgm.takbis.portal.basvuru.server.*`\n\n**Doğrulanan golge taban tipleri (javap çıktısı):**\n\n```text\nGolgeGenericOperationService<ID extends Serializable, GDTO extends GolgeBaseDto<?>>\n  save / saveAll / update / updateAll / dynamicUpdate / dynamicUpdateAll / deleteById / deleteAllById\n\nGolgeGenericOperationServiceImpl<ID, GDTO, GE extends GolgeBaseEntity<ID>,\n                                 GMPPR extends GolgeGenericMapstructMapper<ID,GDTO,GE>,\n                                 R extends GolgeGenericJpaRepository<GE,ID>>\n  ctor(EntityManager, GMPPR mapper, R repository)\n  public getEntityManager() / getMapper() / getRepository()\n\nGolgeGenericSearchService<ID, GDTO, QDTO extends GolgeQueryDto>\n  getById(ID) / queryList(QDTO) / queryPage(QDTO)\n\nGolgeGenericJpaRepository<E extends Serializable, ID extends Serializable>\n  extends GolgeGenericJpaSearchRepository<E,ID>\n  save / saveAndFlush / update / deleteById / deleteAllByIdInBatch ...\n\nGolgeGenericMapstructMapper<ID, DTO extends GolgeBaseDto<?>, E extends GolgeBaseEntity<ID>>\n  DTO convertEntityToDto(E)\n  E   convertDtoToEntity(DTO)\n  void mapToEntity(DTO, E)            // in-place update mapping\n  List/Set toplu dönüşümler\n\nGolgeUncheckedException(RuntimeException)  -> getErrorDetail(): GolgeErrorDetail\nGolgeCheckedException(Exception)           -> getErrorDetail(): GolgeErrorDetail\nGolgeBusinessRuleException extends GolgeUncheckedException   // STATUS=400\nGolgeResourceNotFoundException extends GolgeUncheckedException // STATUS=404\n// tam ad: tr.com.test.golge.exception.model.GolgeErrorDetail  (model alt-paketi)\nGolgeErrorDetail { int httpStatus; String code, type, cause, message;\n                   Map<String,? extends Serializable> attributes; }  // @Builder\n// tam ad: tr.com.test.golge.context.handler.GolgeContextExceptionHandler\nGolgeContextExceptionHandler extends ResponseEntityExceptionHandler\n  handleMethodArgumentNotValid / handleHandlerMethodValidationException /\n  handleHttpMessageNotReadable / handleAllException\n```\n\n---\n\n## 3. Standartlar & Konvansiyonlar — Hızlı İlkeler — Yasak: /(private|protected)\\s+final\\s+[A-Z][A-Za-z0-9]*ServiceImpl\\s/\n\n| # | İlke | Kural |\n|---|------|-------|\n| P1 | İnce controller | Controller'da iş mantığı yok; sadece servis çağırır + `ResponseEntity` sarar |\n| P2 | DTO sınırı | API sınırından **asla entity dönme**; sadece DTO/record |\n| P3 | Arayüz + impl | Service her zaman arayüz + impl; controller arayüze değil servise bağlanır |\n| P4 | Transaction sınırı | `@Transactional` **service** katmanında; controller ve repository'de değil |\n| P5 | Constructor injection | Field injection (`@Autowired` field) **yasak**; `final` + `@RequiredArgsConstructor` |\n| P6 | golge exception | Hata fırlatırken `Golge*Exception` (veya proje türevi) + `GolgeErrorDetail` |\n| P7 | i18n mesaj | Validation/iş kuralı mesajları `*Constraint` sabitleri + `{anahtar}` i18n |\n| P8 | REST/Feign ayrımı | Controller, `server` modülündeki `*RestClient` (`@RequestMapping`) arayüzünü `implements` eder; `client` modülündeki `@FeignClient` ayrı, published client'tır — ikisi karıştırılmamalı |\n\n---\n\n## 4. Controller — Yasak: /@CrossOrigin\\b/\n\n### 4.1 Standart yapı — Yasak: /ResponseEntity\\.status\\s*\\(\\s*\\d{3}\\s*\\)|new\\s+ResponseEntity\\s*</\n\nController **ince** olmalı, aşağıdaki imzaya uymalı:\n\n```java\n// /home/kerim/repositories/taraf/taraf-api/server/src/main/java/.../controller/GercekKisiOperationalRestController.java\n@RestController\n@RequiredArgsConstructor\n@PreAuthorize(\"hasAuthority('IY_KADASTRO_MUDURLUK_KULLANICISI')\")\npublic class GercekKisiOperationalRestController implements GercekKisiOperationalRestClient {\n\n    private final GercekKisiOperationalService gercekKisiOperationalService;\n\n    @Override\n    public ResponseEntity<UUID> addGercekKisi(GercekKisiCompositeDto gercekKisiCompositeDto) {\n        GercekKisiDto gercekKisiDto = gercekKisiOperationalService.addGercekKisi(gercekKisiCompositeDto);\n        return ResponseEntity.status(HttpStatus.CREATED).body(gercekKisiDto.getTarafId());\n    }\n}\n```\n\nİlgili **server-tarafı REST arayüzü** (URL, HTTP metot, `@Valid` burada tanımlanır). Bu arayüz `server` modülündedir ve `@RequestMapping` taşır — `@FeignClient` **değildir**, `client` modülündeki published Feign client ile karıştırılmamalı:\n\n```java\n// /home/kerim/repositories/taraf/taraf-api/server/src/main/java/.../controller/GercekKisiOperationalRestClient.java\n@RequestMapping(\"/api/kisiler\")               // @FeignClient DEĞİL — server-tarafı REST arayüzü\npublic interface GercekKisiOperationalRestClient {\n    @PostMapping(value = \"/\")\n    ResponseEntity<UUID> addGercekKisi(@Valid @RequestBody GercekKisiCompositeDto gercekKisiCompositeDto);\n}\n```\n\nDiğer servislerin bağımlılık aldığı **published Feign client ise ayrı bir sınıftır** (`client` modülünde, `@FeignClient` ile) ve genellikle curated/sınırlı bir uç alt kümesini yayınlar:\n\n```java\n// /home/kerim/repositories/taraf/taraf-api/client/src/main/java/.../client/TarafFeignClient.java\n@FeignClient(name = \"tarafFeignClient\", url = \"${taraf.service.url}\")   // gerçek Feign kontratı\npublic interface TarafFeignClient {\n    @PostMapping(value = \"/taraf/{tarafRef}\")\n    ResponseEntity<TapuIslemKisiKimlikKontroluDto> getGercekKisiById(@PathVariable(\"tarafRef\") UUID tarafRef);\n    // ... (server'daki tüm uçların değil, curated bir alt kümesinin Feign imzaları)\n}\n```\n\n**Konvansiyonlar:**\n- `@RestController` + `@RequiredArgsConstructor` (constructor injection).\n- `implements <Ad>RestClient` — `server` modülündeki (`server/.../controller/`) `@RequestMapping`'li REST arayüzü (`@FeignClient` değil). **Mapping anotasyonları arayüzde**, controller metodu `@Override`.\n- Sınıf düzeyinde `@PreAuthorize(\"hasAuthority('IY_...')\")` yetki.\n- `ResponseEntity<T>` döner; **ekleme** uçlarında `HttpStatus.CREATED` + üretilen `id`.\n\n#### NEDEN\nİnce controller; iş mantığını test edilebilir servise iter, HTTP detayını (status, header) tek yerde tutar. Controller'ın `server` modülündeki `*RestClient` (`@RequestMapping`) arayüzünü implement etmesi, **route tanımını (path/HTTP metot/`@Valid`) controller gövdesinden ayırır** ve tek yerde toplar; metot imzası ile route arasındaki uyum derleme zamanında garanti edilir. (Bu arayüz, `client` modülündeki `@FeignClient`'tan ayrıdır; çağıran taraf published Feign client'ı kullanır, sunan taraf bu server arayüzünü implement eder.)\n\n#### Review'da NASIL TESPİT edilir\n- Controller içinde `if/for/try-catch`, repository çağrısı, MapStruct çağrısı, `EntityManager` → **iş mantığı sızması**.\n- `implements *RestClient` yoksa veya mapping anotasyonları controller'a kopyalanmışsa → kontrat çift tanımı riski.\n- Metot dönüş tipinde entity (`ResponseEntity<Taraf>`) → P2 ihlali.\n\n#### NASIL DÜZELTİLİR\n\n**Anti-pattern 1 — Entity dönmek (gerçek örnek):**\n\n```java\n// ❌ ÖNCE — /home/kerim/repositories/taraf/.../controller/TarafSearchRestController.java\npublic ResponseEntity<Taraf> getTarafByIdList(UUID id) {            // Taraf = ENTITY!\n    Optional<Taraf> taraf = tarafSearchService.getTarafById(id);\n    return taraf.map(ResponseEntity::ok).orElseGet(() -> ResponseEntity.notFound().build());\n}\n```\n\n```java\n// ✅ SONRA — DTO dön, projeksiyon/mapper servis katmanında yapılsın\npublic ResponseEntity<TarafDto> getTarafById(UUID id) {\n    return tarafSearchService.getTarafDtoById(id)\n            .map(ResponseEntity::ok)\n            .orElseGet(() -> ResponseEntity.notFound().build());\n}\n```\n> Entity dönmek; lazy-loading sorunları, Envers/audit alanlarının sızması, JSON döngüsü ve API'nin DB şemasına bağlanması demektir.\n\n**Anti-pattern 2 — Hardcoded CORS (gerçek örnek):**\n\n```java\n// ❌ ÖNCE — /home/kerim/repositories/islem-yonetimi/.../controller/IslemRestController.java\n@RestController\n@CrossOrigin(origins = \"http://localhost:5173\")   // dev URL koda gömülü!\n@PreAuthorize(\"hasAuthority('IY_KADASTRO_MUDURLUK_KULLANICISI')\")\npublic class IslemRestController implements IslemRestClient { ... }\n```\n\n```java\n// ✅ SONRA — CORS merkezi WebMvc/gateway konfigürasyonunda; origin profil/property'den\n// configuration/WebConfig.java içinde CorsRegistry ile yönetilir; controller temiz kalır\n@RestController\n@PreAuthorize(\"hasAuthority('IY_KADASTRO_MUDURLUK_KULLANICISI')\")\npublic class IslemRestController implements IslemRestClient { ... }\n```\n\n---\n\n## 5. Service — Yasak: /new\\s+RestTemplate\\s*\\(/\n\n### 5.1 Standart yapı: arayüz + impl — Yasak: /new\\s+[A-Z][A-Za-z0-9]*(ServiceImpl|RepositoryImpl)\\s*\\(/\n\nService her zaman **arayüz + implementasyon** ikilisidir. Operasyonel (yazma) servisler `golge` generic service'i extend eder:\n\n```java\n// .../service/GercekKisiOperationalService.java\npublic interface GercekKisiOperationalService extends GolgeGenericOperationService<UUID, GercekKisiDto> {\n    GercekKisiDto addGercekKisi(@Valid @NotNull GercekKisiCompositeDto dto);\n    GercekKisiDto saveOrUpdate(GercekKisiDto gercekKisiDto);\n}\n```\n\nImpl, proje base impl'i üzerinden golge impl'e bağlanır (constructor injection):\n\n```java\n// .../service/impl/GercekKisiKimlikOperationalServiceImpl.java\n@Service\npublic class GercekKisiKimlikOperationalServiceImpl\n        extends TarafBaseOperationalServiceImpl<UUID, GercekKisiKimlikDto, GercekKisiKimlik,\n                                                GercekKisiKimlikMapper, GercekKisiKimlikOperationalRepository>\n        implements GercekKisiKimlikOperationalService {\n\n    public GercekKisiKimlikOperationalServiceImpl(EntityManager entityManager,\n            GercekKisiKimlikMapper mapper, GercekKisiKimlikOperationalRepository repository) {\n        super(entityManager, mapper, repository);\n    }\n}\n```\n\nSearch (okuma) servisleri sınıf düzeyinde `@Validated`:\n\n```java\n// .../service/GercekKisiSearchService.java\n@Validated\npublic interface GercekKisiSearchService {\n    Page<GercekKisiDto> getGercekKisiListePageByTanitimNo(GercekKisiSearchByTanitimNoQueryDto q);\n    Optional<GercekKisiOzetDto> getGercekKisiOzetBilgiById(GercekKisiOzetBilgiByIdQueryDto q);\n    ...\n}\n```\n\n**Konvansiyonlar:**\n- İş mantığı, koordinasyon (birden çok alt-servis çağrısı), iş kuralı kontrolü **servis katmanında**.\n- `golge` `GolgeGenericOperationService` / `GolgeGenericSearchService` extend; CRUD'u tekrar yazmadan kullan.\n- Proje base impl (`TarafBaseOperationalServiceImpl`) ortak `@Transactional` ve validation grup ayarlarını taşır.\n- `@Validated` sınıf/arayüz düzeyinde → metot parametrelerindeki `@Valid @NotNull` etkinleşir.\n\n#### NEDEN\nArayüz + impl ayrımı; controller'ın bağlandığı kontratla (server-tarafı `*RestClient` REST arayüzü) simetri sağlar, mock'lanabilir test verir, golge generic CRUD'u tekrar yazmamayı sağlar. İş mantığının servis katmanında olması, transaction sınırının doğru yere oturmasını (Bölüm 11) ve controller'ın ince kalmasını garantiler.\n\n#### Review'da NASIL TESPİT edilir\n- `@Service` sınıfı arayüz `implements` etmiyorsa → P3 ihlali (DI/test/mock zorlaşır).\n- CRUD metotları elle yeniden yazılmışsa (golge `save`/`update` zaten var) → tekrar.\n- Servis 8+ bağımlılık + 100+ satırlık tek metot → SRP/karmaşıklık (gerçek örnek aşağıda).\n\n#### NASIL DÜZELTİLİR — yüksek karmaşıklık (gerçek örnek)\n\n`GercekKisiOperationalServiceImpl.addGercekKisi` tek metotta taraf + kimlik + iletişim + vatandaşlık + fotoğraf + engel kaydını yapıyor (iç içe `if`'ler, kodda zaten `// TODO [SONAR-CRITICAL S3776]` notu var):\n\n```java\n// ✅ SONRA — alt adımlara böl; her blok kendi private metoduna\n@Transactional(transactionManager = \"transactionManager\", rollbackFor = ServerException.class)\npublic GercekKisiDto addGercekKisi(@Valid @NotNull GercekKisiCompositeDto dto) {\n    isKurallariniKontrolEt(dto);\n    TarafDto taraf = saveTaraf(dto);\n    GercekKisiDto kisi = saveGercekKisi(dto, taraf);\n    if (kisi == null) return null;                 // erken dönüş, iç içe if'i azaltır\n    saveKisiKimlikBilgileri(dto, kisi);\n    saveTarafIletisimleri(dto, taraf, kisi);\n    saveVatandaslik(dto, kisi);\n    saveKisiFotograf(dto, kisi);\n    saveKisiEngelVeIslemEhliyet(dto, kisi, taraf);\n    return kisi;\n}\n```\n> Her alt-adım ayrı, test edilebilir, bilişsel karmaşıklığı düşük private metot olur. `Objects.nonNull(...)` üçlü iç içe `if`'leri tek koşulda birleştir.\n\n---\n\n## 6. Repository — Yasak: /(SELECT|select)\\s+\\*\\s+(FROM|from)\\s/\n\n### 6.1 Standart yapı — Yasak: /create(Native)?Query\\s*\\([^;]*\"\\s*\\+\\s*[A-Za-z_$]/\n\nRepository, `golge` JPA repository arayüzünü extend eden bir Spring Data arayüzüdür:\n\n```java\n// /home/kerim/repositories/islem-yonetimi/.../repository/IslemRepository.java\n@Repository\npublic interface IslemRepository extends GolgeGenericJpaRepository<Islem, UUID> { }\n```\n\nTüretilmiş sorgu metotları (derived query) tercih edilir:\n\n```java\n// /home/kerim/repositories/basvuru/.../repository/operational/BasvuruOperationalRepository.java\n@Repository\npublic interface BasvuruOperationalRepository extends GolgeGenericJpaRepository<Basvuru, UUID> {\n    Basvuru findByBasvuruNumarasi(Long basvuruNo);\n}\n```\n\n**Konvansiyonlar:**\n- `@Repository` + `GolgeGenericJpaRepository<Entity, ID>` (veya `GolgeJpaRepository`).\n- Sorgu stratejisi sırası: (1) golge/Spring Data hazır metotları → (2) derived query (`findByX`) → (3) `@Query` JPQL → (4) son çare native query.\n- Native query **zorunluysa** parametreler `:isim` ile **mutlaka parametrelendirilmeli** (string concatenation ile değer eklemek YASAK).\n\n#### NEDEN\ngolge JPA repository; multi-datasource (search datasource), Envers audit ve soft-delete davranışını standartlaştırır. Parametrelendirilmiş sorgu **SQL injection**'ı önler; derived query ise yazım hatasını derleme/başlangıç zamanında yakalar.\n\n#### Review'da NASIL TESPİT edilir\n- Repository içinde iş mantığı / DTO dönüşümü → katman karışması.\n- `createNativeQuery(\"... \" + degisken + \" ...\")` ile **kullanıcı/dış girdi** birleştirme → **SQL injection riski**.\n- `nativeQuery=true` ile `:param` yerine string interpolasyon → injection.\n\n#### NASIL DÜZELTİLİR — native sorgu enjeksiyon karşıtı (gerçek örnek)\n\nDinamik **tablo/kolon adı** gerçekten gerektiğinde (parametre ile bağlanamaz), `islem-yonetimi`'deki çözüm referans alınmalı: `EntityManager` + **whitelist validator** + parametrelendirilmiş değerler.\n\n```java\n// /home/kerim/repositories/islem-yonetimi/.../islemtanimlari/repository/CascadeDeleteRepository.java\n@Repository\n@RequiredArgsConstructor\npublic class CascadeDeleteRepository {\n    private final EntityManager entityManager;\n    private final SqlIdentifierValidator sqlValidator;   // tanımlayıcı whitelist doğrulayıcı\n\n    public void softDeleteByDirectFk(String table, String fkColumn, Long refId) {\n        sqlValidator.validate(table, \"softDeleteByDirectFk.table\");     // ✅ identifier whitelist\n        sqlValidator.validate(fkColumn, \"softDeleteByDirectFk.fkColumn\");\n        entityManager.createNativeQuery(\n                \"UPDATE islem_yonetimi.\" + table + \" SET aktif = false WHERE \" + fkColumn + \" = :ref\")\n            .setParameter(\"ref\", refId)                 // ✅ DEĞER parametre ile bağlanır\n            .executeUpdate();\n    }\n}\n```\n\nJPQL/native sorgularda **değer** daima `:param` ile:\n\n```java\n// /home/kerim/repositories/islem-yonetimi/.../islemtanimlari/repository/IslemTanimRepository.java\n@Query(value = \"\"\"\n        WITH RECURSIVE tree AS ( ... )\n        SELECT ... FROM islem_yonetimi.it_islem_tanim i JOIN tree t ON t.id = i.id\n        WHERE i.id = :id\n        \"\"\", nativeQuery = true)\nList<Object[]> findByIdWithTree(Long id);            // ✅ değer parametrelendirilmiş\n```\n\n```java\n// ❌ ASLA YAPMA\nentityManager.createNativeQuery(\"UPDATE t SET aktif=false WHERE id = \" + userInput);  // SQL injection\n```\n> **Kural:** Değerler her zaman `:param`; sadece tanımlayıcılar (tablo/kolon) zorunlulukta string'e girer ve **whitelist'ten geçirilir**.\n\n---\n\n## 7. DTO — Yasak: /@Data\\b/\n\n### 7.1 Standart yapı — Yasak: /(?<!@Valid\\s)private\\s+(List|Set)<\\s*[A-Z][A-Za-z0-9]*Dto\\s*>/\n\nDTO'lar **`common`** modülde, golge base DTO'larından türer (Lombok ile):\n\n```java\n// /home/kerim/repositories/taraf/taraf-api/common/src/main/java/.../dto/TarafIletisimDto.java\n@Getter @Setter @NoArgsConstructor @AllArgsConstructor\n@SuperBuilder(toBuilder = true)\n@JsonView(value = GolgeView.Base.class)\n@EqualsAndHashCode(callSuper = false)\npublic class TarafIletisimDto extends TarafBaseAuditDto {\n\n    @NotNull(message = \"İletişim tipi boş olamaz\")\n    private Short iletisimTip;\n\n    @NotBlank(message = \"İletişim değeri boş olamaz\")\n    private String iletisimDeger;\n    ...\n}\n```\n\n**Composite DTO** — toplu/iç içe yazma işlemlerinde tek istekle birden çok varlık taşır; iç DTO'larda `@Valid` ile **cascade validation**:\n\n```java\n// .../common/dto/GercekKisiCompositeDto.java\n@Getter @Setter @NoArgsConstructor @AllArgsConstructor @SuperBuilder(toBuilder = true)\n@JsonView(value = GolgeView.Base.class) @EqualsAndHashCode(callSuper = false)\npublic class GercekKisiCompositeDto extends TarafBaseDto {\n    @Valid private GercekKisiDto gercekKisiDto;\n    @Valid private List<GercekKisiKimlikDto> gercekKisiKimlikDto;\n    private List<TarafIletisimDto> tarafIletisimDto;\n    @Valid private GercekKisiVatandaslikDto gercekKisiVatandaslikDto;\n    ...\n}\n```\n\n**Konvansiyonlar:**\n- DTO **`common`** modülde (servisler arası paylaşılır), entity asla.\n- Lombok seti: `@Getter @Setter @NoArgsConstructor @AllArgsConstructor @SuperBuilder(toBuilder=true) @EqualsAndHashCode(callSuper=...)`.\n- Bean Validation anotasyonları DTO alanında, mesajlar Türkçe (i18n için Bölüm 10).\n- Composite DTO'da iç nesnelerde `@Valid` (yoksa cascade validation çalışmaz!).\n\n#### record vs Lombok tartışması\n- **Mevcut konvansiyon: Lombok.** Çünkü golge base DTO'ları (`TarafBaseDto`, `TarafBaseAuditDto`) **mutable** alanlar + `@SuperBuilder` kalıtım gerektirir; `record` final ve kalıtımsız olduğu için golge generic CRUD (`save`/`update` setter bekler) ile uyumsuzdur.\n- **`record` ne zaman uygun:** Servisler arası **immutable** sorgu sonucu / projeksiyon / response-only DTO'larda (golge base'i extend etmeyen, setter gerektirmeyen). Yeni \"query result\" DTO'larda `record` tercih edilebilir.\n\n#### NEDEN\nDTO `common`'da olmaması, servisler arası kontrat paylaşımını imkânsızlaştırır. `@Valid` cascade olmadan iç koleksiyonlar **sessizce doğrulanmaz**. Teleskopik constructor'lar pozisyonel hata kaynağıdır.\n\n#### Review'da NASIL TESPİT edilir\n- Entity'nin Feign/REST sınırında DTO yerine geçmesi.\n- Composite DTO'da iç DTO/List üzerinde `@Valid` eksikliği → cascade validation devre dışı.\n- Aynı kavram için ikiz alanlar (`iletisimTip` + `iletisimTipi`, `ulke` + `ulkeKod`) → veri tutarsızlığı.\n- Çok sayıda teleskopik constructor (gerçek örnek: `TarafIletisimDto`'da 6 adet) → builder varken gereksiz, hata-açık.\n\n#### NASIL DÜZELTİLİR\n\n```java\n// ❌ ÖNCE — TarafIletisimDto'da 6 teleskopik constructor (pozisyonel, hataya açık)\npublic TarafIletisimDto(UUID id, Short iletisimTip, String iletisimDeger, Boolean aktif, ...16 param...) { ... }\n\n// ✅ SONRA — @SuperBuilder zaten var; el-yapımı constructor'ları kaldır,\n//            JPQL projeksiyonlarda constructor-expression yerine interface/record projeksiyon kullan\nTarafIletisimDto.builder().id(id).iletisimTip(tip).iletisimDeger(deger).build();\n```\n\n---\n\n## 8. Mapper — Yasak: /BeanUtils\\.copyProperties\\s*\\(|new\\s+ModelMapper\\s*\\(/\n\n### 8.1 Standart yapı — Yasak: /@Mapper\\b(?!\\s*\\([^)]*(componentModel|nullValuePropertyMappingStrategy))/\n\nMapper, MapStruct arayüzü olup golge generic mapper'ı extend eder:\n\n```java\n// /home/kerim/repositories/taraf/.../mapper/GercekKisiKimlikMapper.java\n@Mapper(nullValuePropertyMappingStrategy = NullValuePropertyMappingStrategy.IGNORE)\npublic interface GercekKisiKimlikMapper\n        extends GolgeGenericMapstructMapper<UUID, GercekKisiKimlikDto, GercekKisiKimlik> { }\n```\n\n`islem-yonetimi`'de aynı kontrat, açık Spring component model ile:\n\n```java\n// /home/kerim/repositories/islem-yonetimi/.../mapper/IslemMapper.java\n@Mapper(componentModel = MappingConstants.ComponentModel.SPRING)\npublic interface IslemMapper extends GolgeGenericMapstructMapper<UUID, IslemDto, Islem> { }\n```\n\n`GolgeGenericMapstructMapper`'ın sağladığı kontrat (javap ile doğrulandı):\n\n```text\nDTO  convertEntityToDto(E)\nE    convertDtoToEntity(DTO)\nvoid mapToEntity(DTO, E)     // var olan entity'yi yerinde günceller (update mapping)\nList/Set toplu dönüşümler\n```\n\n**Konvansiyonlar:**\n- `@Mapper` + `GolgeGenericMapstructMapper<ID, Dto, Entity>` extend.\n- **Null değer stratejisi:** `nullValuePropertyMappingStrategy = IGNORE` → partial/PATCH update'te DTO'daki `null` alanlar entity'nin mevcut değerini **ezmez** (özellikle `@DynamicUpdate` entity'lerle). Taraf'taki tüm mapper'lar bunu kullanır.\n- **Update mapping:** Var olan entity'yi güncellerken `convertDtoToEntity` ile yeni nesne yaratıp kaydetmek yerine `mapToEntity(dto, managedEntity)` ile **managed entity üzerine** yaz (Envers/optimistic-lock/version korunur).\n- `componentModel` tutarlı olmalı (golge plugin Spring component üretir; ek `@Mapper(componentModel=SPRING)` repo geneliyle tutarlı kullanılmalı).\n\n#### NEDEN\nMapStruct compile-time mapper üretir (reflection yok, hızlı, tip güvenli). `IGNORE` stratejisi olmadan partial update istekleri eksik alanları `null`'a çeker → **veri kaybı**. `mapToEntity` yerine `convertDtoToEntity` ile yeni entity kaydetmek detached/yeni satır, version sıfırlanması ve audit kopukluğu yaratır.\n\n#### Review'da NASIL TESPİT edilir\n- Elle `new Entity(); setX(dto.getX())...` dönüşümü (mapper varken) → tekrar, hata kaynağı.\n- Update senaryosunda `convertDtoToEntity` + `save` kullanımı → mevcut entity'nin overwrite'i, version kaybı.\n- Null stratejisi belirtilmeden partial update beklentisi → istemeden alan sıfırlama.\n\n#### NASIL DÜZELTİLİR\n\n```java\n// ❌ ÖNCE — update'te yeni entity üretip kaydetmek (version/audit kopar)\nGercekKisiKimlik e = mapper.convertDtoToEntity(dto);\nrepository.save(e);\n\n// ✅ SONRA — managed entity'yi getir, üzerine yerinde map et\nGercekKisiKimlik managed = repository.getById(dto.getId());\nmapper.mapToEntity(dto, managed);     // IGNORE stratejisiyle null alanlar korunur\nrepository.update(managed);\n```\n\n---\n\n## 9. Exception Handling — Yasak: /catch\\s*\\([^)]*\\)\\s*\\{\\s*\\}/\n\n### 9.1 golge exception tipleri ve ne zaman — Yasak: /throw\\s+new\\s+(RuntimeException|IllegalArgumentException|IllegalStateException|Exception)\\s*\\(/\n\n| golge tipi | Tür | HTTP | Ne zaman |\n|-----------|-----|------|----------|\n| `GolgeBusinessRuleException` | Unchecked | 400 | İş kuralı ihlali (ör. zorunlu alan/kombinasyon hatası) |\n| `GolgeResourceNotFoundException` | Unchecked | 404 | Kayıt bulunamadı |\n| `GolgeUncheckedException` | Unchecked | (custom) | Proje türevi base; özel `GolgeErrorDetail` ile |\n| `GolgeCheckedException` | Checked | (custom) | İmzayla yayılması gereken, çağıranı zorlayan hata |\n\nProjeler kendi türevlerini `GolgeUncheckedException` üzerine kurar ve `GolgeErrorDetail`'i builder ile doldurur:\n\n```java\n// /home/kerim/repositories/taraf/.../exception/TarafBusinessRuleException.java\n@NoArgsConstructor\npublic class TarafBusinessRuleException extends GolgeUncheckedException {\n    private static final int STATUS = 400;\n    public TarafBusinessRuleException(String code, String message) {\n        super(GolgeErrorDetail.builder().code(code).message(message).httpStatus(STATUS).build());\n    }\n}\n```\n\n```java\n// /home/kerim/repositories/basvuru/.../exception/BasvuruResourceNotFoundException.java\npublic class BasvuruResourceNotFoundException extends GolgeUncheckedException {\n    private static final int STATUS = HttpStatus.NOT_FOUND.value();\n    public BasvuruResourceNotFoundException(String code, String message) {\n        super(GolgeErrorDetail.builder().code(code).message(message).httpStatus(STATUS).build());\n    }\n}\n```\n\n`GolgeErrorDetail`, ek bağlam (`attributes`) ve neden (`cause`) taşıyabilir (gerçek örnek — basvuru süreç hatası):\n\n```java\n// /home/kerim/repositories/basvuru/.../exception/BasvuruProcessException.java\npublic BasvuruProcessException(String code, String message, UUID basvuruId, String processInstanceId, Throwable cause) {\n    super(GolgeErrorDetail.builder()\n            .code(code).message(message).httpStatus(HttpStatus.INTERNAL_SERVER_ERROR.value())\n            .attributes(buildAttributes(basvuruId, processInstanceId))   // bağlam: basvuruId, processInstanceId\n            .cause(cause.getMessage())\n            .build(), cause);   // ✅ orijinal cause zincire eklenir\n}\n```\n\n### 9.2 Global donus — GolgeContextExceptionHandler — Yasak: /catch\\s*\\([^)]*\\)\\s*\\{[^}]*return\\s+(null|Optional\\.empty)/\n\ngolge, `ResponseEntityExceptionHandler` türevi global bir handler sağlar (javap ile doğrulandı): `handleMethodArgumentNotValid`, `handleHandlerMethodValidationException`, `handleHttpMessageNotReadable`, `handleAllException`. Bu sayede fırlatılan `Golge*Exception` ve validation hataları **standart JSON gövdesiyle** (`GolgeErrorDetail`) döner.\n\n**Konvansiyon:** Servis iş kuralı hatasında **doğru tipi fırlat**; controller'da `try-catch` ile yutma. Proje bazlı `@RestControllerAdvice` gerekiyorsa (golge handler'ı yetmiyorsa) ayrı değerlendir — `BasvuruBusinessRuleException` üzerindeki `// TODO: Golge framework'ün @ControllerAdvice mekanizması incelenmeli (TAK-22512)` notu bu kararın açık olduğunu gösterir.\n\n#### NEDEN\ngolge exception + `GolgeErrorDetail`; tüm servislerde **tutarlı hata gövdesi** (code/message/httpStatus/attributes) üretir; frontend tek formata göre yazılır. Exception yutmak (catch-log-return null) hatayı gizler, üst katman yanlış başarı varsayar.\n\n#### Review'da NASIL TESPİT edilir\n- `catch (Exception e) { log.error(...); return null; }` → **exception yutma** (anti-pattern).\n- Genel `RuntimeException`/`IllegalArgumentException` fırlatma (golge tipi yerine) → standart gövde yok, yanlış HTTP status.\n- `cause` aktarılmadan yeni exception fırlatma → stack trace kopar, debug zorlaşır.\n- Controller'da iş kuralı `try-catch` → servisteki golge handler devre dışı kalır.\n\n#### NASIL DÜZELTİLİR\n\n```java\n// ❌ ÖNCE — exception yutma\npublic GercekKisiDto getById(UUID id) {\n    try { return repository.getById(id) ...; }\n    catch (Exception e) { log.error(\"hata\", e); return null; }   // çağıran null'ı başarı sanır\n}\n\n// ✅ SONRA — doğru golge tipini fırlat, cause'u koru\npublic GercekKisiDto getById(UUID id) {\n    return repository.findById(id)\n            .map(mapper::convertEntityToDto)\n            .orElseThrow(() -> new TarafBusinessRuleException(\n                    \"TARAF-404\", \"Gerçek kişi bulunamadı: \" + id));\n}\n```\n\n---\n\n## 10. Validation — Yasak: /import\\s+javax\\.validation\\./\n\n### 10.1 Katman bazlı doğrulama — Yasak: /(?<!@Valid\\s)@RequestBody\\b/\n\n1. **API girişi** — controller'ın implement ettiği server-tarafı `*RestClient` (`@RequestMapping`) arayüzünde `@Valid @RequestBody`:\n   ```java\n   // server/.../controller/GercekKisiOperationalRestClient.java  (@RequestMapping arayüzü)\n   ResponseEntity<UUID> addGercekKisi(@Valid @RequestBody GercekKisiCompositeDto dto);\n   ```\n2. **DTO alanları** — jakarta Bean Validation, mesajla:\n   ```java\n   @NotNull(message = \"İletişim tipi boş olamaz\") private Short iletisimTip;\n   @NotBlank(message = \"İletişim değeri boş olamaz\") private String iletisimDeger;\n   ```\n3. **Service metodu** — sınıf/arayüzde `@Validated` + parametrede `@Valid @NotNull`:\n   ```java\n   // @Validated arayüz/impl + \n   GercekKisiDto addGercekKisi(@Valid @NotNull GercekKisiCompositeDto dto);\n   ```\n4. **Validation grupları** — golge `GolgeView.Merge` ile update senaryosu (proje base impl):\n   ```java\n   // TarafBaseOperationalServiceImpl\n   @Validated(value = {Default.class, GolgeView.Merge.class})\n   @Override public GDTO update(GDTO dto) { return super.update(dto); }\n   ```\n\n### 10.2 *Constraint sabit siniflari + i18n — Yasak: /@(Size|Column)\\s*\\([^)]*(max|length)\\s*=\\s*\\d+/\n\nKolon adı / boyut sabitleri ayrı, `final`, private-constructor sınıflarda:\n\n```java\n// /home/kerim/repositories/taraf/.../entity/constraint/GercekKisiKimlikConstraint.java\n@NoArgsConstructor(access = AccessLevel.PRIVATE)\npublic final class GercekKisiKimlikConstraint {\n    public static final String TABLE_NAME = \"kisi_kimlik\";\n    public static final String ADI_COLUMN = \"adi\";\n    public static final int ADI_MAX_SIZE = 60;\n    public static final int SERI_NO_MAX_SIZE = 20;\n    ...\n}\n```\n\nBu sabitler entity `@Column(name=..., length=...)` ve DTO `@Size(max=...)` içinde tek kaynak olarak kullanılır. **i18n mesaj:** validation mesajları `{anahtar}` formatında, `messages/validation-messages*.properties` (tr/en) dosyalarından çözülür:\n\n```properties\n# /home/kerim/repositories/taraf/.../resources/messages/validation-messages_tr.properties\nquestion.sentence.is.empty=Soru cumlesi bos olamaz.\n```\n\n```java\n// ✅ i18n anahtarı — mesaj koda gömülmez, properties'ten gelir\n@NotBlank(message = \"{question.sentence.is.empty}\")\nprivate String soruCumlesi;\n```\n\n#### NEDEN\nKatman bazlı validation; geçersiz veriyi en erken sınırda durdurur (controller), iş katmanında da güvence verir (`@Validated` + `@Valid`). `*Constraint` sabitleri DB şeması ↔ DTO ↔ entity arasında **tek doğruluk kaynağı** sağlar (boyut tutarsızlığını önler). `{anahtar}` i18n; mesajları çok dilli ve merkezi kılar.\n\n#### Review'da NASIL TESPİT edilir\n- Controller arayüzünde `@Valid` eksik → DTO doğrulanmaz.\n- Servis `@Validated` değilse, metot parametre `@Valid @NotNull`'ları **çalışmaz** (proxy devreye girmez).\n- Magic number `@Size(max = 60)` (sabit yerine) → boyut DB ile sapabilir.\n- Hardcoded Türkçe mesaj (i18n `{anahtar}` yerine) → çok dil/merkezi yönetim yok.\n\n#### NASIL DÜZELTİLİR\n\n```java\n// ❌ ÖNCE — magic number + gömülü mesaj\n@Size(max = 60, message = \"Ad 60 karakteri aşamaz\") private String adi;\n\n// ✅ SONRA — Constraint sabiti + i18n anahtarı\n@Size(max = GercekKisiKimlikConstraint.ADI_MAX_SIZE, message = \"{taraf.ad.maxSize}\")\nprivate String adi;\n```\n\n---\n\n## 11. Transaction — Yasak: /import\\s+(javax|jakarta)\\.transaction\\.Transactional/\n\n### 11.1 Standart yapı — Yasak: /@Transactional(?!\\s*\\([^)]*transactionManager)/\n\n`@Transactional` sınırı **servis katmanındadır** (controller/repository değil). golge proje base impl bunu sınıf düzeyinde tanımlar:\n\n```java\n// /home/kerim/repositories/taraf/.../service/impl/base/TarafBaseOperationalServiceImpl.java\n@Transactional(transactionManager = \"transactionManager\")\npublic abstract class TarafBaseOperationalServiceImpl<...> extends GolgeGenericOperationServiceImpl<...> {\n    @Validated(value = {Default.class, GolgeView.Merge.class})\n    @Override public GDTO update(GDTO dto) { return super.update(dto); }\n    ...\n}\n```\n\nÇok adımlı atomik işlemde metot düzeyinde `rollbackFor`:\n\n```java\n// GercekKisiOperationalServiceImpl.addGercekKisi\n@Transactional(transactionManager = \"transactionManager\", rollbackFor = ServerException.class)\npublic GercekKisiDto addGercekKisi(@Valid @NotNull GercekKisiCompositeDto dto) { ... }\n```\n\n**Konvansiyonlar:**\n- `@Transactional` **servis** metot/sınıfında. Multi-datasource olduğundan **`transactionManager` adı açıkça verilmeli** (`transactionManager` vs search/replica datasource manager'ı). Yanlış manager → işlem yanlış DB'de.\n- Salt-okuma servis/metotlarında `@Transactional(readOnly = true)` → Hibernate flush/dirty-check kapanır, performans + yanlışlıkla yazmayı engeller.\n- Checked exception'da rollback için `rollbackFor` (varsayılan sadece `RuntimeException`'da rollback yapar).\n- Toplu/composite yazma tek transaction içinde (kısmi kayıt = tutarsız veri).\n\n#### NEDEN\nTransaction sınırı serviste; çünkü iş birimi (ör. taraf + kimlik + iletişim) **atomik** olmalı. Controller'da olursa transaction HTTP'ye bağlanır; repository'de olursa her CRUD ayrı commit'lenir (kısmi kayıt). `readOnly` okuma yolunu hızlandırır. `rollbackFor`, checked exception'da kayıtların **geri alınmasını** sağlar.\n\n#### Review'da NASIL TESPİT edilir\n- `@Transactional` controller/repository'de → yanlış sınır.\n- Self-invocation: aynı sınıf içinde `this.transactionalMetod()` çağrısı → **proxy atlanır, transaction başlamaz**.\n- `private`/`final` metotta `@Transactional` → proxy uygulanamaz, sessizce etkisiz.\n- Uzun transaction içinde HTTP/Feign çağrısı → DB connection uzun süre tutulur (havuz tükenir).\n- Multi-datasource'ta `transactionManager` belirtilmemiş → yanlış DB'ye yazma/okuma.\n\n#### NASIL DÜZELTİLİR\n\n```java\n// ❌ ÖNCE — self-invocation: addGercekKisi içinden this.saveKimlik() çağrısı,\n//           saveKimlik üzerindeki @Transactional/yeni-propagation ETKİSİZ kalır\npublic GercekKisiDto addGercekKisi(...) { this.saveKimlik(dto); }\n@Transactional(propagation = REQUIRES_NEW) public void saveKimlik(...) { ... }   // proxy atlandı!\n\n// ✅ SONRA — ayrı bean'e taşı (proxy devreye girer) veya tek transaction tasarımı kullan\nprivate final GercekKisiKimlikOperationalService kimlikService;   // ayrı bean\npublic GercekKisiDto addGercekKisi(...) { kimlikService.saveKimlik(dto); }  // ✅ proxy üzerinden\n```\n\n```java\n// ✅ Okuma yolunda readOnly + doğru manager\n@Transactional(transactionManager = \"transactionManager\", readOnly = true)\npublic Page<GercekKisiDto> getGercekKisiListePageByTanitimNo(...) { ... }\n```\n\n> **Uzun transaction karşıtı:** Feign/HTTP/Kafka publish çağrılarını transaction dışına al; sadece DB işlemini `@Transactional` içine koy. Dış çağrıyı `TransactionSynchronization`/`@TransactionalEventListener(AFTER_COMMIT)` ile commit sonrasına ertele.\n\n---\n\n## 12. Ek Standartlar — Yasak: /(password|Password|secret|Secret|apiKey|ApiKey)\\s*=\\s*\"[^\"]{3,}\"/\n\n### 12.1 SADECE constructor injection (field injection YASAK) — Yasak: /@Autowired\\b/\n\n**Kural:** Bağımlılıklar `private final` + constructor (Lombok `@RequiredArgsConstructor`) ile enjekte edilir. `@Autowired` **field** injection yasaktır.\n\n**Gerçek anti-pattern (kodda zaten SONAR notu var):**\n\n```java\n// ❌ ÖNCE — /home/kerim/repositories/taraf/.../service/impl/GercekKisiVatandaslikSearchServiceImpl.java\n// TODO [SONAR-MINOR] Field injection (@Autowired) yerine constructor injection\n@Autowired\nprivate TipDegerSearchService tipDegerSearchService;\n\n// ✅ SONRA\nprivate final TipDegerSearchService tipDegerSearchService;   // + sınıfa @RequiredArgsConstructor\n```\n\n**NEDEN:** field injection; `final` yapamaz (immutability yok), test'te mock enjekte etmek için reflection/Spring context gerekir, döngüsel bağımlılığı gizler, NPE riskini başlatma sırasına bağlar. Constructor injection bunların hepsini derleme/başlatma zamanında çözer.\n**TESPİT:** `grep -rn \"@Autowired\" .../server/src/main` — field üzerinde her eşleşme bulgu. (`@PersistenceContext EntityManager` field kalabilir — istisna.)\n\n### 12.2 Java 21 idiomları (eski API yerine) — Yasak: /new\\s+Date\\s*\\(\\s*\\)|java\\.util\\.(Date|Calendar)\\b|new\\s+SimpleDateFormat\\s*\\(/\n\n| Eski / kaçınılan | Modern Java 21 | Neden |\n|------------------|----------------|-------|\n| `java.util.Date`, `Calendar` | `java.time.*` (`LocalDate`, `LocalDateTime`, `Instant`, `OffsetDateTime`) | immutable, thread-safe, net semantik |\n| `null` dönmek | `Optional<T>` + `orElseThrow(...)` | NPE'yi tipe taşır (bkz. `getGercekKisiOzetBilgiById` → `Optional`) |\n| uzun `if-else if` zinciri | `switch` pattern matching / switch expression | okunur, exhaustive |\n| açık tip tekrarı | yerel `var` (yalnızca tip aşikârsa) | gürültü azaltır; API imzasında kullanma |\n| string birleştirme SQL/JSON | text block `\"\"\"...\"\"\"` | bkz. `IslemTanimRepository` recursive CTE |\n\n```java\n// ❌ ÖNCE\nDate olusturma = new Date();                         // mutable, zaman dilimi belirsiz\nif (tip == 1) {...} else if (tip == 2) {...} else {...}\n\n// ✅ SONRA\nOffsetDateTime olusturma = OffsetDateTime.now();\nString sonuc = switch (tip) {\n    case 1 -> \"gercek\";\n    case 2 -> \"tuzel\";\n    default -> throw new TarafBusinessRuleException(\"TARAF-TIP\", \"Bilinmeyen tip: \" + tip);\n};\n```\n> **TESPİT:** `grep -rn \"new Date()\\|java.util.Date\" .../server/src/main` (gerçekte `taraf` entity/helper/mapper'da geçiyor). Audit alanlarında golge zaten `java.time` kullanır; iş kodunda da tutarlı ol.\n\n### 12.3 Kafka (idempotency / ack) — Yasak: /enable\\.idempotence\"?\\s*[:=,]\\s*\"?false|acks\"?\\s*[:=,]\\s*\"?[01]\\b/\n\n> Not: İncelenen üç serviste aktif Kafka producer/consumer bulunmadı; aşağıdaki kurallar platform standardı (golge Kafka + `ekosistem`) içindir. Kafka kullanan servislerde uygula.\n\n- **Producer:** `acks=all` (veri kaybını önle), `enable.idempotence=true` (duplikasyonu önle), publish'i **commit sonrasına** ertele (uzun transaction içinde publish etme).\n- **Consumer:** İşleyici **idempotent** olmalı (aynı mesaj iki kez gelebilir — at-least-once). Manuel `ack`/`AckMode.MANUAL` ile **iş başarıyla bittikten sonra** ack ver; başarısızsa ack verme (retry/DLT).\n- Mesaj anahtarı (key) ile sıralama garantisi gereken kayıtları aynı partition'a yönlendir.\n\n```java\n// ✅ idempotent consumer + iş bitince ack\n@KafkaListener(topics = \"taraf-events\", ackMode = MANUAL)\npublic void onEvent(TarafEvent e, Acknowledgment ack) {\n    if (islendiMi(e.id())) { ack.acknowledge(); return; }   // idempotency kontrolü\n    isle(e);\n    ack.acknowledge();                                       // ✅ iş bitince ack\n}\n```\n\n### 12.4 Config / profil — Yasak: /\"https?:\\/\\/(localhost|127\\.0\\.0\\.1)/\n\n- Konfigürasyon **remote config server** üzerinden (Spring Cloud Config), `bootstrap.yml`'de `spring.cloud.config` + profil listesi:\n  ```yaml\n  # /home/kerim/repositories/taraf/.../resources/bootstrap.yml\n  spring.cloud.config.profile: actuator,ekolog,jpa,swagger,web,security,keycloak,taraf,...\n  ```\n- **Sır/parametre koda gömülmez**; `${ENV_VAR:default}` placeholder ile dışarıdan gelir (port, app adı, config URL hep `${...}` ile).\n- **Anti-pattern:** `@CrossOrigin(origins = \"http://localhost:5173\")` gibi ortam-özel değerlerin koda gömülmesi (bkz. Bölüm 4.1). Bunlar profile/property'ye taşınmalı.\n- **TESPİT:** Koda gömülü URL/host/port/parola; `application*.yml` içinde düz metin sır.\n\n### 12.5 Guvenlik anotasyon konvansiyonu — Yasak: /hasRole\\s*\\(|permitAll\\b/\n\n- Yetkilendirme: sınıf veya metot düzeyinde `@PreAuthorize(\"hasAuthority('IY_...')\")`. Rol deseni **`IY_*`** (ör. `IY_KADASTRO_MUDURLUK_KULLANICISI`). Üç repoda da bu desen geçerli.\n- golge güvenlik anotasyonları: `@GolgePublicEndpoint` (kimlik doğrulama gerektirmeyen uç), `@GolgeSecureEndpoint` (güvenli uç) — public uçlar **açıkça** işaretlenmeli; aksi halde varsayılan güvenli kabul edilir.\n- Keycloak (OAuth2/JWT) ile entegre; yetki rolü token'dan gelir.\n- **TESPİT:** Yazma uçlarında `@PreAuthorize` eksikliği → yetkisiz erişim. Public yapılmak istenen uçta golge public anotasyonu yoksa istem reddedilir; tam tersine hassas uca yanlışlıkla public anotasyon konması da bulgu.\n\n### 12.6 REST arayuzu (server) vs published Feign client (client) — iki ayri kontrat — Yasak: /\"Authorization\"|HttpHeaders\\.AUTHORIZATION/\n\nBu iki kavram sık karıştırılır; **aynı şey değildir**:\n\n| | **(a) Server `*RestClient` / `*SearchClient`** | **(b) Client `<Ad>FeignClient`** |\n|---|---|---|\n| Modül | `server` (`server/.../controller/`) | `client` |\n| Anotasyon | `@RequestMapping`/`@PostMapping`/`@GetMapping` | `@FeignClient(name=..., url=\"${...}\")` |\n| Rolü | Controller'ın `@Override` ile **implement ettiği** server-tarafı route arayüzü | Diğer servislerin bağımlılık aldığı **published Feign client** |\n| Kapsam | Servisin tüm uçları | Genellikle **curated/sınırlı** uç alt kümesi |\n| Örnek | `taraf-api/server/.../controller/GercekKisiOperationalRestClient.java` | `taraf-api/client/.../client/TarafFeignClient.java` |\n\n- **Sunan taraf:** Controller, `server` modülündeki `*RestClient` (`@RequestMapping`) arayüzünü `implements` eder; path/HTTP metot/`@RequestBody`/`@Valid` **bu arayüzde** tanımlı, controller `@Override` ile sadece gövdeyi yazar (bkz. Bölüm 4).\n- **Çağıran taraf:** Diğer servisler `client` modülündeki `@FeignClient`'a (`TarafFeignClient` / `IslemYonetimiFeignClient` / `BasvuruFeignClient` vb.) bağımlılık alır. Bu, server `*RestClient` ile **aynı arayüz değildir**; ayrı yazılır ve genelde uçların bir alt kümesini yayınlar.\n- **Yanılgı:** \"Tek `*RestClient` arayüzü hem Feign çağıran hem controller tarafından paylaşılır\" / \"`*RestClient`, `client` modülünde bir `@FeignClient`'tır\" **doğru değildir**. `find` ile doğrulandı: `client` modülünde hiçbir `*RestClient` yoktur; hepsi `server/.../controller/`tedir ve `@FeignClient` taşımaz.\n- Auth header propagasyonu golge `golge-feign-client` interceptor'ı ile otomatik (JWT taşınır) — elle header set etme.\n- **REST semantiği:** Salt-okuma/idempotent listeleme uçları için `@GetMapping` tercih edilmeli; gerçek kodda `TipDegerClient`'ta listeleme uçları `@PostMapping` ile tanımlanmış (kodda `// TODO [ONERI-TUTARLILIK]` notu var) — review'da GET'e çevirme önerilir (cache'lenebilirlik + tutarlılık).\n- **TESPİT:** Server `*RestClient` arayüzünde mapping anotasyonlarının arayüz yerine controller sınıfında tekrarlanması (kontrat çift tanımı); published `@FeignClient` ile server `*RestClient`'ın yanlışlıkla tek arayüz sanılması; bir server `@RequestMapping` arayüzüne yanlışlıkla `@FeignClient` eklenmesi.\n\n---\n\n## 13. Hızlı Referans (Checklist)\n\n| ✅ | Kontrol |\n|----|---------|\n| ☐ | Controller ince; iş mantığı yok; `server` modülündeki `*RestClient` (`@RequestMapping`) `implements` (≠ `client` modülündeki `@FeignClient`); sadece DTO döner |\n| ☐ | Ekleme ucu `HttpStatus.CREATED` + id döner |\n| ☐ | Sınıf/metot düzeyinde `@PreAuthorize(\"hasAuthority('IY_...')\")` |\n| ☐ | Service arayüz + impl; golge generic service extend |\n| ☐ | Service `@Validated`; parametrelerde `@Valid @NotNull` |\n| ☐ | Repository `@Repository` + golge JPA repo; native sorgu parametrelendirilmiş |\n| ☐ | Dinamik tablo/kolon adı whitelist validator'dan geçiyor |\n| ☐ | DTO `common` modülde; Composite DTO iç nesnelerde `@Valid` |\n| ☐ | Mapper golge generic mapper extend; `NullValuePropertyMappingStrategy.IGNORE`; update'te `mapToEntity` |\n| ☐ | İş kuralı/404'te `Golge*Exception` + `GolgeErrorDetail`; exception yutulmuyor; `cause` korunuyor |\n| ☐ | Validation mesajları `{anahtar}` i18n; boyutlar `*Constraint` sabitinden |\n| ☐ | `@Transactional` serviste; `transactionManager` adı açık; okuma `readOnly`; checked için `rollbackFor`; self-invocation yok |\n| ☐ | Tüm bağımlılıklar `private final` + constructor; `@Autowired` field yok |\n| ☐ | `java.time` (Date değil); `Optional` (null değil); Feign auth elle set edilmiyor |\n| ☐ | Ortam değerleri koda gömülü değil (`${ENV:default}` / config server) |\n\n---\n\n## 14. İlgili Dosyalar (gerçek, doğrulanmış)\n\n**Controller / server-tarafı REST arayüzü:**\n- `taraf-api/server/.../controller/GercekKisiOperationalRestController.java` (referans ince controller)\n- `taraf-api/server/.../controller/GercekKisiOperationalRestClient.java` (server-tarafı REST arayüzü, `@RequestMapping`/`@PostMapping` — `@FeignClient` DEĞİL)\n- `taraf-api/server/.../controller/TarafSearchRestController.java` (❌ entity döndürme anti-pattern)\n- `taraf-api/server/.../controller/TipDegerClient.java` (server `@RequestMapping` arayüzü; GET/POST semantiği TODO)\n- `islem-yonetimi-api/server/.../controller/IslemRestController.java` (❌ hardcoded `@CrossOrigin`)\n- `basvuru-api/server/.../controller/impl/BasvuruSearchRestController.java`\n\n**Published Feign client (client modülü, `@FeignClient` — server `*RestClient`'tan ayrı):**\n- `taraf-api/client/.../client/TarafFeignClient.java`\n- `islem-yonetimi-api/client/.../client/IslemYonetimiFeignClient.java`, `IslemFeignClient.java`\n- `basvuru-api/client/.../client/BasvuruFeignClient.java`\n\n**Service:**\n- `taraf-api/server/.../service/GercekKisiOperationalService.java`, `GercekKisiSearchService.java`\n- `taraf-api/server/.../service/impl/base/TarafBaseOperationalServiceImpl.java` (golge extend + `@Transactional` + validation grupları)\n- `taraf-api/server/.../service/impl/GercekKisiOperationalServiceImpl.java` (composite yazma; SONAR S3776 TODO)\n- `taraf-api/server/.../service/impl/GercekKisiVatandaslikSearchServiceImpl.java`, `TuzelKisiSearchServiceImpl.java` (❌ field injection)\n\n**Repository:**\n- `islem-yonetimi-api/server/.../repository/IslemRepository.java` (golge generic)\n- `basvuru-api/server/.../repository/operational/BasvuruOperationalRepository.java` (derived query)\n- `islem-yonetimi-api/server/.../islemtanimlari/repository/CascadeDeleteRepository.java` (EntityManager + `SqlIdentifierValidator` whitelist)\n- `islem-yonetimi-api/server/.../islemtanimlari/repository/IslemTanimRepository.java` (`@Query` native, parametrelendirilmiş, text block)\n\n**DTO:**\n- `taraf-api/common/.../dto/GercekKisiCompositeDto.java` (Composite, `@Valid` cascade)\n- `taraf-api/common/.../dto/TarafIletisimDto.java` (validation + ❌ teleskopik constructor'lar)\n\n**Mapper:**\n- `taraf-api/server/.../mapper/GercekKisiKimlikMapper.java`, `TarafMapper.java` (`IGNORE` stratejisi)\n- `islem-yonetimi-api/server/.../mapper/IslemMapper.java` (`componentModel = SPRING`)\n\n**Exception:**\n- `taraf-api/server/.../exception/TarafBusinessRuleException.java`\n- `basvuru-api/server/.../exception/BasvuruResourceNotFoundException.java`, `BasvuruBusinessRuleException.java`, `BasvuruProcessException.java`\n\n**Validation / config:**\n- `taraf-api/server/.../entity/constraint/GercekKisiKimlikConstraint.java`\n- `taraf-api/server/.../resources/messages/validation-messages_tr.properties`\n- `taraf-api/server/.../resources/bootstrap.yml`\n\n**golge framework (jar — javap/unzip ile doğrulandı; cache'teki 1.9.0 jar'ları üzerinden, yanı sıra 1.8.1 de mevcut; aktif sürüm BOM'dan gelir):**\n- `golge-web-starter` (`tr.com.test.golge.web.starter.service`): `GolgeGenericOperationService(Impl)`, `GolgeGenericSearchService(Impl)`\n- `golge-data-orm-jpa`: `GolgeGenericJpaRepository`, `GolgeJpaNativeRepository`\n- `golge-data-orm-mapper`: `GolgeGenericMapstructMapper`\n- `golge-exception`: `tr.com.test.golge.exception.GolgeUncheckedException` / `GolgeBusinessRuleException` / `GolgeResourceNotFoundException` / `GolgeCheckedException`; `tr.com.test.golge.exception.model.GolgeErrorDetail` (model alt-paketi)\n- `golge-context`: `tr.com.test.golge.context.handler.GolgeContextExceptionHandler`\n\n**Çapraz-link:** Entity/Audit/Liquibase standartları, Frontend (mikro-frontend) review, Güvenlik (Keycloak/JWT) dokümanları ayrı tutulur; bu doküman backend Spring Boot katmanlarını kapsar.\n",
  "03-hibernate-jpa-taslak.md": "# Hibernate / JPA Taslak Dokumani\n\n> TKGM TAKBIS — golge (`tr.com.test.golge.*`) veri katmani standartlari\n> Hedef kitle: backend gelistirici, kod review yapan, kod revizyonu yapan muhendis\n> Surum dogrulamasi (bu dokuman yazilirken, taraf'in cozdugu gercek bagimlilik zinciri): `golge-data-orm-entity` **1.8.1**, `golge-data-orm-jpa` **1.8.1**, `golge-data-orm-mapper` **1.8.1**, `golge-data-orm-liquibase` **1.3.1**, Java **21**, Spring Boot 3.x (Jakarta EE), Hibernate + Envers, QueryDSL, PostgreSQL/PostGIS.\n> Bu surumler `taraf-api/build.gradle` -> `takbis-provider-parent:1.3.8` -> `ekosistem-parent:1.6.1` -> `golge-parent:1.8.1` BOM zinciri ile pinlenir (`golge-parent:1.8.1` POM'unda `golge-data-orm-entity/jpa/mapper/web-starter`=`1.8.1`, `golge-data-orm-liquibase`=`1.3.1`). taraf build dosyalarinda surum override'i yoktur. Cache'de `1.9.0`/`1.4.0` jar'lari bulunsa da taraf bunlari cozmez. API imzalari 1.8.1'de aynidir (`int version`, `boolean active`, `LocalDateTime` audit alanlari javap ile dogrulandi); teknik iddialar gecerli kalir.\n> Referans servis: `taraf` (`taraf-api/server`). Sema yonetimi: merkezi `takbis-metadata` reposu (Liquibase).\n\n---\n\n## 1. Amac & Kapsam\n\nBu dokuman TAKBIS mikroservislerinde **Hibernate / JPA veri katmaninin** nasil yazilacagina dair STANDART ve taslagi tanimlar. Kod review ve kod revizyonu sirasinda referans olarak kullanilir. Her standart icin:\n\n- **(a) NEDEN onemli** — hangi hatayi/maliyeti onler,\n- **(b) review'da NASIL TESPIT edilir** — neye bakilir, hangi grep/sinyal,\n- **(c) NASIL DUZELTILIR** — mumkun oldugunda before/after kod.\n\nKapsam: entity mapping, iliskiler & fetch (N+1), sorgulama (Spring Data turetilmis metot + QueryDSL golge generator + native + DTO projeksiyon), transaction & oturum yonetimi, Envers audit, Liquibase migration, MapStruct mapper, optimistic/pessimistic locking, batch islem, PostGIS/geometri ve `equals/hashCode` tuzaklari.\n\nKapsam disi: REST controller / Feign kontrati (bkz. ayri controller dokumani), guvenlik anotasyonlari, Elasticsearch arama datasource detayi (sadece JPA tarafi anlatilir).\n\n---\n\n## 2. Arka plan / Mimari ozet\n\n### 2.1 golge entity hiyerarsisi (jar: golge-data-orm-entity 1.8.1, javap ile dogrulandi) — Yasak: /@Id\\b/\n\n```\nGolgeBaseEntity<ID>                       // id + isNew sozlesmesi (Persistable)\n  └─ GolgeGenericEntity<ID>               // int version; Boolean active;   (UUID/herhangi ID icin)\n       ├─ GolgeGenericAuditEntity<ID>     // + createdDate/updatedDate (LocalDateTime), createdBy/updatedBy\n       └─ ...\n  └─ GolgeEntity extends GolgeGenericEntity<Long>   // ID = Long sabit\n       └─ GolgeAuditEntity                // Long-ID + audit alanlari\n```\n\n`javap` ciktisindan dogrulanmis kritik gercekler:\n\n- `GolgeGenericEntity<ID>` icinde **`int version`** ve **`Boolean active`** alanlari vardir (mantiksal silme = `active=false`).\n- `GolgeGenericAuditEntity<ID>` audit alanlari **`java.time.LocalDateTime`** tipindedir (`createdDate`, `updatedDate`, `createdBy`, `updatedBy`). `GolgeAuditEntityStructure<LocalDateTime>` implement eder.\n- `GolgeEntity` sabit olarak `GolgeGenericEntity<Long>` genisletir — ID tipi `Long`. UUID id istiyorsan `GolgeGenericEntity`/`GolgeGenericAuditEntity` zincirini kullan.\n- Sabit kolon adlari `GolgeEntityConstraint` icindedir: `ID_FIELD_COLUMN`, `VERSION_FIELD_COLUMN`, `CREATED_DATE_FIELD_COLUMN`, `UPDATED_DATE_FIELD_COLUMN`, `CREATED_BY_FIELD_COLUMN`, `UPDATED_BY_FIELD_COLUMN`, `ACTIVE_FIELD_COLUMN`, `ACTIVE_FIELD`, `SEQUENCE_GENERATOR_NAME`.\n\n### 2.2 Uygulama base entity (taraf ornegi — dogrulanmis) — Yasak: /(private|protected)\\s+[A-Za-z<>,\\s]*\\s(createdBy|createdDate|updatedBy|updatedDate|version)\\s*;/\n\n`taraf-api/server/.../entity/base/TarafAuditEntity.java`:\n\n```java\n@NoArgsConstructor\n@SuperBuilder(toBuilder = true)\n@Data\n@EqualsAndHashCode(callSuper = true)\n@Audited\n@AuditOverride(forClass = GolgeGenericAuditEntity.class)\n@MappedSuperclass\n@AttributeOverrides({\n  @AttributeOverride(name = \"active\",      column = @Column(name = \"aktif\",             nullable = false)),\n  @AttributeOverride(name = \"version\",     column = @Column(name = \"versiyon\",          nullable = false)),\n  @AttributeOverride(name = \"createdDate\", column = @Column(name = \"olusturma_tarihi\",  updatable = false, nullable = false)),\n  @AttributeOverride(name = \"updatedDate\", column = @Column(name = \"guncelleme_tarihi\", nullable = false)),\n  @AttributeOverride(name = \"createdBy\",   column = @Column(name = \"olusturan\",         updatable = false, nullable = false)),\n  @AttributeOverride(name = \"updatedBy\",   column = @Column(name = \"guncelleyen\",       nullable = false)),\n})\npublic abstract class TarafAuditEntity extends GolgeGenericAuditEntity<UUID> {\n    @Id\n    @GeneratedValue(strategy = GenerationType.IDENTITY)\n    @Column(name = ID_FIELD_COLUMN, updatable = false, nullable = false)\n    private UUID id;\n\n    @Override\n    public boolean isNew() { return Objects.isNull(getId()); }\n}\n```\n\nKalip: **her servis kendi `<Servis>AuditEntity` base'ini** golge audit entity'sinden tureterek olusturur; golge'nin Ingilizce alan adlarini `@AttributeOverrides` ile Turkce kolon adlarina (`aktif`, `versiyon`, `olusturma_tarihi`...) cevirir. Domain entity'leri (`Taraf`, `GercekKisi`...) bu base'i extend eder.\n\n### 2.3 Repository / service / mapper katmanlari (golge sozlesmesi) — Yasak: /extends\\s+(JpaRepository|CrudRepository|PagingAndSortingRepository)\\s*</\n\n| Katman | golge tipi | taraf ornegi |\n|---|---|---|\n| Repository | `GolgeGenericJpaRepository<E, ID>` | `GercekKisiOperationalRepository extends GolgeGenericJpaRepository<GercekKisi, UUID>` |\n| Operasyon servisi | `GolgeGenericOperationService<ID, DTO>` | `GercekKisiOperationalService` |\n| Arama servisi | `GolgeGenericSearchService` / elle QueryDSL | `GercekKisiSearchService` |\n| Mapper | `GolgeGenericMapstructMapper<ID, DTO, E>` | `GercekKisiMapper` |\n| Dinamik sorgu | `GolgeQueryGeneratorImpl<QD, EPB>` | `GercekKisiQueryGeneratorImpl` |\n\n### 2.4 Sema yonetimi (Liquibase) — merkezi repo — Yasak: /(CREATE|ALTER|DROP)\\s+(TABLE|INDEX|SEQUENCE)\\b/\n\nKRITIK: Liquibase changelog'lari **servis reposunda degil**, ayri **`takbis-metadata`** reposunda tutulur (orn. `takbis-metadata/taraf/`). golge `GolgeLiquibaseProperties` icinde **`git`** alani vardir (`javap` dogruladi) — changelog'lar git'ten cekilerek uygulanir. `taraf-api/server/src/main/resources` altinda Liquibase changelog YOKTUR; sadece `script/dev-seed-kisi.sql` (gelistirme seed) bulunur. Bu, \"sema = tek merkezi kaynak\" prensibini uygular.\n\n---\n\n## 3. Standartlar & Konvansiyonlar — Yasak: /@Table\\s*\\(\\s*name\\s*=\\s*\"/\n\n### 3.1 Entity mapping konvansiyonu — Yasak: /@Column\\s*\\(\\s*name\\s*=\\s*\"/\n\n#### 3.1.1 golge base entity'yi extend et (kendi base'in uzerinden)\n\n**NEDEN:** id, `version` (optimistic lock), `active` (soft delete), audit alanlari (`createdBy/Date`, `updatedBy/Date`) ve Envers entegrasyonu golge tarafindan tek noktadan saglanir. Tekrar tanimlamak tutarsizlik ve audit kaybi yaratir.\n\n**✅ Dogru** (`GercekKisi`, dogrulanmis):\n\n```java\n@Getter @Setter @NoArgsConstructor @AllArgsConstructor\n@SuperBuilder(toBuilder = true)\n@Entity\n@Table(name = TABLE_NAME)                  // TABLE_NAME = \"kisi\", *Constraint'ten\n@DynamicUpdate\n@EqualsAndHashCode(callSuper = true)\n@Inheritance(strategy = InheritanceType.JOINED)\npublic class GercekKisi extends TarafAuditEntity { ... }\n```\n\n**❌ Yanlis:** `@Entity public class GercekKisi { @Id Long id; ... }` — golge base'i extend etmez, audit/version/active alanlari yok, `@Audited` yok.\n\n**Review'da tespit:** Bir `@Entity` sinifi `<Servis>AuditEntity` / golge base'ini extend etmiyorsa flag'le.\n\n#### 3.1.2 Lombok kombinasyonu: `@SuperBuilder` + `@EqualsAndHashCode(callSuper = true)`\n\n**NEDEN:**\n- `@SuperBuilder(toBuilder = true)` — kalitim zincirindeki tum alanlar builder'a dahil olur; `toBuilder()` mevcut nesneden turetip degistirmeye imkan verir. Sade `@Builder` super alanlari atlar -> id/audit set edilmez.\n- `@EqualsAndHashCode(callSuper = true)` — base'teki `id` esitlikten haric tutulmaz; `callSuper=false` (Lombok default) base alanlarini gozardi eder ve **yanlis esitlik** uretir.\n\n**Review'da tespit:** `@SuperBuilder` yokken `@Builder` kullanimi; `@EqualsAndHashCode` uzerinde `callSuper` belirtilmemesi (uyari) veya `callSuper=false`.\n\n**Duzeltme (before/after):**\n\n```java\n// ❌ before\n@Builder\n@EqualsAndHashCode\npublic class GercekKisi extends TarafAuditEntity { ... }\n\n// ✅ after\n@SuperBuilder(toBuilder = true)\n@EqualsAndHashCode(callSuper = true)\npublic class GercekKisi extends TarafAuditEntity { ... }\n```\n\n#### 3.1.3 `@DynamicUpdate`\n\n**NEDEN:** UPDATE deyiminde yalnizca **degisen kolonlar** yer alir. Cok kolonlu entity'lerde gereksiz UPDATE'leri, gereksiz index yazimini ve `@Version` yarismasini azaltir; ozellikle `@OptimisticLock` ve kismi guncellemelerde net fayda saglar.\n\n**Review'da tespit:** Genis entity'lerde `@DynamicUpdate` yoksa oner. (taraf'ta TUM entity'lerde mevcut — standart budur.)\n\n#### 3.1.4 `@Inheritance(strategy = InheritanceType.JOINED)`\n\n**NEDEN:** taraf domaininde `Taraf` ust tablo, `GercekKisi`/`TuzelKisi` alt tablolar gibi normalize bir model kullanilir. JOINED stratejisi her sinifa ayri tablo + FK ile baglar; `SINGLE_TABLE`'in genis null kolon israfini onler, veri butunlugunu korur.\n\n**Dikkat:** JOINED, sorguda JOIN maliyeti getirir. Cok derin hiyerarside performansi olcun. taraf'ta `GercekKisi`/`Taraf` ayni `JOINED` ile isaretlenmis olsa da gercek FK iliskisi `taraf_ref` kolonu uzerinden kuruluyor (asagi bkz. 3.1.6) — kalitim ile yabanci anahtar iliskisini karistirma.\n\n#### 3.1.5 `*Constraint` sinifi: kolon adi / boyut / index sabitleri\n\n**NEDEN:** Kolon adlari ve boyutlar tek bir `final` sabit sinifinda toplanir; entity, mapper, QueryDSL ve gerektiginde native sorgu **ayni sabiti** kullanir. \"Magic string\" kolon adlarini ve entity ile DB arasinda boyut tutarsizligini onler.\n\n**✅ Dogru** (`GercekKisiConstraint`, dogrulanmis):\n\n```java\n@NoArgsConstructor(access = AccessLevel.PRIVATE)\npublic final class GercekKisiConstraint {\n    public static final String TABLE_NAME = \"kisi\";\n    public static final String ADI_COLUMN = \"adi\";\n    public static final String SOYADI_COLUMN = \"soyadi\";\n    ...\n    public static final int ADI_MAX_SIZE = 60;\n    public static final int SOYADI_MAX_SIZE = 60;\n    public static final int VERGI_NO_MAX_SIZE = 10;\n}\n```\n\nEntity'de:\n\n```java\n@Size(max = ADI_MAX_SIZE, message = \"{adi.maxSize}\")\n@NotNull(message = \"{adi.is.empty}\")\n@Column(name = GercekKisiConstraint.ADI_COLUMN)\nprivate String adi;\n```\n\n**❌ Yanlis:** `@Column(name = \"adi\")` ve `@Size(max = 60)` — dogrudan literal; DDL ile senkron kalmasi garanti degil.\n\n**Review'da tespit:** Entity icinde `@Column(name = \"...\")` literal string; `@Size(max = <sayi>)` literal sayi. `*Constraint` sinifi yoksa veya kullanilmiyorsa flag'le.\n\n> Not (gercek kod kokusu — `GercekKisiConstraint`): dosyada kullanilmayan `import org.bouncycastle...NHSecretKeyProcessor` var. Review'da gereksiz/yanlis import temizlenmeli.\n\n#### 3.1.6 i18n validation mesajlari\n\n**NEDEN:** Hata mesajlari koda gomulmez; `{anahtar}` ile mesaj kaynagindan (`messages/validation-messages*.properties`) cozulur. Coklu dil (tr/en) ve tutarli mesaj yonetimi saglar.\n\n**✅ Dogru:** `@NotNull(message = \"{adi.is.empty}\")`, `@Size(max = ADI_MAX_SIZE, message = \"{adi.maxSize}\")`.\nMesaj dosyalari: `taraf-api/server/src/main/resources/messages/validation-messages_tr.properties` (+ `_en`, default). Hata mesajlari icin ayri `error-messages*.properties`.\n\n**❌ Yanlis:** `@NotNull(message = \"Adi bos olamaz\")` — sabit Turkce metin, i18n disi.\n\n**Review'da tespit:** `message = \"...\"` icinde `{...}` yerine duz metin.\n\n#### 3.1.7 ID uretimi ve tip tutarliligi (gercek TODO'lar)\n\ntaraf kodunda zaten isaretlenmis iki konu standart olarak benimsenmelidir:\n\n- **ID stratejisi:** `@GeneratedValue(strategy = GenerationType.IDENTITY)` UUID ile kullaniliyor; DDL'de `id uuid default gen_random_uuid()` ile DB tarafi uretiyor. UUID icin `GenerationType.UUID` veya uygulama tarafi uretimi degerlendir (batch insert ve \"her insertte ekstra select\" maliyeti acisindan). taraf base entity'de bu zaten `TODO [ONERI-PERFORMANS]` olarak not edilmis.\n- **Tarih tipi tutarliligi:** `GercekKisi.dogumTarihi/olumTarihi` legacy `java.util.Date`, `Taraf.gecerlilikBaslangic` ise `java.time.Instant`. Standart: yeni kodda **`java.time`** (`LocalDate`/`LocalDateTime`/`Instant`). Audit alanlari golge'de `LocalDateTime`'dir. taraf'ta `TODO [ONERI-TUTARLILIK]` ile not edilmis.\n- **Isimlendirme tutarliligi:** Ayni kavram (Taraf'a referans) `GercekKisi`'de `tarafId`, `TuzelKisi`'de `tarafRef` adlandirilmis. Tek isim (`tarafRef`) standardi benimsenmeli (gercek TODO).\n\n**Review'da tespit:** Yeni entity'de `java.util.Date`; ayni kavrama farkli alan adi.\n\n---\n\n### 3.2 Iliskiler & fetch (N+1) — Yasak: /@(ManyToOne|OneToOne)(?![^\\n]*LAZY)/\n\n#### 3.2.1 Iki yaklasim: skaler FK kolonu vs. JPA iliski anotasyonu\n\ntaraf domaini iliskiyi cogunlukla **skaler UUID kolon** ile tutar (JPA iliski nesnesi yerine):\n\n```java\n// GercekKisi\n@Column(name = GercekKisiConstraint.TARAF_REF_COLUMN)\nprivate UUID tarafId;\n```\n\nDDL tarafinda gercek FK kisiti vardir (`takbis-metadata/taraf/.../taraf_..._foreign_key_ddl.sql`):\n\n```sql\nalter table taraf.kisi add constraint fk_kisi_taraf\n  foreign key(taraf_ref) references taraf.taraf(id)\n  on update restrict on delete restrict;\n```\n\n**NEDEN bu kalip:** Mikroservis sinirlarinda ve QueryDSL/DTO projeksiyon agirlikli kodda skaler ref, lazy proxy ve yanlislikla yuklenen graf riskini ortadan kaldirir; join'i sorguda **acikca** kurarsin (bkz. 3.3.3). Maliyeti: JPA cascade/navigasyon kolayligindan vazgecilir.\n\n`@ManyToOne`/`@OneToMany` iliskileri ise `basvuru` gibi servislerde yogun kullanilir (dogrulanmis ornekler).\n\n#### 3.2.2 LAZY varsayilan — `@ManyToOne`/`@OneToOne`'da acikca LAZY yaz\n\n**NEDEN:** JPA varsayilani `@ManyToOne` ve `@OneToOne` icin **EAGER**'dir. EAGER, her sorguda gereksiz JOIN/SELECT ureterek N+1 ve buyuk graf yuklemesine yol acar.\n\n**✅ Dogru** (`basvuru` — `IslemTanim`, dogrulanmis):\n\n```java\n@ManyToOne(fetch = FetchType.LAZY)\n@JoinColumn(name = \"kategori_id\")\nprivate Kategori kategori;\n\n@OneToMany(mappedBy = \"islemTanim\", cascade = CascadeType.ALL, fetch = FetchType.LAZY)\n@Builder.Default\nprivate Set<IslemBelge> belgeler = new LinkedHashSet<>();   // koleksiyonlar Set olarak tutulur\n```\n\n**❌ Yanlis:** `@ManyToOne` (fetch belirtmeden) -> EAGER.\n\n**Review'da tespit:** `@ManyToOne`/`@OneToOne` satirinda `fetch = FetchType.LAZY` yoksa flag'le.\ngrep: `grep -rn \"@ManyToOne\\|@OneToOne\" <servis>/.../entity | grep -v LAZY`\n\n#### 3.2.3 N+1 tespiti ve cozumu — `JOIN FETCH` / `@EntityGraph`\n\n**NEDEN:** Lazy koleksiyon listede dolasilirsa her eleman icin ek SELECT (N+1) cikar. Cozum: tek sorguda iliskiyi getirmek.\n\n**Cozum A — `@EntityGraph`** (`islem-yonetimi` — dogrulanmis):\n\n```java\n@EntityGraph(attributePaths = {\"secenekList\"})\nList<IslemOzellikTanim> findAllByActiveIsTrue();\n```\n\n**Cozum B — `JOIN FETCH`** (`basvuru` — dogrulanmis):\n\n```java\n@Query(\"SELECT t FROM IslemTanim t \" +\n       \"LEFT JOIN FETCH t.kural \" +\n       \"LEFT JOIN FETCH t.kategori k \" +\n       \"LEFT JOIN FETCH k.ustKategori \" +\n       \"WHERE t.aktif = true ORDER BY t.domain, t.sira\")\nList<IslemTanim> findAllWithDetay();\n```\n\n**Review'da tespit:** Servis metodu lazy koleksiyon/iliski uzerinde donguyle dolasiyor ve repository tarafinda `@EntityGraph`/`JOIN FETCH` yok; loglarda ayni SELECT'in tekrari.\n\n**Uyari:** Tek sorguda **birden fazla koleksiyonu** `JOIN FETCH` etmek kartezyen carpima (`MultipleBagFetchException`) yol acar. Bu durumda `@EntityGraph` ile birden cok koleksiyonu cekme yerine ayri sorgu / `Set` kullan veya `@BatchSize` degerlendir. `JOIN FETCH` + `Pageable` birlikte kullanildiginda Hibernate sayfalamayi bellekte yapar (uyari verir) — sayfalama gereken yerde DTO projeksiyon tercih et.\n\n#### 3.2.4 Cascade — dikkatli kullan\n\n**NEDEN:** `CascadeType.ALL` + `orphanRemoval = true` parent silindiginde/koleksiyondan cikarildiginda cocuklari da siler. Yanlis kapsamda DELETE patlamasi veya istenmeyen veri kaybi olur. Yalnizca gercek \"owning + lifecycle\" iliskisinde kullan (`IslemTanim` -> alt belge/validasyon listeleri gibi).\n\n**Review'da tespit:** `@ManyToOne` tarafinda `cascade = CascadeType.ALL` (genelde yanlis — many tarafi lifecycle sahibi degildir); paylasilan referansta `orphanRemoval = true`.\n\n---\n\n### 3.3 Sorgulama — Yasak: /(SELECT|select)\\s+\\*\\s+(FROM|from)\\s/\n\ngolge repository (`GolgeGenericJpaRepository<E, ID>`) `GolgeGenericJpaSearchRepository`'yi genisletir ve `javap` ile dogrulanan **QueryDSL `Predicate` imzalarini** sunar: `findAll(Predicate)`, `findAll(Predicate, Pageable)`, `findOne(Predicate)`, `count(Predicate)`, `exists(Predicate)`, ayrica `getReferenceById`, `getById`, `findById`, `findAllById`, `findBy(...FluentQuery...)`. Yazma tarafi (`GolgeGenericJpaRepository`): `save/saveAndFlush/saveAll/saveAllAndFlush`, `update/updateAndFlush/updateAll/updateAllAndFlush`, `deleteById/delete/deleteAll/deleteAllInBatch/deleteAllByIdInBatch`, `flush`.\n\n#### 3.3.1 Spring Data turetilmis metot (derived query)\n\n**NEDEN:** Basit, statik kriterler icin en az kod. Metot adindan sorgu uretilir.\n\n**✅ Dogru:**\n\n```java\npublic interface GercekKisiOperationalRepository extends GolgeGenericJpaRepository<GercekKisi, UUID> {\n    Optional<GercekKisi> findByTcKimlikNoAndActiveTrue(Long tcKimlikNo);\n    boolean existsByVergiNoAndActiveTrue(String vergiNo);\n}\n```\n\n**Review'da tespit:** Asiri uzun, okunamaz metot adi (`findByAAndBAndCOrderByD...`) -> `@Query` veya QueryDSL'e tasimayi oner. `active` filtresi unutulmussa (soft delete) flag'le.\n\n#### 3.3.2 QueryDSL — golge generator ile dinamik arama (TERCIH EDILEN kalip)\n\ngolge `GolgeQueryGeneratorImpl<QD extends GolgeQueryDto, EPB extends EntityPathBase>` (`javap` dogruladi) `preparePredicate(BooleanBuilder, QD, EPB)` soyut metodunu sunar; `generate(...)` icinde `BooleanBuilder` -> `Predicate` uretir ve golge filtre DTO'larini (string/boolean/datetime) otomatik isler.\n\n**NEDEN:** Frontend'ten gelen dinamik kriter DTO'su ile tip-guvenli (Q-sinifi) predicate kurmak; null/bos kriterleri sessizce atlamak.\n\n**✅ Dogru** (`GercekKisiQueryGeneratorImpl`, dogrulanmis):\n\n```java\n@Component(value = \"gercekKisiQueryGenerator\")\npublic class GercekKisiQueryGeneratorImpl\n        extends GolgeQueryGeneratorImpl<GercekKisiSearchByTanitimNoQueryDto, QGercekKisi> {\n\n    @Override\n    protected void preparePredicate(BooleanBuilder builder,\n                                    GercekKisiSearchByTanitimNoQueryDto dto,\n                                    QGercekKisi gercekKisi) {\n        if (\"TCKN\".equals(dto.getTanitimNoTipi()) || \"YKN\".equals(dto.getTanitimNoTipi())) {\n            builder.and(gercekKisi.tcKimlikNo.eq(Long.valueOf(dto.getTanitimNo())));\n        } else if (\"VN\".equals(dto.getTanitimNoTipi())) {\n            builder.and(gercekKisi.vergiNo.eq(dto.getTanitimNo()));\n        }\n        builder.and(gercekKisi.active.isTrue());   // soft-delete filtresi her zaman\n    }\n}\n```\n\nQ-siniflari (`QGercekKisi`, `QKisiEngel`) golge gradle plugin (`golgeHibernate { querydsl { enabled = true } }`, `server/build.gradle` dogrulandi) tarafindan derleme aninda uretilir — elle yazilmaz, `build/generated` altinda olusur.\n\n**Review'da tespit / kokular:**\n- `preparePredicate`'te `active.isTrue()` filtresi eksik (pasif kayitlar donuyor).\n- \"magic string\" tip kodlari (`\"TCKN\"`, `\"VN\"`) — gercek TODO'da isaretlenmis; enum'a tasinmali.\n- `Long.valueOf(...)` `NumberFormatException` kontrolsuz — gecersiz girdi 500 doner.\n\n#### 3.3.3 Elle QueryDSL + DTO projeksiyon (`Projections.constructor`)\n\n**NEDEN:** Entity'yi tamamen yuklemeden, yalnizca gereken kolonlari DTO'ya cekmek — bellek ve N+1 acisindan en verimli okuma. Sayfalama gereken raporlarda tercih edilir.\n\n**✅ Dogru** (`KisiEngelSearchServiceImpl`, dogrulanmis):\n\n```java\n@Service\n@Transactional(transactionManager = \"searchTransactionManager\", readOnly = true)\npublic class KisiEngelSearchServiceImpl implements KisiEngelSearchService {\n    @PersistenceContext private EntityManager entityManager;\n\n    @Override\n    public List<KisiEngelDto> getKisiEngel(UUID kisiRef) {\n        QKisiEngel kisiEngel = QKisiEngel.kisiEngel;\n        QGercekKisi gercekKisi = QGercekKisi.gercekKisi;\n        JPAQueryFactory queryFactory = new JPAQueryFactory(entityManager);\n        BooleanBuilder builder = new BooleanBuilder();\n        builder.and(gercekKisi.id.eq(kisiRef));\n        builder.and(kisiEngel.active.eq(Boolean.TRUE));\n\n        return queryFactory.select(Projections.constructor(KisiEngelDto.class,\n                        kisiEngel.id, kisiEngel.engelTip, kisiEngel.aciklama, kisiEngel.durum))\n                .from(kisiEngel)\n                .join(gercekKisi).on(gercekKisi.id.eq(kisiEngel.kisiRef))  // skaler ref uzerinden JOIN\n                .where(builder.getValue())\n                .fetch();\n    }\n}\n```\n\nDikkat: skaler `kisiRef` kolonu uzerinden `join(...).on(...)` ile iliski sorguda kurulur (JPA iliski nesnesi olmadan). Bu, taraf'in skaler-ref kalibiyla tutarli.\n\n**Review'da tespit:** `Projections.constructor(...)` parametre sirasi DTO constructor'i ile birebir eslesmek zorundadir; sira/tip kaymasi sessiz yanlis veri uretir. DTO'da `@AllArgsConstructor` ve alan sirasi degisirse projeksiyon kirilir — birlikte gozden gecir.\n\n#### 3.3.4 Native sorgu\n\ngolge `GolgeJpaNativeRepository` (dahili) `GolgeNativeQueryPredicate` ile native sorgu sunar (`get/find/findAll/findAll+Pageable`). Native sorgu yalnizca QueryDSL/JPQL ile ifade edilemeyen (DB-ozel fonksiyon, PostGIS operatoru, karmasik analitik) durumlarda kullanilir.\n\n**Review'da tespit:** Saf CRUD/filtre icin native SQL kullanimi (gereksiz) — turetilmis metot veya QueryDSL'e tasin. Native string icinde elle string birlestirme (SQL injection riski) -> parametre bind kullan.\n\n---\n\n### 3.4 Transaction & oturum — Yasak: /\\.set(CreatedBy|CreatedDate|UpdatedBy|UpdatedDate)\\s*\\(/\n\n#### 3.4.1 Okuma servislerinde `readOnly = true` + dogru `transactionManager`\n\n**NEDEN:** Coklu datasource var (ana + **search** datasource — golge `SearchJpaRepositoriesConfiguration`). Okuma servisleri `readOnly=true` ile dirty-checking ve gereksiz flush'i kapatir (performans), ve dogru `transactionManager`'a baglanmazsa yanlis baglanti/transaction'a duser.\n\n**✅ Dogru** (dogrulanmis): `@Transactional(transactionManager = \"searchTransactionManager\", readOnly = true)` arama servis impl'lerinde sinif duzeyinde.\n\n**Review'da tespit:** Arama servisinde `@Transactional` yok veya `readOnly` belirtilmemis; coklu datasource ortaminda `transactionManager` adi belirtilmemis.\n\n#### 3.4.2 Yazma servislerinde transaction siniri\n\n**NEDEN:** Yazma islemleri tek atomik transaction icinde olmali; `@Transactional` servis (impl) katmaninda olmali, repository veya controller'da degil. Birden cok repository cagrisi ayni transaction'da commit/rollback olmali.\n\n**Review'da tespit:** Composite yazma (`addGercekKisi(GercekKisiCompositeDto)` gibi cok-entity'li akis) `@Transactional` ile sarilmamissa -> kismi yazma/tutarsizlik riski.\n\n#### 3.4.3 `LazyInitializationException` ve `flush`/`clear`\n\n**NEDEN:** Transaction kapandiktan sonra lazy alana erismek `LazyInitializationException` firlatir. Servis cikis noktasinda entity'yi degil **DTO** don (mapper ile) -> oturum kapaninca proxy erisimi olmaz.\n\n**Review'da tespit:** Servis metodu **entity** donuyor (DTO yerine) ve cagiran tarafta lazy alan kullaniliyor. Cozum: transaction icinde mapper ile DTO'ya cevir.\n\n`flush()`/`saveAndFlush()`/`updateAndFlush()`: golge repository'de mevcuttur; ID'ye/DB tetikleyicisine hemen ihtiyac varsa veya buyuk batch'te bellek baski yonetimi icin kullanilir (bkz. 3.8). Gereksiz `saveAndFlush` her cagrida senkron flush -> performans kaybi; sadece gerektiginde kullan.\n\n#### 3.4.4 prePersist / auditor\n\ngolge `GolgeGenericEntityListener.prePersist(...)` ve `GolgeJpaAuditorAwareImpl` (jar'da mevcut) `createdBy/createdDate` vb. otomatik doldurur. **Elle** `setCreatedBy/setCreatedDate` cagirma — auditor mekanizmasini ezersin.\n\n**Review'da tespit:** Servis kodunda elle `setCreatedDate(now())` / `setCreatedBy(...)`.\n\n---\n\n### 3.5 Audit (Envers) — Yasak: /\"[A-Za-z_]+_aud\"/\n\n**NEDEN:** Tapu domaininde \"kim ne zaman degistirdi\" yasal zorunluluktur. Envers degisiklik tarihcesini ayri `_aud` tablolarinda tutar.\n\n**Kurulum (taraf base — dogrulanmis):**\n\n```java\n@Audited\n@AuditOverride(forClass = GolgeGenericAuditEntity.class)\n@MappedSuperclass\npublic abstract class TarafAuditEntity extends GolgeGenericAuditEntity<UUID> { ... }\n```\n\n- `@Audited` -> entity tarihce tablosuna (`<tablo>_aud`) yazilir.\n- `@AuditOverride(forClass = GolgeGenericAuditEntity.class)` -> base'teki audit alanlarinin denetim davranisini ayarlar.\n\n**Denetim sorgusu:** golge `GolgeGenericJpaEnversAuditRepository<E, ID>` Spring Data `RevisionRepository<E, ID, Long>`'i genisletir (`javap` dogruladi). Tarihce sorgusu icin repository bu arayuzu de extend etmelidir:\n\n```java\npublic interface GercekKisiAuditRepository\n        extends GolgeGenericJpaRepository<GercekKisi, UUID>,\n                GolgeGenericJpaEnversAuditRepository<GercekKisi, UUID> {\n}\n// kullanim: findRevisions(id), findLastChangeRevision(id) -> Revision<Long, GercekKisi>\n```\n\n**Review'da tespit:** Yasal/denetlenmesi gereken entity'de `@Audited` yok; `@Audited` olmayan iliskili alan denetlenen entity'de `@NotAudited` ile isaretlenmeden birakilmis (Envers mapping hatasi); elle audit kolonu yazma.\n\n---\n\n### 3.6 Migration (Liquibase) — Yasak: /(hbm2ddl|ddl-auto|ddl_auto)/\n\n#### 3.6.1 Merkezi konum ve dosya/changeset hiyerarsisi\n\n**NEDEN:** Sema tek otorite reposunda (`takbis-metadata`) versiyonlanir; servisler bunu git uzerinden (golge `GolgeLiquibaseProperties.git`) uygular. Boylece sema, kod tarafindan `ddl-auto` ile DEGIL, controlu changeset'lerle degisir.\n\n**Gercek hiyerarsi (`takbis-metadata/taraf/`, dogrulanmis):**\n\n```\nchangelog-latest.xml          -> include changelog-v_1_0_1.xml\nchangelog-v_1_0_1.xml         -> include changelog-v_1_0_0.xml ; includeAll ./v_1_0_1\nchangelog-v_1_0_0.xml         -> includeAll ./v_1_0_0\nv_1_0_0/\n  taraf_101_init.sql                       (schema + rol + grant)\n  taraf_1775835418_table_ddl.sql           (create table)\n  taraf_1775835419_table_comment.sql\n  taraf_1775835420_column_comment.sql\n  taraf_1775835421_table_constraint_ddl.sql (PK + CHECK)\n  taraf_1775835422_table_index_ddl.sql      (index)\n  taraf_1775835423_table_foreign_key_ddl.sql (FK)\nv_1_0_1/\n  taraf_1776062937.sql                     (ALTER: drop not null, type change)\n```\n\nKalip: surum bazli `changelog-v_x_y_z.xml` zincirleme `include` eder; her surum klasoru `includeAll` ile alinir. **Calistirma sirasi onemli** -> DDL once tablo, sonra comment, sonra constraint, sonra index, en son FK. Yeni degisiklik **yeni dosyaya** (yeni surum klasoru) eklenir; eski changeset DUZENLENMEZ.\n\n#### 3.6.2 `formatted sql` changeset konvansiyonu\n\n**✅ Dogru** (dogrulanmis):\n\n```sql\n-- liquibase formatted sql\n\n--changeset ttiryaki:1775835418-1\ncreate table taraf.taraf ( id uuid default gen_random_uuid() not null, ... );\n\n--changeset aacehan:1776062937-1\nALTER TABLE taraf.kisi ALTER COLUMN tc_kimlik_no DROP NOT NULL;\n```\n\nKurallar:\n- Dosya basinda `-- liquibase formatted sql`.\n- Her changeset `--changeset <yazar>:<id>` ile baslar; **id benzersiz ve sirali** (epoch/numerik + `-n` alt sira). `<yazar>` = gercek kullanici (orn. `ttiryaki`, `aacehan`).\n- Coklu deyim icermesi gereken PL/pgSQL bloklarinda `splitStatements:false` (orn. `taraf_101_init.sql` `do $$ ... $$`).\n- Sema her zaman acikca nitelenir: `taraf.kisi` (search_path'e guvenme).\n\n#### 3.6.3 Rollback ve \"semaya elle mudahale karsiti\"\n\n**NEDEN:** Liquibase ileri-yonlu uygulanir; geri alinabilirlik icin riskli/yikici changeset'lere `rollback` blogu eklenmeli. **DB'ye elle DDL atmak** Liquibase `DATABASECHANGELOG` ile kod arasinda kalici tutarsizlik (drift) yaratir — yasaktir.\n\n**Review'da tespit:**\n- Var olan changeset'in **icerigi degistirilmis** (Liquibase checksum hatasi verir; uretimi bozar) -> her degisiklik YENI changeset.\n- `DROP`/`ALTER ... DROP NOT NULL` gibi yikici degisiklikte `rollback` yok.\n- PR'da DDL ama `takbis-metadata` changeset'i yok (elle DB mudahalesi sinyali).\n- `spring.jpa.hibernate.ddl-auto` `validate`/`none` disinda (orn. `update`) — **yasak**; sema yalnizca Liquibase ile degisir.\n\n---\n\n### 3.7 Mapper (MapStruct) — Yasak: /@Mapper\\b(?!\\s*\\([^)]*nullValuePropertyMappingStrategy)/\n\n**NEDEN:** Entity <-> DTO donusumu elle yazilirsa hata/eksik alan riski yuksek. MapStruct derleme aninda tip-guvenli mapper uretir. golge `GolgeGenericMapstructMapper<ID, DTO, E>` standart metotlari sunar (`javap` dogruladi): `convertEntityToDto`, `convertDtoToEntity`, `mapToEntity(DTO, E)`, liste/set donusumleri, `convertDtoIdToEntityId`.\n\n**✅ Dogru** (`GercekKisiMapper`, dogrulanmis):\n\n```java\n@Mapper(nullValuePropertyMappingStrategy = NullValuePropertyMappingStrategy.IGNORE)\npublic interface GercekKisiMapper\n        extends GolgeGenericMapstructMapper<UUID, GercekKisiDto, GercekKisi> {\n}\n```\n\n**Null stratejisi — `NullValuePropertyMappingStrategy.IGNORE`:**\n- **NEDEN:** Kismi guncellemede (`mapToEntity(dto, entity)`) DTO'da `null` gelen alanlar **mevcut entity degerini SILMEZ**; sadece dolu alanlar guncellenir. `@DynamicUpdate` ile birlikte gercek \"patch\" davranisi verir. IGNORE olmadan null alanlar entity'yi null'a ezer (veri kaybi).\n\n**Review'da tespit:**\n- `@Mapper(...)` uzerinde `nullValuePropertyMappingStrategy = IGNORE` yokken `mapToEntity` ile guncelleme yapiliyor (null ezme riski).\n- golge generic mapper yerine elle `new Dto(...)` donusumu (bakim maliyeti, eksik alan).\n- Composite donusumlerde ayri `*CompositeMapper` (taraf'ta `GercekKisiCompositeMapper` var) — coklu entity'li DTO'lar bunlarla ele alinir.\n\n---\n\n### 3.8 Locking — Yasak: /PESSIMISTIC_(WRITE|READ|FORCE_INCREMENT)/\n\n#### 3.8.1 Optimistic lock (`@Version`) — VARSAYILAN\n\n**NEDEN:** golge base entity'de **`int version`** alani vardir (`GolgeGenericEntity`, taraf'ta `versiyon` kolonu). Hibernate her UPDATE'te `version`'i kontrol/artirir; eszamanli iki guncelleme yarisirsa ikincisi `OptimisticLockException` / `ObjectOptimisticLockingFailureException` alir. Veri kaybini (lost update) sessizce engeller.\n\n**Tespit ve ele alinis (`islem-yonetimi` — dogrulanmis):**\n\n```java\n@ExceptionHandler({ ObjectOptimisticLockingFailureException.class, OptimisticLockException.class })\npublic ResponseEntity<GolgeErrorDetail> handleOptimisticLock(Exception ex) { ... }\n```\n\n`fen-kayit` icinde de iliskili kontrolde `ObjectOptimisticLockingFailureException` aciklayici mesajla firlatiliyor.\n\n**Review'da tespit:** `version` kolonu/`AttributeOverride`'i kaldirilmis veya `nullable=true`; eszamanli guncellenen kaynakta optimistic lock istisnasinin **kullaniciya anlamli** ceviriliyor olmasi (yoksa ham 500). DTO'da `version` tasinmiyorsa client gonderdigi versiyon eski olur -> her zaman catisma; DTO version round-trip'ini kontrol et.\n\n#### 3.8.2 Pessimistic lock — yalnizca gercek kritik bolgede\n\n**NEDEN:** `@Lock(LockModeType.PESSIMISTIC_WRITE)` satiri DB satir kilidi alir; yuksek catisma/finansal tutarlilik gereken dar bolge icin uygundur. Genis kapsamda kullanmak deadlock ve throughput dususu yaratir. Varsayilan optimistic'tir; pessimistic istisnadir ve gerekce ister.\n\n**Review'da tespit:** Genis okuma/yazma metodunda gereksiz `PESSIMISTIC_WRITE`; lock + uzun transaction kombinasyonu.\n\n---\n\n### 3.9 Batch insert / update — Yasak: /(for\\s*\\([^)]*\\)|forEach\\s*\\()[^\\n]*(\\.save\\s*\\(|::save\\b)/\n\n**NEDEN:** Cok kayitli yazmada tek tek `save` N adet round-trip uretir. golge repository **toplu** metotlar sunar (`javap` dogruladi): `saveAll`, `saveAllAndFlush`, `updateAll`, `updateAllAndFlush`, `deleteAllInBatch`, `deleteAllByIdInBatch`.\n\n**Standart:**\n- Toplu yazmada `saveAll(list)` kullan; ara flush gerekiyorsa `saveAllAndFlush`.\n- Toplu silmede `deleteAllInBatch` / `deleteAllByIdInBatch` (tek DELETE) tercih et; `deleteAll(list)` her kayit icin SELECT+DELETE uretebilir.\n- Hibernate JDBC batch icin `hibernate.jdbc.batch_size` ve sirali insert/update (`order_inserts`, `order_updates`) ayarlari aktif olmali. **ID stratejisi `IDENTITY` ise JDBC batch insert DEVRE DISI kalir** (Hibernate her insert sonrasi generated key'i okumak zorunda) — bu yuzden buyuk batch insert'lerde `SEQUENCE`/`UUID` uretimi tercih edilir (taraf base'indeki `TODO [ONERI-PERFORMANS]` tam da bunu isaret eder).\n- Cok buyuk dongulerde periyodik `flush()` + `clear()` (golge base impl `EntityManager` tasir) ile birinci seviye cache sismesini onle.\n\n**Review'da tespit:** Dongude tek tek `repository.save(...)`; `IDENTITY` id ile buyuk batch insert beklentisi; `deleteAll(collection)` ile buyuk silme.\n\n---\n\n### 3.10 PostGIS / geometri — Yasak: /private\\s+String\\s+[a-zA-Z]*[Gg]eom/\n\n**NEDEN:** Kadastro verisi geometriktir. golge/Hibernate Spatial + PostGIS ile `org.locationtech.jts.geom.Geometry` JPA alani DB `geometry` kolonuna eslenir.\n\n**✅ Gercek ornek** (`fen-kayit` — `KadastralAlan`, dogrulanmis):\n\n```java\nimport org.locationtech.jts.geom.Geometry;\n\n@Column(name = GEOM_COLUMN)\nprivate Geometry geom;\n\n@Column(name = GEOM_SRID_COLUMN)\nprivate Integer geomSrid;\n\n@Column(name = GEOM_TIP_COLUMN)\nprivate String geomTip;\n\npublic void setGeom(Geometry geom) {\n    this.geom = geom;\n    setGeomSrid(geom.getSRID());\n    setGeomTip(geom.getGeometryType());\n}\n```\n\nStandartlar:\n- Geometri tipi **JTS `Geometry`** (vendor-bagimsiz). `geom` + tureyen `srid`/`tip` birlikte tutuluyor.\n- SRID acik yonetilir; karistirilirsa mekansal sorgu/yansitma hatali olur.\n- Mekansal sorgular (`ST_Intersects`, `ST_Within`...) genelde native/`@Query` ile (bkz. fen-kayit geometry operasyonlari).\n\n**Review'da tespit:** Geometri alaninda SRID set edilmiyor; `Geometry` yerine `String`/WKT tutulup elle parse ediliyor; mekansal filtreyi Java tarafinda yapma (DB'de `ST_*` yerine).\n\n---\n\n### 3.11 Entity equals/hashCode tuzagi — Yasak: /@EqualsAndHashCode(?!\\.)(?!\\s*\\([^)]*callSuper)/\n\n**NEDEN:** golge base entity'lerde `equals/hashCode` Lombok ile uretilir. taraf base entity `@Data` + `@EqualsAndHashCode(callSuper = true)` kullanir; bu **`id` dahil tum alanlar** uzerinden esitlik uretir.\n\n**Tuzaklar ve standart:**\n- **Mutable id riski:** `@GeneratedValue` ile id INSERT'ten **sonra** atanir. Entity bir `HashSet`/`Map`'e id atanmadan (null) eklenip sonra kaydedilirse `hashCode` degisir -> koleksiyon bozulur. Standart: yeni (kaydedilmemis) entity'leri hash tabanli koleksiyonlarda tutmaktan kacin; gerekirse `id`-bazli stabil `hashCode` (sabit) kullan.\n- **`@Data` koleksiyonlarda dikkat:** `@Data`/`callSuper=true` butun alanlari (lazy iliski dahil) `equals/hashCode/toString`'e katarsa lazy proxy yuklenmesi veya `LazyInitializationException`/`StackOverflow` (cift yonlu iliski) olusabilir. taraf entity'leri cogunlukla **skaler ref** tuttugu icin bu risk dusuk; ama `@ManyToOne`/`@OneToMany` ekleyen entity'lerde iliski alanlarini `equals/hashCode/toString` disina al (`@EqualsAndHashCode.Exclude`, `@ToString.Exclude`).\n- `callSuper = true` mutlaka belirtilmeli (base `id`/audit alanlari icin) — Lombok aksi halde uyarir ve yanlis esitlik uretir.\n\n**Review'da tespit:**\n- `@EqualsAndHashCode` uzerinde `callSuper` yok / `false`.\n- Cift yonlu `@OneToMany`/`@ManyToOne` entity'de iliski alani `@ToString.Exclude`/`@EqualsAndHashCode.Exclude` ile haric tutulmamis.\n- Kaydedilmemis entity'lerin `Set`/`Map` anahtari olarak kullanilmasi.\n\n---\n\n## 4. Sik Hatalar & Anti-pattern'ler (before/after) — Yasak: /@Builder\\b(?!\\.)/\n\n| # | Anti-pattern | Sonuc | Duzeltme |\n|---|---|---|---|\n| 1 | `@Builder` (super degil) kalitimli entity'de | id/audit builder'a girmez | `@SuperBuilder(toBuilder = true)` |\n| 2 | `@EqualsAndHashCode` (callSuper'siz) | base id esitlikte yok | `@EqualsAndHashCode(callSuper = true)` |\n| 3 | `@ManyToOne` fetch'siz | EAGER, N+1 | `@ManyToOne(fetch = FetchType.LAZY)` |\n| 4 | Lazy koleksiyonu dongude gezme | N+1 | `@EntityGraph` / `JOIN FETCH` |\n| 5 | Servis **entity** donuyor | `LazyInitializationException` | DTO don (MapStruct) |\n| 6 | `@Column(name=\"adi\")` literal | DDL ile drift | `*Constraint` sabiti |\n| 7 | `message = \"duz metin\"` | i18n disi | `message = \"{anahtar}\"` |\n| 8 | `mapToEntity` + IGNORE'suz mapper | null ezme/veri kaybi | `nullValuePropertyMappingStrategy = IGNORE` |\n| 9 | Var olan changeset'i duzenleme | Liquibase checksum hatasi | Yeni changeset / yeni surum klasoru |\n| 10 | Elle DB DDL / `ddl-auto=update` | sema drift | Liquibase changeset (`takbis-metadata`), `ddl-auto=validate` |\n| 11 | `preparePredicate`'te `active` filtresi yok | pasif kayit doner | `builder.and(q.active.isTrue())` |\n| 12 | Optimistic lock istisnasi ham 500 | kotu UX | `@ExceptionHandler(ObjectOptimisticLockingFailureException...)` |\n| 13 | Dongude tek tek `save` (`IDENTITY` id) | batch insert kapali, N round-trip | `saveAll` + SEQUENCE/UUID id, periyodik `flush/clear` |\n| 14 | Cift yonlu iliski `toString`/`equals`'te | StackOverflow / lazy yukleme | `@ToString.Exclude` / `@EqualsAndHashCode.Exclude` |\n| 15 | `Projections.constructor` sira/tip kaymasi | sessiz yanlis veri | DTO ctor sirasi ile birebir esle |\n| 16 | Geometride SRID set edilmiyor | hatali mekansal sorgu | `setGeom`'da SRID/tip turet |\n\n---\n\n## 5. Hizli Referans\n\n**Entity iskeleti (UUID, audit, soft-delete):**\n\n```java\n@Getter @Setter @NoArgsConstructor @AllArgsConstructor\n@SuperBuilder(toBuilder = true)\n@Entity @Table(name = TABLE_NAME)\n@DynamicUpdate\n@EqualsAndHashCode(callSuper = true)\n@Inheritance(strategy = InheritanceType.JOINED)\npublic class Foo extends <Servis>AuditEntity {\n    @Size(max = AD_MAX_SIZE, message = \"{ad.maxSize}\")\n    @NotNull(message = \"{ad.is.empty}\")\n    @Column(name = FooConstraint.AD_COLUMN)\n    private String ad;\n}\n```\n\n**Repository:** `interface FooRepository extends GolgeGenericJpaRepository<Foo, UUID> {}`\n**Mapper:** `@Mapper(nullValuePropertyMappingStrategy = IGNORE) interface FooMapper extends GolgeGenericMapstructMapper<UUID, FooDto, Foo> {}`\n**Dinamik sorgu:** `extends GolgeQueryGeneratorImpl<FooQueryDto, QFoo>` + `preparePredicate(...)` (her zaman `active.isTrue()`).\n**Okuma servisi:** `@Transactional(transactionManager = \"searchTransactionManager\", readOnly = true)`.\n**Audit sorgusu:** repository `... , GolgeGenericJpaEnversAuditRepository<Foo, UUID>` (RevisionRepository).\n**Batch:** `saveAll` / `saveAllAndFlush` / `deleteAllInBatch`; buyuk insert'te id stratejisi `IDENTITY` olmasin.\n**Migration:** `takbis-metadata/<servis>/v_x_y_z/<servis>_<id>.sql`, `-- liquibase formatted sql` + `--changeset <yazar>:<id>`, DDL sirasi: table -> comment -> constraint -> index -> FK. `ddl-auto=validate`.\n\n**Yararli grep'ler (review):**\n\n```bash\n# EAGER iliski riski\ngrep -rn \"@ManyToOne\\|@OneToOne\" <servis>/.../entity | grep -v LAZY\n# literal kolon adi\ngrep -rn '@Column(name *= *\"' <servis>/.../entity\n# i18n disi mesaj\ngrep -rn 'message *= *\"[^{]' <servis>/.../entity\n# ddl-auto kontrol\ngrep -rn \"ddl-auto\" <servis>/.../resources\n# active filtresi olmayan generator\ngrep -rL \"active\" <servis>/.../generator\n```\n\n---\n\n## 6. Ilgili dosyalar & capraz-link\n\n**Incelenen gercek kaynaklar (iddialar bunlara dayanir):**\n\n- Entity & base: `taraf/taraf-api/server/src/main/java/tr/gov/tkgm/takbis/taraf/server/entity/GercekKisi.java`, `.../entity/Taraf.java`, `.../entity/base/TarafAuditEntity.java`, `.../entity/constraint/GercekKisiConstraint.java`\n- Repository: `.../repository/operational/GercekKisiOperationalRepository.java`\n- Mapper: `.../mapper/GercekKisiMapper.java`\n- Servis: `.../service/GercekKisiSearchService.java`, `.../service/GercekKisiOperationalService.java`, `.../service/impl/KisiEngelSearchServiceImpl.java`, `.../service/impl/TarafOperationalServiceImpl.java`\n- QueryDSL: `.../generator/GercekKisiQueryGeneratorImpl.java`; `server/build.gradle` (`golgeHibernate { querydsl { enabled = true } }`, `mapstruct { enabled = true }`)\n- Liquibase (merkezi): `takbis-metadata/taraf/changelog-latest.xml`, `.../changelog-v_1_0_0.xml`, `.../changelog-v_1_0_1.xml`, `.../v_1_0_0/taraf_101_init.sql`, `.../taraf_1775835418_table_ddl.sql`, `.../taraf_1775835421_table_constraint_ddl.sql`, `.../taraf_1775835422_table_index_ddl.sql`, `.../taraf_1775835423_table_foreign_key_ddl.sql`, `.../v_1_0_1/taraf_1776062937.sql`\n- Iliski/N+1 ornekleri: `basvuru/.../admin/entity/IslemTanim.java`, `basvuru/.../admin/repository/IslemTanimRepository.java`, `islem-yonetimi/.../repository/IslemOzellikTanimRepository.java`\n- Locking: `islem-yonetimi/.../controller/IslemBpmnOperationalRestController.java`, `fen-kayit/.../service/impl/IslemFenKayitServiceImpl.java`\n- PostGIS: `fen-kayit/.../entity/KadastralAlan.java`\n- golge jar (taraf'in cozdugu surumler, javap/unzip ile dogrulandi): `golge-data-orm-entity-1.8.1`, `golge-data-orm-jpa-1.8.1`, `golge-data-orm-mapper-1.8.1`, `golge-data-orm-liquibase-1.3.1` (BOM zinciri: `takbis-provider-parent:1.3.8` -> `ekosistem-parent:1.6.1` -> `golge-parent:1.8.1`)\n\n**Dogrulanan kritik sinif/imza:**\n`GolgeGenericEntity` (`int version`, `Boolean active`), `GolgeGenericAuditEntity` (audit alanlari `LocalDateTime`), `GolgeEntityConstraint` (kolon adi sabitleri), `GolgeGenericJpaRepository` / `GolgeGenericJpaSearchRepository` (QueryDSL `Predicate` + batch metotlari), `GolgeQueryGeneratorImpl.preparePredicate`, `GolgeGenericMapstructMapper`, `GolgeGenericJpaEnversAuditRepository extends RevisionRepository`, `GolgeLiquibaseProperties.git`.\n\n**Capraz-link (diger review dokumanlari):**\n- Controller / Feign kontrati dokumani — `*RestClient` implements eden controller, `@PreAuthorize`, DTO sozlesmesi.\n- DTO & mapper dokumani (varsa) — Composite DTO ve `*CompositeMapper`.\n- Guvenlik dokumani — `@GolgeSecureEndpoint`, IY_* rol desenleri.\n",
  "04-golge-framework-backend.md": "# Golge Framework — Backend Code Review Standartlari\n\n> **Alt gorev 4** karsiligi. Kurum ici **golge** (golge = shadow) backend framework'u (`tr.com.test.golge.*` jar'lari) uzerine kurulu TKGM TAKBIS servislerinin code review'u ve revizyonu icin referans dokuman.\n> Frontend (golge-ui + Module Federation) tarafi ayri dokumanda: [04-golge-framework-frontend.md](04-golge-framework-frontend.md) (alt gorev 9).\n> **Kullanim:** Her standart icin (a) **NEDEN** onemli, (b) review'da **NASIL TESPIT** edilir, (c) **NASIL DUZELTILIR**. Iddialar jar icerigine (`javap -p`) ve gercek repo dosyalarina dayandirilmistir.\n\n---\n## 1. Amac & Kapsam\n\nBu dokuman, golge framework'un sundugu **hazir altyapiyi** (base entity/DTO/repository/service/controller hiyerarsisi, exception modeli, context/oturum, guvenlik, Feign auth propagasyonu, frontend bilesen/tema/router kutuphanesi, Module Federation kabugu) tanitir ve bu altyapinin **dogru kullanimini** denetleyen review kriterleri verir.\n\nTemel ilke: **Framework zaten sagliyorsa elle yazma.** golge; CRUD, sayfalama, audit, soft-delete, validation view'lari, exception-to-HTTP donusumu, auth header propagasyonu gibi capraz-kesen islerin tamamini generic siniflarda saglar. Bunlari elle tekrar yazan her PR, review'da geri cevrilmelidir (bkz. Bolum A.8).\n\nDogrulanan kritik surumler (gradle cache, `/home/kerim/.gradle/caches/.../tr.com.test.golge`):\n\n| Modul | Cache'te bulunan surumler | Bu dokumanda incelenen |\n|---|---|---|\n| golge-web-starter | 1.8.1, **1.9.0** | 1.9.0 |\n| golge-data-orm-entity / -jpa / -dto / -mapper / -commons | 1.8.1, **1.9.0** | 1.9.0 |\n| golge-exception | 1.8.1, **1.9.0** | 1.9.0 |\n| golge-context | 1.8.1, **1.9.0** | 1.9.0 (`GolgeSessionAttributeHolder` SADECE 1.9.0'da var) |\n| golge-security | 1.2.1, **1.3.0** | 1.3.0 |\n| golge-security-cloud | 1.0.1, **1.1.0** | 1.1.0 |\n| golge-feign-client | 1.0.1, **1.1.0** | 1.1.0 |\n| golge-ui (frontend) | — | **1.16.10** (`taraf-web/node_modules/golge-ui`) |\n\n> **Surum notu:** golge surumleri `ekosistem-parent` BOM'undan transitif gelir (`taraf/taraf-api/server/build.gradle` golge bagimliliklarinda **explicit surum yoktur**). Kesin surumu DAIMA ilgili repo'nun BOM'undan ve override'larindan dogrulayin (bkz. A.7).\n\n---\n\n## 2. Arka Plan / Mimari Ozet\n\ngolge, `ekosistem-parent` BOM uzerine kurulu, Spring Boot 3.x (Jakarta EE) / Java 21 tabanli bir \"altyapi cercevesi\"dir. Iki katmana ayrilir:\n\n- **Backend jar'lari** (`tr.com.test.golge:*`): her `<ad>-api` projesinin `server` modulu bunlari bagimlilik alir. Calistirilabilir uygulama, golge'nin generic base siniflarini **extends/implements** ederek kendi domain'ini scaffold eder.\n- **Frontend (`golge-ui`)**: React 18 + MUI 6 tabanli paylasilan bilesen/tema/router/e-imza/api kutuphanesi. Mikro-frontend'ler (`dis-portal-mf-shell` = host, `<ad>-web` = remote) bunu **singleton shared** olarak Module Federation uzerinden paylasir.\n\n**KRITIK KONVANSIYON (her iki katmanda da):** server controller, `server` modulunun `controller/` paketinde tanimli `*RestClient` arayuzunu **IMPLEMENTS** eder. Bu `*RestClient` arayuzleri (dogrulandi: `taraf-api/server/.../server/controller/`'da 40+ adet) `@FeignClient` DEGIL — paylasilan **Spring MVC REST kontratlaridir** (`@RequestMapping` + `@JsonView(GolgeView.Base)`). Controller bu kontrati implement ederek REST mapping'lerini ve govdeyi ayirir. Feign cagri tarafi ayri bir kontrat olan `TarafFeignClient`'tir (`@FeignClient`, `taraf-api/client` modulunde). golge'nin generic controller'lari (`GolgeOperationalRestController` vb.) generic-CRUD kontratin hazir kismini saglar.\n\n---\n\n# BOLUM A — BACKEND (golge-* jarlar)\n\n## A.1 Modul Haritasi\n\nHer golge modulunun sorumlulugu. (Surumler cache'teki en guncel; gercek surumu BOM belirler.)\n\n| Modul | Sorumluluk | Review'da onemli ic siniflar |\n|---|---|---|\n| **golge-data-orm-entity** | JPA base entity hiyerarsisi + Envers audit listener'lari + QueryDSL `Q*` uretimi | `GolgeBaseEntity`, `GolgeGenericEntity`, `GolgeEntity`, `GolgeGenericAuditEntity`, `GolgeAuditEntity`, `@GolgeReadOnlyEntity` |\n| **golge-data-orm-dto** | DTO base hiyerarsisi (entity'nin ayna karsiligi) | `GolgeBaseDto<ID>`, `GolgeGenericDto<ID>`, `GolgeDto`, `query.GolgeQueryDto` |\n| **golge-data-orm-mapper** | MapStruct entity<->DTO donusum sozlesmesi | `GolgeGenericMapstructMapper<ID,DTO,E>` |\n| **golge-data-orm-jpa** | Repository base'leri, multi-datasource (search datasource), native sorgu, Envers revizyon repo | `GolgeGenericJpaRepository`, `GolgeJpaRepository`, `GolgeGenericJpaSearchRepository`, `GolgeJpaSearchRepository`, `audit.GolgeGenericJpaEnversAuditRepository` |\n| **golge-data-orm-commons** | Repository markeri, native predicate, `GolgeView` (Base/Command/Persist/Merge/Query JSON view'lari) | `GolgeRepository<E>`, `GolgeNativeQueryPredicate`, `view.GolgeView` |\n| **golge-data-orm-liquibase** | Liquibase entegrasyonu / changelog altyapisi | — |\n| **golge-web-starter** | CRUD service + search service + REST controller generic'leri; tek auto-config ile devreye girer | `GolgeGenericOperationService(Impl)`, `GolgeGenericSearchService(Impl)`, `GolgeGenericOperationalRestController`, `GolgeGenericSearchRestController` + `*Structure` arayuzleri |\n| **golge-exception** | Tipli is hatasi modeli | `GolgeUncheckedException`, `GolgeCheckedException`, `GolgeBusinessRuleException`, `GolgeResourceNotFoundException`, `model.GolgeErrorDetail` |\n| **golge-context** | Uygulama context erisimi, oturum attribute holder, global exception handler | `holder.GolgeApplicationContextHolder`, `holder.GolgeSessionAttributeHolder`, `handler.GolgeContextExceptionHandler`, `aware.GolgeSessionAware` |\n| **golge-security** | Method/endpoint guvenlik anotasyonlari, security context, granted-authority cozumlemesi, RestTemplate auth interceptor | `@GolgeSecureEndpoint`, `@GolgePublicEndpoint`, `context.GolgeSecurityContext`, `interceptor.GolgeSecurityAuthorizationRestClientInterceptor`, `@GolgeConditionalOnSecurityEnabled/Disabled` |\n| **golge-security-cloud** | Bulut/mikroservis tarafi: Feign authority client + Feign auth interceptor | `interceptor.GolgeSecurityFeignClientInterceptor`, `client.GolgeSecurityGrantedAuthorityFeignClient` |\n| **golge-feign-client** | Feign request interceptor altyapisi (auth header propagasyonu base'i) | `interceptor.GolgeFeignClientInterceptor` (abstract), `@GolgeFeignClientMethodExcludeInterceptor` |\n| **golge-keycloak / -integration** | Keycloak OAuth2/JWT entegrasyonu | — |\n| **golge-cache / -redis** | Cache soyutlamasi + Redis (sentinel) implementasyonu | — |\n| **golge-configuration** | Tum auto-config'lerin extends ettigi `GolgeBaseConfiguration` | `GolgeBaseConfiguration` |\n| **golge-swagger** | OpenAPI/Swagger entegrasyonu | — |\n| **golge-util / -git / -test** | Yardimci util, git metadata, test altyapisi (`golge-test`) | — |\n\n---\n\n## A.2 Base Sinif Hiyerarsisi (Entity / DTO) — Yasak: /public\\s+(boolean\\s+equals|int\\s+hashCode)\\s*\\(/\n\ngolge iki paralel hiyerarsi sunar: **entity** (DB tarafi) ve **DTO** (tasima tarafi). Ikisi de ayni `ID` tip parametresini ve ayni alan kumesini (version/active/audit) paylasir.\n\n### Entity hiyerarsisi (`javap -p` ile dogrulanmis)\n\n```\nGolgeBaseEntity<ID extends Serializable>           // @MappedSuperclass; isNew(), equals/hashCode; Persistable<ID>\n  └─ GolgeGenericEntity<ID>                          // + version (int, @Version, kolon OBJ_VERSION) + active (Boolean)\n       ├─ GolgeEntity  (= GolgeGenericEntity<Long>)  // + Long id getter/setter; ID sabit Long\n       └─ GolgeGenericAuditEntity<ID>                // + createdDate/updatedDate/createdBy/updatedBy (@CreatedDate/@CreatedBy ...)\nGolgeAuditEntity (= GolgeEntity + audit alanlari)    // Long id'li audit'li varyant\n```\n\n| Base sinif | ID tipi | version+active | audit alanlari | Ne zaman? |\n|---|---|---|---|---|\n| `GolgeBaseEntity<ID>` | generic | ❌ | ❌ | Cok nadir; sadece optimistic-lock ve active'e ihtiyac yoksa. |\n| `GolgeGenericEntity<ID>` | generic (orn. `UUID`) | ✅ | ❌ | UUID PK'li, audit istenmeyen entity. |\n| `GolgeEntity` | sabit `Long` | ✅ | ❌ | Long PK'li, audit istenmeyen entity. |\n| `GolgeGenericAuditEntity<ID>` | generic (orn. `UUID`) | ✅ | ✅ | **En yaygin** — UUID PK + olusturma/guncelleme izi. (taraf domaini bunu kullanir.) |\n| `GolgeAuditEntity` | sabit `Long` | ✅ | ✅ | Long PK + audit. |\n\n> `GolgeGenericEntity`'de `version` alani `OBJ_VERSION` kolonuna `@Version` ile maplenir (optimistic locking). `active` alani soft-delete icin kullanilir; golge `deleteById(id, softDelete=true)` ile bunu yonetir (bkz. A.3).\n\n### Gercek kullanim — `taraf` domain base'i\n\n`taraf/taraf-api/server/.../entity/base/TarafAuditEntity.java`:\n\n```java\n@NoArgsConstructor @SuperBuilder(toBuilder = true) @Data @EqualsAndHashCode(callSuper = true)\n@Audited @AuditOverride(forClass = GolgeGenericAuditEntity.class)\n@MappedSuperclass\n@AttributeOverrides({                                  // golge kolon adlarini Turkce'ye cevirir\n    @AttributeOverride(name = \"active\",      column = @Column(name = \"aktif\",            nullable = false)),\n    @AttributeOverride(name = \"version\",     column = @Column(name = \"versiyon\",         nullable = false)),\n    @AttributeOverride(name = \"createdDate\", column = @Column(name = \"olusturma_tarihi\", updatable = false, nullable = false)),\n    @AttributeOverride(name = \"updatedDate\", column = @Column(name = \"guncelleme_tarihi\",nullable = false)),\n    @AttributeOverride(name = \"createdBy\",   column = @Column(name = \"olusturan\",        updatable = false, nullable = false)),\n    @AttributeOverride(name = \"updatedBy\",   column = @Column(name = \"guncelleyen\",      nullable = false)),\n})\npublic abstract class TarafAuditEntity extends GolgeGenericAuditEntity<UUID> {\n    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)\n    @Column(name = ID_FIELD_COLUMN, updatable = false, nullable = false)\n    private UUID id;\n    @Override public boolean isNew() { return Objects.isNull(getId()); }\n}\n```\n\nSomut entity (`GercekKisi.java`): `@Entity @Table @DynamicUpdate @Inheritance(JOINED) @SuperBuilder ... extends TarafAuditEntity`.\n\n### DTO hiyerarsisi (entity'nin aynasi)\n\n```\nGolgeBaseDto<ID extends Serializable>            // isNew()\n  └─ GolgeGenericDto<ID>                           // + version (Integer) + active (Boolean)\n       └─ GolgeDto  (= GolgeGenericDto<Long>)      // + Long id\n```\n\n> **Kural:** Entity hangi seviyedeyse DTO da ayni seviyede olmali. `GolgeGenericAuditEntity<UUID>` -> DTO `GolgeGenericDto<UUID>` (orn. `GercekKisiDto extends GolgeGenericDto<UUID>`). Audit alanlari DTO'da audit hiyerarsisi olmadigi icin gerekiyorsa DTO'ya elle eklenir.\n\n**Review kontrolleri (A.2):**\n- ❌ Yeni entity `@MappedSuperclass`'li golge base'ini extend etmeden, ham `@Entity` + elle `id/version/createdDate` alanlari yaziyorsa: golge base'ine cevir.\n- ❌ `equals/hashCode` elle yaziliyorsa: golge base'i + `@EqualsAndHashCode(callSuper = true)` zaten saglar; gereksiz/yanlis (proxy uyumsuzlugu) olabilir.\n- ❌ `version`/`active` alanlari elle entity'ye eklenmis (golge base'inde zaten var): cift mapleme, `TarafEntity.java` icindeki TODO bunu acikca isaretliyor — tek kaynak birak.\n- ❌ Audit alanlarini (`createdBy` vb.) elle `@PrePersist` ile dolduran kod: golge `@CreatedBy/@CreatedDate` + auditor-aware ile otomatik doldurur.\n\n---\n\n## A.3 Scaffold Akisi (entity → repository → service → controller) — Yasak: /(Optional<[^>]*>\\s+findById\\s*\\(|boolean\\s+existsById\\s*\\(|void\\s+deleteById\\s*\\()/\n\ngolge'nin generic CRUD/search zinciri. Domain sinifi her katmanda golge generic'ini extend/implement eder ve tip parametrelerini doldurur.\n\n### Tip parametreleri sozlugu\n\n- `ID` — PK tipi (`UUID`, `Long`, ...).\n- `GDTO`/`DTO` — `GolgeBaseDto` turevi DTO.\n- `QDTO` — `GolgeQueryDto` turevi sorgu DTO'su (sayfalama/filtre).\n- `GE`/`E` — `GolgeBaseEntity` turevi entity.\n- `GMPPR` — `GolgeGenericMapstructMapper<ID,DTO,E>` mapper.\n- `R` — repository (`GolgeGenericJpaRepository` / `...SearchRepository`).\n\n### Katman 1 — Repository\n\n`GolgeGenericJpaRepository<E, ID>` = yazma+okuma (save/update/delete + tum find). `GolgeGenericJpaSearchRepository<E, ID>` = sadece okuma (search datasource icin). Long PK kisayollari: `GolgeJpaRepository<E extends GolgeEntity>`, `GolgeJpaSearchRepository<E>`.\n\n```java\n// taraf: operational repo (yazma)\n@Repository\npublic interface GercekKisiOperationalRepository extends GolgeGenericJpaRepository<GercekKisi, UUID> {}\n\n// taraf: search repo (okuma; ek derived query metodu eklenebilir)\n@Repository\npublic interface GercekKisiSearchRepository extends GolgeGenericJpaSearchRepository<GercekKisi, UUID> {\n    boolean existsByTcKimlikNo(Long tcKimlikNo);\n}\n```\n\n> `GolgeGenericJpaRepository` zaten su metodlari sunar: `save/saveAll/saveAndFlush`, `update/updateAll/updateAndFlush`, `deleteById/deleteAllById/deleteAllInBatch`, `flush`. `GolgeGenericJpaSearchRepository` ise `findById/getById/findAll(Predicate/Pageable/Example/Sort)/exists/count/findBy(...)` + QueryDSL `Predicate` overload'larini sunar. **Bunlari elle yazmayin.**\n\n### Katman 2 — Mapper\n\n```java\n@Mapper(nullValuePropertyMappingStrategy = NullValuePropertyMappingStrategy.IGNORE)\npublic interface GercekKisiMapper extends GolgeGenericMapstructMapper<UUID, GercekKisiDto, GercekKisi> {}\n```\n\n`GolgeGenericMapstructMapper` su metodlari kontrat olarak verir: `convertEntityToDto`, `convertDtoToEntity`, `mapToEntity(dto,e)`, `convertEntityListToDtoList`/`convertDtoListToEntityList` (List+Set), `convertDtoIdToEntityId`. MapStruct impl'i build-time uretir.\n\n### Katman 3 — Service\n\n```java\n// arayuz: golge generic operation service'i extend et, domain-ozel metod ekle\npublic interface GercekKisiOperationalService extends GolgeGenericOperationService<UUID, GercekKisiDto> {\n    GercekKisiDto addGercekKisi(@Valid @NotNull GercekKisiCompositeDto dto);\n}\n```\n\n`GolgeGenericOperationService<ID, GDTO>` sundugu metodlar (`javap`): `save/saveAll`, `update/updateAll`, `dynamicUpdate/dynamicUpdateAll`, `deleteById(id)`, `deleteById(id, boolean softDelete)`, `deleteAllById(list)`, `deleteAllById(list, boolean)`.\n\nImpl, `GolgeGenericOperationServiceImpl<ID, GDTO, GE, GMPPR, R>`'i extend eder (5 tip parametresi: `EntityManager`, mapper, repository ctor'a verilir). taraf bunu bir ara base ile sarmis:\n\n```java\n@Transactional(transactionManager = \"transactionManager\")\npublic abstract class TarafBaseOperationalServiceImpl<ID extends Serializable, GDTO extends GolgeGenericDto<ID>,\n        E extends GolgeGenericEntity<ID>, MPPR extends GolgeGenericMapstructMapper<ID,GDTO,E>,\n        R extends GolgeGenericJpaRepository<E,ID>>\n        extends GolgeGenericOperationServiceImpl<ID, GDTO, E, MPPR, R> {\n    // update*/dynamicUpdate*: @Validated({Default.class, GolgeView.Merge.class}) ile override\n}\n```\n\nSearch service icin `GolgeGenericSearchService<ID, GDTO, QDTO>`: `getById(id)`, `queryList(qdto)`, `queryPage(qdto)`. Impl (`GolgeGenericSearchServiceImpl`) `QueryGenerator` + `EntityPathBase` (QueryDSL `Q*`) ile sorgu uretir.\n\n### Katman 4 — Controller (`*Structure` arayuzlerinin rolu)\n\ngolge controller'i iki parcalidir:\n- **`*RestStructure` arayuzu** — REST mapping anotasyonlarini tasir. `javap -v` ile dogrulandi: `GolgeGenericOperationalRestStructure`'da `save` -> `@PostMapping` + `@JsonView(GolgeView.Persist/Query)` + `@Validated({Default, GolgeView.Persist})`; `update` -> `@PutMapping` (+ `GolgeView.Merge`); `deleteById` -> `@DeleteMapping(\"/id/{id}\")` + `@PathVariable`. Body parametreleri `@RequestBody @Valid @NotNull`.\n- **`*RestController` sinifi** — Structure'i implement eder, service'i constructor'dan alir, govdesi `service.save(...)` cagrisina indirgenir.\n\n```\nGolgeGenericOperationalRestController<ID, GDTO, OS>  implements GolgeGenericOperationalRestStructure<ID, GDTO>\nGolgeOperationalRestController<DTO, OS>  (= ...<Long, DTO, OS>)\nGolgeGenericSearchRestController<ID, GDTO, QDTO, S>  implements GolgeGenericSearchRestStructure<...>\n```\n\n**Pratikte taraf** domain'i CRUD endpoint'lerini cogunlukla `server` modulunun `controller/` paketindeki paylasilan `*RestClient` REST kontrat arayuzu (Spring MVC: `@RequestMapping` + `@JsonView(GolgeView.Base)`, `@FeignClient` DEGIL) uzerinden tanimlar ve controller onu implement eder — golge generic controller'i base olarak da kullanilabilir. Ornek controller (gercek dosya `controller/impl/KorumaKarariRestController.java`):\n\n```java\n@RestController @RequiredArgsConstructor\n@PreAuthorize(\"hasAuthority('IY_KADASTRO_MUDURLUK_KULLANICISI')\")\npublic class KorumaKarariRestController implements KorumaKarariRestClient {   // server modulu controller/ paketindeki paylasilan REST kontrat arayuzu\n    private final KorumaKarariOperationalService korumaKarariOperationalService;\n    private final KorumaKarariSearchService korumaKarariSearchService;\n    @Override public ResponseEntity<KorumaKarariDto> saveKorumaKarari(KorumaKarariDto r) { ... }\n}\n```\n\n> **Not (kontrat ile Feign ayrimi):** `KorumaKarariRestClient` adina ragmen bir Spring MVC arayuzudur (`@RequestMapping(\"/api/koruma-karari\")`, metodlar `@PostMapping` + `@JsonView(GolgeView.Base.class)`); `@FeignClient` anotasyonu YOKTUR. Servisler arasi cagri yapan asil Feign client `TarafFeignClient`'tir (`@FeignClient(name=\"tarafFeignClient\")`, `taraf-api/client` modulunde). `client` modulunde hic `*RestClient` arayuzu yoktur (dogrulandi: `find` ile 0 sonuc; modulde yalniz `TarafFeignClient`, `EnableTarafFeignClient`, `TarafFeignClientConfiguration` var).\n\n> **`GolgeView` (Base/Command/Persist/Merge/Query):** golge, JSON serializasyon ve Bean Validation gruplarini bu view'larla yonetir. View hiyerarsisi (`javap -p` ile dogrulandi): `Base` (kok) -> `Command extends Base` ve `Query extends Base`; `Persist extends Command`, `Merge extends Command`. `save` -> Persist grubu (id beklenmez), `update` -> Merge grubu (id zorunlu); `Base` ise hem yazma hem okuma cevaplarinda ortak gorunen en genis taban view'dir. Gercek taraf kodunda en yaygin kullanilan view `GolgeView.Base`'tir — paylasilan REST kontratlari yanit DTO'larini `@JsonView(GolgeView.Base.class)` ile isaretler (orn. `KorumaKarariRestClient`). Validation anotasyonlarinizi (`@NotNull(groups=...)`) bu view'lara gore tanimlayin; aksi halde update'te id dogrulamasi calismaz.\n\n### Review kontrolleri (A.3)\n\n- ❌ **Elle CRUD controller/service** (save/update/delete metodlarini elle yazan): golge generic'i kullan. (Bolum A.8.)\n- ❌ Repository'de `findById`/`save`/`existsById` gibi metodlar **elle redeclare** edilmis: golge base'inde zaten var.\n- ❌ Mapper elle `convertEntityToDto` impl'i yaziyor (interface yerine class): MapStruct `@Mapper` + golge interface'i ile build-time uretilmeli.\n- ❌ Controller `@RequestMapping` path/HTTP method'larini elle veriyor ama golge `*Structure`'i da implement ediyor: cifte mapping cakismasi. Birini sec.\n- ⚠️ Service impl'de `getMapper().convertDtoToEntity(...).save(...)` gibi golge `save()` yerine **dogrudan repository** cagrisi (`saveOrUpdate` ornegindeki gibi): audit/validation/`GolgeView` adimlarini atlayabilir; gerekce yoksa `super.save(dto)` tercih edilmeli.\n\n---\n\n## A.4 Exception Modeli ve Dogru Tip Secimi — Yasak: /throw\\s+new\\s+(RuntimeException|IllegalArgumentException|IllegalStateException|Exception)\\s*\\(/\n\n`javap -p` ile dogrulanmis hiyerarsi:\n\n```\nRuntimeException\n  └─ GolgeUncheckedException        (final GolgeErrorDetail errorDetail)\n       ├─ GolgeBusinessRuleException        (ctor: String code, String message; STATUS sabit)\n       └─ GolgeResourceNotFoundException    (ctor: String code, String message; STATUS=404 tipi)\nException\n  └─ GolgeCheckedException          (final GolgeErrorDetail errorDetail)\n```\n\n`GolgeErrorDetail` alanlari: `httpStatus (int)`, `code`, `type`, `cause`, `message`, `attributes (Map<String, ? extends Serializable>)` + Lombok `builder()`.\n\n| Durum | Kullanilacak tip | HTTP |\n|---|---|---|\n| Is kurali ihlali (cinsiyet listede yok, ad < 2 hane, ...) | `GolgeBusinessRuleException(code, msg)` | 4xx (genelde 400/422) |\n| Aranan kayit yok | `GolgeResourceNotFoundException(code, msg)` | 404 |\n| Beklenmeyen ama checked akista | `GolgeCheckedException` | 5xx |\n| Genel uncheck altyapi hatasi | `GolgeUncheckedException` | `errorDetail.httpStatus` |\n\nDomain genelde kendi alt sinifini turetir (`taraf`: `TarafBusinessRuleException`, `TarafResourceNotFoundException`) ve sabit hata kodlarini (`ClientErrorCodes`) kullanir:\n\n```java\nthrow new TarafBusinessRuleException(ClientErrorCodes.CINSIYET_1_3_ARASINDA_OLMALI);\nthrow new TarafResourceNotFoundException(TARAF_ERROR, \"Aradiginiz kriterlerde kayitli kisi yok.\");\n```\n\n### `GolgeContextExceptionHandler` (golge-context)\n\n`ResponseEntityExceptionHandler` turevi global handler. Yakaladiklari (`javap`): `handleMethodArgumentNotValid`, `handleHandlerMethodValidationException`, `handleHttpMessageNotReadable`, `handleAllException`. Yani **Bean Validation hatalari (`@Valid`) ve tum exception'lar otomatik olarak `GolgeErrorDetail` JSON'una donusur.** `GolgeBusinessRuleException` icindeki `errorDetail` HTTP status'a maplenir.\n\n### Review kontrolleri (A.4)\n\n- ❌ Controller/service'te `try/catch` ile exception yakalanip elle `ResponseEntity.status(400).body(...)` donuluyor: golge handler zaten yapiyor; sadece dogru exception'i `throw` et.\n- ❌ Genel `RuntimeException`/`IllegalArgumentException`/`Exception` firlatan is kurali: `GolgeBusinessRuleException`/`GolgeResourceNotFoundException`'a cevir — aksi halde 500 doner ve `errorDetail`/code istemciye gitmez.\n- ❌ Mesaj string'i hardcode + her yerde tekrar: hata kodu sabitine (`ClientErrorCodes`) tasi (i18n + tek kaynak).\n- ❌ `@ControllerAdvice` ile elle global handler yaziliyor: golge `GolgeContextExceptionHandler` ile cakisir; gerekmiyorsa kaldir.\n- ⚠️ `catch (Exception e) { return null; }` veya yutulan exception: 404/400 yerine sessiz hata; firlat.\n\n---\n\n## A.5 Context / Oturum — Yasak: /GolgeApplicationContextHolder\\.getBean\\s*\\(/\n\n| API | Tip | Scope / Dikkat |\n|---|---|---|\n| `GolgeApplicationContextHolder` | static yardimci (`ApplicationContextAware`) | **Static** `getBean(...)`, `getApplicationName()`, `publishEvent(...)`. DI mumkunse onu tercih et; bean'i static cekmek son care. |\n| `GolgeSessionAttributeHolder` | request/session-scoped bean (interface) | `setAttribute/getAttribute/removeAttribute/getAttributes`. **SADECE golge-context 1.9.0+'da var** (bkz. A.7). |\n| `GolgeSessionAware` | bean | `getSessionId()`, `getUsername()`. |\n| `GolgeContextAutoConfiguration` | auto-config | `golgeSessionAware`, `golgeSessionAttributeHolder`, `requestContextListener`, exception preparer bean'lerini saglar. |\n\n> `GolgeSessionAttributeHolder` request kapsamli oturum verisi tutar; uzun yasayan singleton'a inject edilip alan olarak saklanirsa thread/istek karismasi olur. Inject edip **her cagriside** `getAttribute` ile oku; degeri field'a cache'leme.\n\n### Review kontrolleri (A.5)\n- ❌ `GolgeApplicationContextHolder.getBean(...)` constructor injection'in mumkun oldugu yerde kullanilmis: DI'a cevir (test edilebilirlik).\n- ❌ `GolgeSessionAttributeHolder`'dan okunan deger singleton bean field'inda saklanmis: istekler arasi sizinti riski.\n- ⚠️ Kod `GolgeSessionAttributeHolder` kullaniyorsa, BOM'un getirdigi golge-context surumunu dogrula (A.7).\n\n---\n\n## A.6 Guvenlik Anotasyonlari ve Feign Auth Propagasyonu — Yasak: /@RequestHeader\\s*\\([^)]*[Aa]uthorization|\"Authorization\"/\n\n### Endpoint/method guvenligi (golge-security)\n\n`javap -v` ile: `@GolgeSecureEndpoint` -> `@Target({METHOD, TYPE}) @Retention(RUNTIME) @Documented`; `@GolgePublicEndpoint` ayni sekilde `@Target({METHOD, TYPE})` (public/permit). Yani her ikisi de hem metoda hem sinifa uygulanabilir. Bunlar golge security expression altyapisi (handler: `tr.com.test.golge.security.handler.GolgeSecurityMethodSecurityExpressionHandler`; root'lar: `GolgeSecurityExpressionRoot` ve `GolgeMethodSecurityExpressionRoot`) ile calisir. Pratikte yetkilendirme cogunlukla Spring'in `@PreAuthorize(\"hasAuthority('IY_...')\")`'i ile yapilir (rol deseni `IY_*`):\n\n```java\n@PreAuthorize(\"hasAuthority('IY_KADASTRO_MUDURLUK_KULLANICISI')\")\n```\n\n`GolgeSecurityContext`: `getPermitUrlSet()`, `getPermitRequestMatcherList()` — permit (public) URL kumesini saglar. `@GolgeConditionalOnSecurityEnabled/Disabled` ile guvenlik acik/kapaliya gore kosullu bean tanimi yapilir.\n\n### Feign / RestTemplate auth header propagasyonu\n\nBir servisten digerine cagri yapilirken **kullanici token'i otomatik tasinmali**. golge bunu interceptor'larla saglar:\n\n- **Feign:** `GolgeFeignClientInterceptor` (abstract, `feign.RequestInterceptor`). Somut: `GolgeSecurityFeignClientInterceptor` (golge-security-cloud) — `doApply` icinde `GolgeSecurityAuthorizationHeaderAware`'den alinan Authorization header'ini RequestTemplate'e ekler. Auto-config: `GolgeFeignClientAutoConfiguration`.\n- **RestTemplate:** `GolgeSecurityAuthorizationRestClientInterceptor` (`ClientHttpRequestInterceptor`).\n- **Belirli metodu interceptor'dan haric tutmak:** `@GolgeFeignClientMethodExcludeInterceptor` (`@Target({TYPE, METHOD})`).\n\n### Review kontrolleri (A.6)\n- ❌ Feign client metoduna **elle** `@RequestHeader(\"Authorization\") String token` parametresi eklenmis ve cagrida elle gecmis: golge interceptor zaten propagate ediyor; gereksiz/sizinti riski.\n- ❌ Server-to-server cagride token kayboluyor (401): interceptor bean'i (golge-security-cloud) bagimliligi/aktifligi eksik olabilir — `GolgeSecurityFeignClientInterceptor` devrede mi kontrol et.\n- ❌ Controller metodu yetkilendirmesiz (`@PreAuthorize` yok, `@GolgePublicEndpoint` da yok): bilincli public degilse aciktir.\n- ⚠️ Public olmasi gereken endpoint icin elle SecurityConfig yazmak yerine `GolgeSecurityContext` permit mekanizmasi/`@GolgePublicEndpoint` kullan.\n\n---\n\n## A.7 Auto-configuration & BOM Surum Pinning Tuzaklari — Yasak: /(@SpringBootApplication|@EnableAutoConfiguration)\\s*\\([^)]*exclude/\n\ngolge modulleri Spring Boot auto-configuration ile devreye girer (`golge-web-starter` -> `GolgeWebStarterAutoConfiguration`, tek `AutoConfiguration.imports` girisi). Surumler **`ekosistem-parent` BOM'undan transitif** gelir.\n\n### TUZAK: BOM pinned surum < gereken surum (gercek vaka)\n\n`GolgeSessionAttributeHolder` golge-context **1.9.0** ile geldi; 1.8.1 jar'inda **yoktur** (dogrulandi: 1.8.1 jar'inda yalniz `GolgeSessionAware`/`GolgeSessionAwareImpl` var). Eger `ekosistem-parent` BOM golge-context'i 1.8.1'e pinliyorsa, `GolgeSessionAttributeHolder` kullanan kod **derlenmez/NoClassDefFoundError** verir.\n\n**Gercek cozum — `basvuru/basvuru-api/build.gradle` (dogrulanmis):**\n\n```gradle\ndependencyManagement {\n    imports { mavenBom \"tr.com.test.ekosistem:ekosistem-parent:${ekosistemVersion}\" }   // 1.6.1 -> golge-context 1.8.1 pinler\n    dependencies {\n        // ekosistem BOM 1.8.1'i pinler; AktifProfilProvider'in kullandigi\n        // GolgeSessionAttributeHolder 1.9.0 ile geldi.\n        dependency \"tr.com.test.golge:golge-context:${golgeContextVersion}\"   // golgeContextVersion=1.9.0\n    }\n}\n```\n\n### Review kontrolleri (A.7)\n- ❌ `GolgeSessionAttributeHolder` (veya baska yeni golge API) kullanilmis ama BOM eski surumu pinliyor ve **override yok**: derleme/runtime hatasi. Cozum: ilgili modulu `dependencyManagement.dependencies` ile override et (yukaridaki desen).\n- ⚠️ Build'de golge modulune **explicit surum** yazilmis (BOM'u baypas): tek modulu yukseltmek diger golge modulleriyle surum uyumsuzlugu yaratabilir (entity/jpa/web-starter ayni minor'da olmali — hepsi 1.9.0). Override'i sadece gercekten gereken modulle sinirla ve gerekce yorumu ekle.\n- ⚠️ Auto-config'i elle `@Import` veya `exclude` ile devre disi birakan kod: golge'nin sagladigi handler/interceptor/bean'leri kapatabilir; gerekce sorgula.\n- ✅ Beklenen desen: golge plugin surumleri (`golgeSpringBootPluginVersion=1.7.2` vb.) gradle.properties'te; golge **kutuphane** surumleri BOM'dan (override haric).\n\n---\n\n## A.8 ILKE: Framework Sagliyorken Elle Boilerplate Yazma — Yasak: /@(Rest)?ControllerAdvice\\b|new\\s+PageImpl\\s*</\n\ngolge'nin generic zinciri **olmadan** elle yazilan her CRUD/sayfalama/exception-mapping/audit/auth kodu review'da geri cevrilmelidir. Hizli tarama icin:\n\n| Anti-pattern (elle yazilmis) | golge karsiligi |\n|---|---|\n| Repository'de `Optional<X> findById(...)`, `X save(X)` elle redeclare | `GolgeGenericJpaRepository`/`...SearchRepository` zaten saglar |\n| Service'te save/update/delete + dirty-check + version artirma | `GolgeGenericOperationService(Impl)` |\n| Sayfalama: `PageRequest` + `count` + `PageImpl` elle | `GolgeGenericSearchService.queryPage(qdto)` + `GolgeQueryGenerator` |\n| Controller'da `@PostMapping/@PutMapping/@DeleteMapping` elle | `*RestStructure` (golge mapping'leri + `@JsonView`/`@Validated` view'lari) |\n| entity<->dto donusumu elle | `GolgeGenericMapstructMapper` |\n| `@ControllerAdvice` global handler | `GolgeContextExceptionHandler` |\n| audit alanlarini `@PrePersist`/`@PreUpdate` ile elle doldurma | golge audit entity + auditor-aware |\n| Feign'e elle Authorization header | `GolgeSecurityFeignClientInterceptor` |\n\n> Istisna: golge generic'i karsilamadigi **gercek domain mantigi** (orn. `addGercekKisi` composite kayit, Elasticsearch sorgusu, QueryDSL ile ozel filtre) elbette elle yazilir — ama bu kod bile golge `save()`/exception/transaction altyapisini cagirmali. Ornekteki `GercekKisiSearchServiceImpl` QueryDSL'i elle kullanir cunku ihtiyac genericin disindadir; yine de `TarafResourceNotFoundException` firlatir.\n\n---\n\n## 5. Hizli Referans\n\n### Backend — golge base secimi\n- UUID PK + audit -> `GolgeGenericAuditEntity<UUID>` / DTO `GolgeGenericDto<UUID>`.\n- Long PK + audit -> `GolgeAuditEntity` / DTO `GolgeDto`.\n- Yazma repo -> `GolgeGenericJpaRepository<E,ID>`; okuma -> `GolgeGenericJpaSearchRepository<E,ID>`.\n- Service -> `GolgeGenericOperationService<ID,GDTO>` / `GolgeGenericSearchService<ID,GDTO,QDTO>`.\n- Mapper -> `@Mapper interface X extends GolgeGenericMapstructMapper<ID,DTO,E>`.\n- Hata -> `GolgeBusinessRuleException` (is kurali) / `GolgeResourceNotFoundException` (404); asla cIplak `RuntimeException`.\n- Yetki -> `@PreAuthorize(\"hasAuthority('IY_...')\")`; public -> `@GolgePublicEndpoint`.\n\n### Backend — \"kirmizi bayraklar\"\nElle CRUD controller/service · elle `findById/save` redeclare · `@ControllerAdvice` global handler · elle audit doldurma · Feign'e elle Authorization · `GolgeApplicationContextHolder.getBean` (DI mumkunken) · BOM eski golge-context + `GolgeSessionAttributeHolder` (override yok).\n\n\n---\n\n## 6. Ilgili Dosyalar\n\n**golge backend jar'lari** (`/home/kerim/.gradle/caches/modules-2/files-2.1/tr.com.test.golge/<modul>/<surum>/<hash>/<jar>`):\n- golge-web-starter 1.9.0, golge-data-orm-entity/-jpa/-dto/-mapper/-commons 1.9.0, golge-exception 1.9.0, golge-context 1.9.0 (ve 1.8.1 — `GolgeSessionAttributeHolder` farki), golge-security 1.3.0, golge-security-cloud 1.1.0, golge-feign-client 1.1.0.\n\n**Gercek backend kullanimi:**\n- `/home/kerim/repositories/taraf/taraf-api/server/.../entity/base/TarafAuditEntity.java`, `.../entity/base/TarafEntity.java`, `.../entity/GercekKisi.java`\n- `.../service/GercekKisiOperationalService.java`, `.../service/impl/GercekKisiOperationalServiceImpl.java`, `.../service/impl/base/TarafBaseOperationalServiceImpl.java`, `.../service/GercekKisiSearchService.java`, `.../service/impl/GercekKisiSearchServiceImpl.java`\n- `.../repository/operational/GercekKisiOperationalRepository.java`, `.../repository/search/GercekKisiSearchRepository.java`, `.../mapper/GercekKisiMapper.java`, `.../controller/impl/KorumaKarariRestController.java`\n- BOM override tuzagi: `/home/kerim/repositories/basvuru/basvuru-api/build.gradle` + `gradle.properties` (`golgeContextVersion=1.9.0`, `ekosistemVersion=1.6.1`)\n\n\n**Frontend tarafi** (golge-ui + Module Federation) ayri dokumanda: [04-golge-framework-frontend.md](04-golge-framework-frontend.md).\n\n**Capraz-link:** entity/DTO/MapStruct/Envers detaylari icin [03-hibernate-jpa-taslak.md](03-hibernate-jpa-taslak.md); Spring katmanlari icin [02-spring-boot-code-review.md](02-spring-boot-code-review.md); backend PR checklist'i [06-backend-checklist.md](06-backend-checklist.md).\n",
  "04-golge-framework-frontend.md": "# Golge Framework — Frontend Code Review Standartlari\n\n> **Alt gorev 9** karsiligi. Frontend golge framework'u: **golge-ui** (paylasilan bilesen/tema/router/e-imza/api kutuphanesi) + **Module Federation** mikro-frontend mimarisi (`dis-portal-mf-shell` = host, `<ad>-web` = remote).\n> Backend (golge-* jar'lari) tarafi ayri dokumanda: [04-golge-framework-backend.md](04-golge-framework-backend.md) (alt gorev 4).\n> **Kullanim:** Her standart icin (a) **NEDEN** onemli, (b) review'da **NASIL TESPIT** edilir, (c) **NASIL DUZELTILIR**. Iddialar `golge-ui` `dist/*.d.ts` tip tanimlarina ve gercek `vite.config` dosyalarina dayandirilmistir.\n\n### Surum (dogrulanmis)\n\ngolge-ui **1.16.10** (`taraf-web/node_modules/golge-ui`). Repolar arasi hedef **1.16.x**; hala `^1.0.x`/`^1.2.x` kullanan repo var (singleton riski — bkz. B.2).\n\n---\n# BOLUM B — FRONTEND (golge-ui + Module Federation)\n\n## B.1 golge-ui Modulleri ve Export Alanlari — Yasak: /localStorage\\.(?:getItem|setItem)\\s*\\(\\s*[\"'][^\"']*(?:[Tt]oken|[Jj]wt|[Aa]uth)/\n\n`taraf-web/node_modules/golge-ui/package.json` (**v1.16.10**) `exports` alani — bes giris noktasi + stiller:\n\n| Import yolu | Saglananlar (`.d.ts`'ten dogrulandi) |\n|---|---|\n| `golge-ui` (`\".\"`) | **Bilesenler:** `GolgeApp`, `GolgeAppBar`, `GolgeMain`, `GolgeFooter`, `GolgeBrowserDebugger`, `GolgeDraggableDialog`, `GolgeInfoCard`, `GolgeTreeView`, `GolgeCrudLayout`, `components/base` (card/modal/button/menu/input), `components/crud` (`GolgeEntityForm`, `GolgeFilterForm`, `GolgeTable` + `GolgeTableField/GolgeField/GolgeFilterField` tipleri), `iconify`. **API:** `GolgeApi`, `golgeRtkApiHeaders`, `golgeErrorMiddleware`, tip: `GolgeEntity`, `GolgePageableRequest/Response`. **Bildirim:** `enqueueSnackbar`. **Guvenlik:** `useGolgeSecurity` + `GolgeUser`/`GolgeUserPosition`. **Vite:** `GolgeVitePlugin`, `PostTransformPlugin`. **Log/media hook'lari.** |\n| `golge-ui/utils` | `configUtils`, `DateUtil`, `inputUtils`, `postMessageBridge`, `typeUtils`, `windowUtils` |\n| `golge-ui/eimza` | E-imza: `EImza`, `EImzaModal` (+`EImzaModalProps`), `EImzaProps`, `SignDoc`, `GolgeDocument` |\n| `golge-ui/theme` | `theme-provider`, `theme-config`, `core`, `layouts`, `settings`, tema `types` (MUI tema entegrasyonu) |\n| `golge-ui/router` | `GolgeRouter` + `react-router-dom`'un tamami re-export |\n| `golge-ui/styles` | `dist/style.css` |\n\n`useGolgeSecurity()` doner: `{ logout, getToken, getAuthorities, hasAuthority, getUser, getUserPosition, switchPosition }` (hepsi `Promise`). **Token/yetki erisimi icin standart yol budur.**\n\n### golge-ui mi, ozel bilesen mi? (+ portal-ui/tapu-ui)\n- **golge-ui kullan:** uygulama kabugu (`GolgeApp/GolgeAppBar/GolgeMain`), CRUD ekranlari (`GolgeTable/GolgeEntityForm/GolgeFilterForm/GolgeCrudLayout`), tema, router, e-imza, RTK API header/middleware, guvenlik hook'u. Bunlari yeniden yazmak golge ile tutarsizlik ve bakim yuku dogurur.\n- **portal-ui / tapu-ui:** portal/tapu'ya ozgu paylasilan bilesen kutuphaneleri (MF'de `golge-ui` ile birlikte `portal-ui`, `portal-ui/ui`, `portal-ui/shared` singleton paylasilir). Domain-genel bilesen portal-ui/tapu-ui'de varsa onu kullan.\n- **Ozel bilesen yaz:** yalniz domain'e cok ozgu, paylasilamaz UI icin — ve mumkunse golge `base`/tema primitifleri uzerine kur.\n\n### Review kontrolleri (B.1)\n- ❌ Tablo/form/filtre elle MUI ile sifirdan yazilmis: `GolgeTable`/`GolgeEntityForm`/`GolgeFilterForm` kullan.\n- ❌ Token elle `localStorage`/cookie'den okunuyor: `useGolgeSecurity().getToken()` veya `golgeRtkApiHeaders` kullan.\n- ❌ Tarih/input/config islemleri elle: `golge-ui/utils` icinde var.\n- ❌ E-imza akisi elle: `golge-ui/eimza` (`EImzaModal`) kullan.\n\n---\n\n## B.2 Module Federation Mimarisi — Yasak: /[\"']{1}(?:golge-ui|react|react-dom|react-router-dom|portal-ui)[\"']\\s*:\\s*\\{(?![^}]*singleton\\s*:\\s*true)/\n\n**Host/shell:** `dis-portal-mf-shell-web` (port 5100). **Remote'lar:** `<ad>-web` (taraf 3005, zeminsorgu 5101, ...). Plugin: `@module-federation/vite`. Runtime: `@module-federation/runtime` + `runtime-tools` + `retry-plugin` (shell package.json `^0.21.6`).\n\n### Shell (host) — dinamik remote kaydi\nShell `vite.config.ts`'te `remotes: {}` **bos** birakilir; remote'lar **runtime'da** manifest'ten yuklenir (`src/remotes/loader.ts`):\n\n```ts\nimport { loadRemote, registerRemotes } from '@module-federation/runtime';\nconst manifestUrl = import.meta.env.DEV ? '/remotes.dev.json' : '/remotes.json';\n// fetch -> registerRemotes(remotesMap, { force: true }) -> loadRemote(remotePath)\n```\n\nShell ayrica `./shared` (`src/mf-shared.ts`) expose eder; remote'lara `getShellAuthToken()` saglar (`window.__SHELL_AUTH__`).\n\n### Remote — expose + shell'i remote olarak alma\n- `taraf-web`: `name: 'tarafApp'`, `filename: 'remoteEntry.js'`, expose: `./KisiLayout`, `./TuzelKisiLayout`, `./TipDegerVarlikApi`.\n- `zemin-sorgu-web`: `name: 'immovable_property_processes'`, expose: `./App`, ve **shell'i remote alir** (`remotes.shell` -> `http://localhost:5100/remoteEntry.js`) ki paylasilan auth token'ina (`shell/shared`) erisebilsin.\n\n### SHARED / SINGLETON bagimliliklar\nCogu config benzer bir shared blok kullanir (singleton + eager), ama **bloklar birebir ayni DEGILDIR** — dogrulandi: shell ve zeminsorgu (`zemin-sorgu-web`) config'leri `@reduxjs/toolkit`/`react-redux`'u shared'a koyar, ama `taraf-web` koymaz (taraf-web shared'i yalniz `react`, `react-dom`, `react-router-dom`, `@mui/*`, `portal-ui`/`portal-ui/ui`/`portal-ui/shared`, `golge-ui` icerir). Asagidaki blok **kanonik ornek**tir, tum config'lere dayatilan tek dogru sablon degil; review'da farkliliklarin **kasitli** olup olmadigini sorgulayin (orn. remote redux store paylasimina ihtiyac duyuyorsa redux singleton'i eksik birakmamali).\n\n```ts\n// Ornek (shell/zeminsorgu); taraf-web redux satirlarini icermez.\nshared: {\n  react:            { singleton: true, eager: true },\n  'react-dom':      { singleton: true, eager: true },\n  'react-router-dom': { singleton: true, eager: true },\n  '@reduxjs/toolkit': { singleton: true, eager: true },   // store paylasimi — taraf-web'de YOK\n  'react-redux':    { singleton: true, eager: true },     // taraf-web'de YOK\n  '@mui/material':  { singleton: true, eager: true },\n  '@mui/icons-material': { singleton: true, eager: true },\n  '@mui/system':    { singleton: true, eager: true },\n  'portal-ui':      { singleton: true, eager: true, version: false, requiredVersion: false },\n  'portal-ui/ui':   { singleton: true, eager: true, version: false, requiredVersion: false },\n  'portal-ui/shared': { singleton: true, eager: true, version: false, requiredVersion: false },\n  'golge-ui':       { singleton: true, eager: true, version: false, requiredVersion: false },\n}\n```\n\n> **NEDEN singleton:** React (hooks/context), react-router (tek router context), Redux (tek store), MUI/Emotion (tek tema + tek CSS cache), golge-ui (tek `useGolgeSecurity` context). Iki kopya yuklenirse: \"Invalid hook call\", kaybolan context, cift tema/CSS, bozuk auth. `golge-ui`/`portal-ui*` icin `version: false, requiredVersion: false` — surum uyumsuzlugunda hard fail yerine tek instance zorlanir.\n\n> **dedupe/optimizeDeps.dedupe** tum config'lerde ayni listeyi (`react`, `react-dom`, `react-router-dom`, `@remix-run/router`, `@mui/*`, `@emotion/*`, `golge-ui`) icerir — Vite'in dev'de cift kopya bundlelamasini engeller. Bu blok her remote'ta TUTARLI olmali.\n\n### Auth / token ve routing\n- Token paylasimi: birincil `golgeRtkApiHeaders`/`useGolgeSecurity().getToken()`; alternatif `shell/shared` -> `getShellAuthToken()` (`window.__SHELL_AUTH__`).\n- Routing: tek `react-router-dom` singleton; remote'lar shell'in router context'i icine mount edilir (`MicroAppRenderer` `loadRemote` + 10sn timeout ile).\n- Proxy/auth (dev): her web'in vite proxy'si `/api`'yi backend'e yonlendirir, `referer/referrer/origin` header'larini temizler, `Referrer-Policy: no-referrer` ekler; shell `tasinmaz` proxy'sinde cookie'den token fallback yapar.\n\n### golge-ui surum uyumu (RISK)\nRepolar arasi golge-ui surum dagilimi (dogrulandi): cogu `1.16.x`, ama hala `^1.0.0` (3 repo) ve `^1.2.0` (3 repo) kullanan var. Singleton paylasimda **tek instance** yuklenir; 1.0.x/1.2.x bekleyen bir remote 1.16.x ile calismak zorunda kalirsa **kirilma** (kayip export, degisen API) olur.\n\n### Review kontrolleri (B.2)\n- ❌ Yeni remote'un `shared` blogunda **ortak/zorunlu** bagimliliklar (react, react-dom, react-router-dom, @mui/*, golge-ui, portal-ui*) singleton olarak paylasilmamis: \"Invalid hook call\"/cift tema/bozuk auth. Bu cekirdek listeyi shell ile hizala. (Not: redux/`react-redux` her remote'ta olmak zorunda degil — shell/zeminsorgu paylasir, taraf-web paylasmaz; ama bir remote shell store'unu/redux'i gercekten paylasiyorsa `@reduxjs/toolkit`+`react-redux` singleton'i da eksiksiz olmali, yoksa cift store olusur.)\n- ❌ React/React-DOM/MUI/golge-ui surumleri remote ile shell arasinda **major** olarak farkli: singleton tek surum yukleyince digeri kirilir. package.json surumlerini hizala (golge-ui'yi 1.16.x'e cek).\n- ❌ Token elle remote'a prop olarak gecilmis: `useGolgeSecurity`/`golgeRtkApiHeaders`/`getShellAuthToken` standardini kullan.\n- ❌ Remote `dedupe`/`optimizeDeps.dedupe` listesi eksik: dev'de cift kopya. Standart listeyi ekle.\n- ❌ Remote kendi `react-router`'ini izole yuklemis (singleton degil): navigasyon shell ile kopar.\n- ⚠️ `GolgeVitePlugin()` eksik (taraf/shell var, zeminsorgu config'inde yok): golge build/transform davranisi tutarsiz olabilir — gerekliligini dogrula.\n- ⚠️ Remote `remoteEntry.js` adi/`name` cakismasi: shell `registerRemotes` scope'a gore dedup eder; iki remote ayni `name` kullanmamali.\n\n---\n\n\n---\n\n## Hizli Referans — Frontend \"kirmizi bayraklar\"\n\nshared blok shell ile uyumsuz · react/mui/golge-ui major surum farki · token elle localStorage/prop · dedupe listesi eksik · elle tablo/form (golge CRUD bilesenleri varken) · golge-ui `^1.0.x`/`^1.2.x` (1.16.x'e cek).\n\n---\n\n## Ilgili Dosyalar\n\n- `/home/kerim/repositories/taraf/taraf-web/node_modules/golge-ui/dist/*.d.ts` + `package.json` (v1.16.10 export'lari)\n- MF config: `/home/kerim/repositories/dis-portal-mf-shell/dis-portal-mf-shell-web/vite.config.ts` (+ `src/remotes/loader.ts`, `src/mf-shared.ts`), `/home/kerim/repositories/taraf/taraf-web/vite.config.ts`, `/home/kerim/repositories/zeminsorgu/zemin-sorgu-web/vite.config.ts`\n\n**Backend tarafi** (golge-* jar'lari) ayri dokumanda: [04-golge-framework-backend.md](04-golge-framework-backend.md).\n\n**Capraz-link:** React standartlari [01-react-code-review.md](01-react-code-review.md); frontend PR checklist'i [05-frontend-checklist.md](05-frontend-checklist.md).\n",
  "05-frontend-checklist.md": "# Frontend Code Review Checklist\n\n> TAKBIS mikro-frontend ekosistemi (`taraf-web`, `islem-yonetimi-web`, `fen-kayit-web` ve diger `<is-alani>-web` repolari) icin PR incelemede kullanilacak **eyleme donuk** kontrol listesi.\n> Kaynak standartlar: [01-react-code-review.md](./01-react-code-review.md) ve [04-golge-framework-frontend.md](./04-golge-framework-frontend.md) (Bolum B — Frontend). Maddeler bu dokumanlardan turetilmistir ve onlarla tutarlidir.\n>\n> ⚡ **Önce hızlı tara:** [`08-review-rehberi.md`](08-review-rehberi.md) — `pre-review.sh` mekanik ön-tarama (`eslint-disable`, `console.*`, golge-ui sürüm…), dosya-tipi→madde yönlendirme tablosu ve tek-sayfa Blocker kartı. Bu liste o akışın **derin inceleme** adımıdır.\n\n## Nasil kullanilir\n- PR'daki **degisen** dosyalar uzerinde maddeleri sirayla tara; her madde tek bir somut kontroldur.\n- Oncelik etiketi: **Blocker** = merge engeli; **Major** = duzeltilmeli, gerekce sorulmali; **Minor** = iyilestirme/oneri.\n- Repo desenini once tespit et: `taraf-web` = duz `src/` (`features/services/components/pages/hooks`), `islem-yonetimi-web` = feature-sliced (`features/<domain>` + `shared/`). Madde \"repo desenine uy\" derken bunu kasteder.\n- Surumleri DAIMA ilgili `package.json`'dan dogrula (React 18.2/18.3, MUI 5/6, ESLint legacy/flat, golge-ui 1.16.x). Capraz-linkler ayni `code-review-docs/` klasorune goredir.\n\n---\n\n## 1. Component & yapi\n\n- [ ] Dosyanin repo desenine uygun konumda oldugundan (`taraf-web` duz `services/` / `islem-yonetimi-web` `features/<domain>` + `shared/`) **emin ol**  — yanlis desen tutarsizlik yaratir  [Oncelik: Major]  ([01 §2.3](./01-react-code-review.md#23-klasor-deseni))\n- [ ] Bilesenin <250-300 satir ve tek sorumluluk oldugundan; container (veri/mantik) ile presentational (saf render) katmanlarinin ayrik oldugundan **emin ol**  — buyuk karma bilesen test edilemez, `memo` etkisiz kalir  [Oncelik: Major]  ([01 §3.1.1-3.1.2](./01-react-code-review.md#s-311-tek-sorumluluk-ve-bilesen-boyutu))\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ tek bilesende fetch + mantik + buyuk JSX (>300 satir)\n  function IslemTanimTree() { const { data } = useGetTreeQuery(); /* +200 satir JSX */ }\n  // ✅ container/presentational ayrik: mantik hook'ta, satir memo'lu saf bilesende\n  function IslemTanimTree() { const { flatItems } = useTreeData(); return <List rowComponent={TreeNodeRow} ... />; }\n  const TreeNodeRow = memo(function TreeNodeRow({ node, style }) { /* saf render */ });\n  ```\n  </details>\n- [ ] Veri cekmeyi custom hook'a, prezentasyonu saf bilesene **tasi** (useSearchKamu/useTaskFiltering deseni)  — render icinde dogrudan apiSlice hook + buyuk JSX karisimi olmamali  [Oncelik: Major]  ([01 §3.1.2](./01-react-code-review.md#s-312-container--presentational-ayrimi)) Yasak: /function\\s+[A-Z]\\w*\\s*\\([^)]*\\)\\s*\\{[^}]*use\\w*Query\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ veri cekme + filtre render govdesinde\n  function KisiListesi() { const { data } = useSearchKamuQuery(q); const filtered = data?.filter(...); return <Table rows={filtered} />; }\n  // ✅ veri/mantik hook'ta, bilesen saf\n  function KisiListesi() { const { searchKurum, sonuclar } = useSearchKamu(); return <Table rows={sonuclar} onSearch={searchKurum} />; }\n  ```\n  </details>\n- [ ] Isimlendirme konvansiyonunu **kullan**: PascalCase bilesen, useXxx hook, xxxApiSlice/xxxApi, xxxSlice+xxxReducer, XxxApi.ts (axios), XxxContext/XxxProvider/useXxx  — sembol/dosya aramasi icin tutarlilik  [Oncelik: Minor]  ([01 §3.1.3](./01-react-code-review.md#s-313-isimlendirme-konvansiyonu)) Yasak: /const\\s+(?!\\w*[Ss]lice)\\w+\\s*=\\s*createSlice\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ tutarsiz: gercekKisiapi, KisiCtx, getKisiData\n  export const gercekKisiapi = createApi({ ... });\n  // ✅ konvansiyon: xxxApiSlice / XxxContext / useXxx\n  export const gercekKisiApiSlice = createApi({ reducerPath: 'gercekKisiApi', ... });\n  export const KisiContext = createContext<KisiContextType | null>(null);\n  ```\n  </details>\n- [ ] JSX donen dosya icin `.tsx`, salt mantik icin `.ts` uzantisini **kullan** (orn. `useSearchKamu.tsx` vs `useResponsive.ts`)  — uzanti dogru olmali  [Oncelik: Minor]  ([01 §3.1.4](./01-react-code-review.md#s-314-hook-iceren-dosya-uzantisi))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ useResponsive.tsx — JSX yok, yine de .tsx\n  // ❌ useSearchKamu.ts — ReactNode/JSX donduruyor ama .ts\n  // ✅ JSX yok -> .ts ;  JSX/ReactNode var -> .tsx\n  // useResponsive.ts (salt mantik)  |  useSearchKamu.tsx (JSX icerir)\n  ```\n  </details>\n- [ ] Domain dilini Turkce; alan adlarini Turkce (tcKimlikNo, basvuruRef), React/teknik terimleri Ingilizce **kullan**  — TAKBIS konvansiyonu  [Oncelik: Minor] Yasak: /\\b(firstName|lastName|identityNumber|taxNumber|birthDate)\\b/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ domain alanlari Ingilizce\n  interface GercekKisiDto { identityNumber: string; applicationRef: string; }\n  // ✅ domain Turkce, teknik terim Ingilizce\n  interface GercekKisiDto { tcKimlikNo: string; basvuruRef: string; }\n  ```\n  </details>\n\n## 2. State yonetimi\n\n- [ ] Sunucu verisi (CRUD/liste/detay) icin **RTK Query apiSlice**'i; global UI/akis durumu icin Redux slice'i; form/ekran-lokal durum icin useState/useReducer'i **kullan**  — yanlis katman boilerplate ve stale-data dogurur  [Oncelik: Major]  ([01 §3.2.1](./01-react-code-review.md#s-321-dogru-state-mekanizmasini-sec)) Yasak: /createAsyncThunk\\s*\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ sunucu verisi Redux slice'a elle yazilmis\n  dispatch(setKisiler(await fetch('/api/kisiler').then(r => r.json())));\n  // ✅ sunucu verisi RTK Query apiSlice'ta (cache/dedupe/invalidation otomatik)\n  const { data: kisiler } = useGetKisilerQuery();\n  ```\n  </details>\n- [ ] Sunucu verisini useState'e kopyalamaktan **kacin** (const {data}=useGetXQuery() sonrasi useEffect(()=>setItems(data)) kalibi olmasin)  — cift kaynak/senkron hatasi  [Oncelik: Major]  ([01 §3.2.2](./01-react-code-review.md#s-322-sunucu-verisini-usestatee-kopyalama)) Yasak: /set[A-Z]\\w*\\(\\s*data\\s*\\)/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ RTK Query sonucu useState'e kopyalaniyor (stale-data)\n  const { data } = useGetVarlikQuery(); const [items, setItems] = useState([]);\n  useEffect(() => { if (data) setItems(data); }, [data]);\n  // ✅ dogrudan data'yi kullan\n  const { data: items = [] } = useGetVarlikQuery();\n  ```\n  </details>\n- [ ] Turetilebilir degeri ayri state'te tutmaktan **kacin**; useMemo ile render'da turet  — useEffect icinde state'ten state set etme  [Oncelik: Major]  ([01 §3.2.3](./01-react-code-review.md#s-323-turetilmis-statei-state-olarak-tutma)) Yasak: /useEffect\\(\\s*\\(\\s*\\)\\s*=>\\s*\\{?\\s*set[A-Z]\\w*\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ turetilmis deger ayri state + useEffect ile senkron\n  const [tasks, setTasks] = useState<Task[]>([]);\n  useEffect(() => { setTasks(camundaTasks.map(camundaTaskToTask)); }, [camundaTasks]);\n  // ✅ render'da useMemo ile turet\n  const tasks = useMemo(() => camundaTasks.map(camundaTaskToTask), [camundaTasks]);\n  ```\n  </details>\n- [ ] Cift state-kaynagindan **kacin**: ayni kayit/secim hem Context hem Redux'ta, ya da hem React state hem modul-seviye mutable degiskende tutulmasin (AuthTokenContext token anti-pattern'i)  — token degisimi sonrasi eski token tasiyabilir  [Oncelik: Blocker]  ([01 §3.2.5 / AP-2](./01-react-code-review.md#s-325-global-vs-lokal-sinir--cift-state-kaynagi-yasagi)) Yasak: /(^|\\s)let\\s+\\w*[Tt]oken\\w*\\s*=/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ token hem Context state hem modul-global; axios eski token tasiyabilir\n  let authToken: string | null = null; // modul-global, useEffect ile senkronlanir\n  // ✅ tek kaynak: axios interceptor token'i useGolgeSecurity/store'dan ceker\n  const token = await useGolgeSecurity().getToken();\n  ```\n  </details>\n- [ ] Immutability'yi koru: mutasyonu yalniz reducer **icinde** (Immer) yap; reducer/store/props **disinda** obj.x = y kullanmaktan **kacin**  — Immer disi mutasyon bug uretir  [Oncelik: Major]  ([01 §3.2.4](./01-react-code-review.md#s-324-immutability-rtk--immer)) Yasak: /\\bprops\\.\\w+\\s*=\\s*[^=]/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ reducer disinda props/store mutasyonu\n  const onSec = (kayit) => { kayit.secili = true; setKayitlar(kayitlar); };\n  // ✅ Immer sadece reducer icinde; disarida immutable kopya\n  setGeldigiBilesen: (state, action: PayloadAction<GeldigiBilesenType>) => {\n    state.geldigiBilesen = action.payload; // Immer: guvenli\n  }\n  ```\n  </details>\n- [ ] Tiplenmis Redux hook'larini (useAppDispatch/useAppSelector) app/hooks.ts'ten **kullan**; bilesende ham useDispatch<AppDispatch>() tekrari olmasin  [Oncelik: Minor]  ([01 §3.1.4](./01-react-code-review.md#s-314-hook-iceren-dosya-uzantisi)) Yasak: /useDispatch\\s*<\\s*AppDispatch\\s*>/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ her bilesende ham, tiplenmemis hook\n  const dispatch = useDispatch<AppDispatch>();\n  const kisi = useSelector((s: RootState) => s.kisi);\n  // ✅ app/hooks.ts'ten tiplenmis hook\n  const dispatch = useAppDispatch();\n  const kisi = useAppSelector((s) => s.kisi);\n  ```\n  </details>\n\n## 3. Hook kullanimi\n\n- [ ] Hook'larin kosulsuz ve ust seviyede oldugundan; if/for/.map/.reduce/erken-return sonrasi hook cagrisi OLMADIGINDAN **emin ol**  — react-hooks/rules-of-hooks: error, runtime crash riski (useWidth ihlali)  [Oncelik: Blocker]  ([01 §3.3.1 / AP-1](./01-react-code-review.md#s-331-hook-kurallari-rules-of-hooks--error-seviyesi)) Yasak: /(if|for|while)\\s*\\([^)]*\\)\\s*\\{?\\s*(const\\s+[^=]+=\\s*)?use[A-Z]\\w*\\s*\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ .reduce callback'i icinde hook (kosullu) — rules-of-hooks ihlali\n  keys.reduce((out, key) => {\n    const m = useMediaQuery(theme.breakpoints.up(key)); return !out && m ? key : out;\n  }, null);\n  // ✅ tum hook'lar kosulsuz ust seviyede, secim sonra\n  const md = useMediaQuery(theme.breakpoints.up('md'));\n  const sm = useMediaQuery(theme.breakpoints.up('sm'));\n  return md ? 'md' : sm ? 'sm' : 'xs';\n  ```\n  </details>\n- [ ] `eslint-disable react-hooks/rules-of-hooks` yorumunu **kaldir**  — hook ihlalini gizlemek kirmizi bayrak  [Oncelik: Blocker]  ([01 §3.3.1](./01-react-code-review.md#s-331-hook-kurallari-rules-of-hooks--error-seviyesi))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ disable ile ihlal gizlenmis\n  // eslint-disable-next-line react-hooks/rules-of-hooks\n  const matches = useMediaQuery(theme.breakpoints.up(key));\n  // ✅ disable'i kaldir, hook'u ust seviyeye tasi (kok-nedeni gider)\n  const matches = useMediaQuery(theme.breakpoints.up('md'));\n  ```\n  </details>\n- [ ] useEffect cleanup'inin dondugunden (listener/setInterval/AbortController/subscription) ve addEventListener -> removeEventListener yapildigindan **emin ol**  — sizinti onlemi  [Oncelik: Major]  ([01 §3.3.2 / AP-6](./01-react-code-review.md#s-332-useeffect--dogru-kullanim-cleanup-bagimlilik-dizisi)) Yasak: /useEffect\\((?:(?!removeEventListener).)*addEventListener/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ listener eklenir ama kaldirilmaz (sizinti)\n  useEffect(() => { window.addEventListener('taraf:auth-error', handleAuthError); }, []);\n  // ✅ cleanup ile removeEventListener\n  useEffect(() => {\n    window.addEventListener('taraf:auth-error', handleAuthError);\n    return () => window.removeEventListener('taraf:auth-error', handleAuthError);\n  }, [handleAuthError]);\n  ```\n  </details>\n- [ ] useEffect'e dogrudan async fn vermekten **kacin**; ic IIFE/async function **kullan**  — async fn cleanup yerine Promise doner  [Oncelik: Major]  ([01 §3.3.2](./01-react-code-review.md#s-332-useeffect--dogru-kullanim-cleanup-bagimlilik-dizisi)) Yasak: /useEffect\\(\\s*async\\b/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ async fonksiyon dogrudan effect'e (cleanup yerine Promise doner)\n  useEffect(async () => { await logout(); }, []);\n  // ✅ ic IIFE; cleanup donulebilir\n  useEffect(() => { (async () => { await logout(); })(); }, []);\n  ```\n  </details>\n- [ ] Bagimlilik dizilerinin tam oldugundan; eslint-disable react-hooks/exhaustive-deps OLMADIGINDAN; effect icinde set edilen state'in bagimlilikta OLMADIGINDAN (sonsuz dongu) **emin ol**  [Oncelik: Major]  ([01 §3.3.2](./01-react-code-review.md#s-332-useeffect--dogru-kullanim-cleanup-bagimlilik-dizisi)) Yasak: /eslint-disable[^\\n]*exhaustive-deps/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ set edilen state bagimlilikta -> sonsuz dongu; disable ile gizlenmis\n  // eslint-disable-next-line react-hooks/exhaustive-deps\n  useEffect(() => { setSayac(sayac + 1); }, [sayac]);\n  // ✅ functional update; bagimlilik gereksiz\n  useEffect(() => { setSayac((s) => s + 1); }, []);\n  ```\n  </details>\n- [ ] Iki+ bilesende kopyalanan `useState`+`useEffect` blogunu, tek-sorumluluk + `useCallback`/`useMemo` ile kararli cikti veren bir custom hook'a **cikar** (`useLocalStorage` referans sablonu)  [Oncelik: Minor]  ([01 §3.3.3](./01-react-code-review.md#s-333-custom-hook-tasarimi))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ ayni localStorage useState+useEffect blogu iki bilesende kopyalanmis\n  const [v, setV] = useState(() => JSON.parse(localStorage.getItem('k') ?? 'null'));\n  useEffect(() => { localStorage.setItem('k', JSON.stringify(v)); }, [v]);\n  // ✅ tek custom hook'a cikar (useCallback'li setValue, referans kararli)\n  const [v, setV] = useLocalStorage<MyType>('k', initial);\n  ```\n  </details>\n- [ ] Custom hook'ta hatayi yutmadan, throw new Error(msg, { cause: error }) ile orijinal hatayi gecirmekten **emin ol**  — tani kaybi (S2737)  [Oncelik: Minor]  ([01 §3.3.4 / AP-9](./01-react-code-review.md#s-334-custom-hookta-hata-yutma)) Yasak: /catch\\s*(\\([^)]*\\))?\\s*\\{\\s*\\}/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ orijinal hata yutulur (cause kaybi)\n  catch (error) { throw new Error('Kamu arama işlemi başarısız oldu'); }\n  // ✅ orijinal hata cause ile gecirilir\n  catch (error) { throw new Error('Kamu arama işlemi başarısız oldu', { cause: error }); }\n  ```\n  </details>\n\n## 4. Performans\n\n- [ ] Pahali liste donusumu (.map/.filter zinciri) icin useMemo **kullan**; her render'da yeniden hesaplanmasin  [Oncelik: Major]  ([01 §3.4.1](./01-react-code-review.md#s-341-usememo--usecallback--dogru-yerde-dogru-bagimlilikla)) Yasak: /=\\s*\\w+[?.]*\\.(filter|map)\\([^)]*\\)\\s*\\.(map|filter|sort|reduce)\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ her render'da pahali zincir yeniden hesaplanir\n  const flatItems = flatten(filteredTree, expandedIds);\n  // ✅ useMemo ile bagimliliklara baglanir\n  const flatItems = useMemo(() => flatten(filteredTree, expandedIds), [filteredTree, expandedIds]);\n  ```\n  </details>\n- [ ] Handler'i useCallback, value'yu useMemo ile sabitleyerek memo'lu cocuga / Context Provider value'ya inline ()=>{}/{...}/[...] gecmekten **kacin**  — yeni referans memo'yu etkisiz kilar, tum tuketiciler re-render olur  [Oncelik: Major]  ([01 §3.4.1 / §3.4.5 / AP-7](./01-react-code-review.md#s-341-usememo--usecallback--dogru-yerde-dogru-bagimlilikla)) Yasak: /Provider\\s+value=\\{\\{/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ inline value/fn -> her render yeni referans -> tum tuketiciler re-render\n  <TreeContext.Provider value={{ selectedId, onToggle: (id) => setSel(id) }}>\n  // ✅ useMemo value + useCallback handler ile referans kararli\n  const onToggle = useCallback((id: string) => setSel(id), []);\n  const value = useMemo(() => ({ selectedId, onToggle }), [selectedId, onToggle]);\n  <TreeContext.Provider value={value}>\n  ```\n  </details>\n- [ ] Sik render edilen liste/agac satirini React.memo ile sar (TreeNodeRow deseni); asiri useMemo'dan (ilkel-aritmetik) **kacin**  [Oncelik: Minor]  ([01 §3.4.2](./01-react-code-review.md#s-342-reactmemo-ile-saf-bilesen)) Yasak: /useMemo\\(\\s*\\(\\s*\\)\\s*=>\\s*[\\w.]+\\s*[-+*\\/]\\s*[\\w.]+\\s*,/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ sik render edilen satir bileseni memo'suz\n  function TreeNodeRow({ node, style }) { /* satir render */ }\n  // ✅ React.memo ile sar (prop degismedikce render atlanir)\n  const TreeNodeRow = memo(function TreeNodeRow({ node, style }) { /* satir render */ });\n  ```\n  </details>\n- [ ] Yuzlerce+ satirli liste/agaci react-window ile sanallastir; islem-yonetimi-web v2 List (rowComponent/rowProps) API'sini, eski FixedSizeList ile karistirmaktan **kacin**  [Oncelik: Major]  ([01 §3.4.3](./01-react-code-review.md#s-343-sanallastirma-react-window)) Yasak: /FixedSizeList/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ binlerce satir DOM'a tam basilir\n  {flatItems.map((item) => <TreeNodeRow key={item.id} node={item} />)}\n  // ✅ react-window v2 List ile sanallastir\n  <List<TreeRowProps> rowComponent={TreeNodeRow} rowCount={flatItems.length}\n    rowHeight={ROW_HEIGHT} rowProps={rowProps} />\n  ```\n  </details>\n- [ ] Agir/nadiren acilan ekrani (BPMN/DMN/Monaco/PDF), ana bundle'a statik baglamadan, React.lazy + <Suspense> ile ayri chunk'a **bol**  [Oncelik: Minor]  ([01 §3.4.4](./01-react-code-review.md#s-344-kod-bolme-lazy--suspense)) Yasak: /from\\s+[\"\\']\\s*(bpmn-js|dmn-js|monaco-editor|@monaco-editor|react-pdf|pdfjs-dist)/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ agir editor ana bundle'a statik bagli\n  import BpmnEditor from './features/islem-bpmn/BpmnEditor';\n  // ✅ lazy + Suspense ile ayri chunk\n  const BpmnEditor = React.lazy(() => import('./features/islem-bpmn/BpmnEditor'));\n  <Suspense fallback={<GolgeLoader />}><BpmnEditor /></Suspense>\n  ```\n  </details>\n- [ ] useRef(debounce(...)).current ile stale-closure debounce yerine useMemo(()=>debounce(...),[deps]) + unmount'ta .cancel() **kullan**  [Oncelik: Minor]  ([01 AP-10](./01-react-code-review.md#ap-10--useref-ile-yaratilan-debounceun-stale-closurei)) Yasak: /useRef\\(\\s*debounce\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ useRef ilk render closure'unu kalici yakalar (stale)\n  const debounced = useRef(debounce(performSearch, 300)).current;\n  // ✅ useMemo ile bagimliliklara bagli; unmount'ta cancel\n  const debounced = useMemo(() => debounce(performSearch, 300), [performSearch]);\n  useEffect(() => () => debounced.cancel(), [debounced]);\n  ```\n  </details>\n\n## 5. Okunabilirlik\n\n- [ ] Render basinda erken donus (guard) kullan; JSX'te 3+ kademeli ic-ice ternary'den **kacin**  [Oncelik: Minor]  ([01 §3.5.3](./01-react-code-review.md#s-353-erken-donus-early-return--jsx-sadeligi)) Yasak: /\\?[^?:]{1,80}\\?[^?:]{1,80}\\?/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ ic-ice ternary ile render\n  return yetkiliKullanici === false ? <Unauthorized /> : loading ? <Loader /> : <Icerik />;\n  // ✅ erken donus (guard) ile sadelik\n  if (yetkiliKullanici === false) return <UnauthorizedScreen />;\n  if (loading) return <Loader />;\n  return <Icerik />;\n  ```\n  </details>\n- [ ] Kaynak kodda dogrudan `console.*` yerine merkezi `logger` (`utils/logger.ts`, sadece `import.meta.env.DEV`) veya notistack middleware **kullan**  — `no-console: warn`  [Oncelik: Minor]  ([01 §3.5.4](./01-react-code-review.md#s-354-console-yerine-merkezi-logger))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ dogrudan console (no-console: warn, uretimde sizinti)\n  console.error('Kisi yuklenemedi', error);\n  // ✅ merkezi logger (sadece import.meta.env.DEV'de loglar)\n  import { logger } from '../utils/logger';\n  logger.error('Kisi yuklenemedi', error);\n  ```\n  </details>\n- [ ] Sabit kodlu URL/ortam degeri yerine .env (VITE_REACT_APP_*) uzerinden cozulen degerleri **kullan**  — ortamlar arasi tasinabilirlik (S1075)  [Oncelik: Major]  ([01 §3.5.5](./01-react-code-review.md#s-355-sabit-kodlu-urldeger)) Yasak: /[\"\\']https?:\\/\\/[a-zA-Z0-9.-]+/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ sabit kodlu URL (S1075, ortamlar arasi tasinmaz)\n  const TIP_DEGER_VARLIK_API_URL = 'https://test.test.com.tr/tipdeger/api';\n  // ✅ .env'den coz (VITE_REACT_APP_*)\n  const TIP_DEGER_VARLIK_API_URL = env.envTipdegerVarlikApiUrl;\n  ```\n  </details>\n- [ ] Kullanilmayan import/degisken/eslint-disable'i ve gereksiz disable'i **kaldir**  — --report-unused-disable-directives + max-warnings 0  [Oncelik: Major]  ([01 §3.5.1 / AP-8](./01-react-code-review.md#s-351-eslint---max-warnings-0--uyarisiz-birlestirme)) Yasak: /eslint-disable-next-line/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ uyariyi gizleyen disable + kullanilmayan import\n  import { useMemo, useRef } from 'react'; // useRef kullanilmiyor\n  // eslint-disable-next-line @typescript-eslint/no-explicit-any\n  const x: any = veri;\n  // ✅ kok-nedeni gider, gereksiz import/disable'i kaldir\n  import { useMemo } from 'react';\n  const x: VarlikDto = veri;\n  ```\n  </details>\n\n## 6. Tekrar kullanilabilirlik\n\n- [ ] golge-ui karsiligi varken yeniden yazmaktan **kacin**: modal/snackbar/api-client/tema/CRUD tablo-form (GolgeModal, enqueueSnackbar, GolgeApi, GolgeThemeProvider, GolgeTable/GolgeEntityForm/GolgeFilterForm/GolgeCrudLayout)  — el yapimi kopya tutarsizlik + bakim yuku  [Oncelik: Major]  ([01 §3.6.1](./01-react-code-review.md#s-361-golge-ui-bilesenlerini-once-kullan) / [04 §B.1](./04-golge-framework-frontend.md#review-kontrolleri-b1)) Yasak: /<Dialog[\\s>]/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ CRUD tablo/form elle MUI ile sifirdan yazilmis\n  <Table>{rows.map((r) => <TableRow>...</TableRow>)}</Table> /* + el yapimi form/filtre */\n  // ✅ golge-ui CRUD bilesenleri\n  import { GolgeTable, GolgeEntityForm, GolgeFilterForm } from 'golge-ui';\n  <GolgeCrudLayout table={<GolgeTable ... />} form={<GolgeEntityForm ... />} />\n  ```\n  </details>\n- [ ] portal-ui/tapu-ui'de domain-genel bilesen varsa onu, ozel bileseni ise yalniz paylasilamaz domain UI icin ve golge `base`/tema primitifleri uzerine kurulu olacak sekilde **kullan**  [Oncelik: Minor]  ([04 §B.1](./04-golge-framework-frontend.md#golge-ui-mi-ozel-bilesen-mi--portal-uitapu-ui))\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ portal-genel bilesen yeniden yazilmis\n  function PortalUserCard({ user }) { /* el yapimi */ }\n  // ✅ portal-ui'deki paylasilan bileseni kullan; ozel ise golge base uzerine kur\n  import { PortalUserCard } from 'portal-ui';\n  import { GolgeCard } from 'golge-ui'; // ozel bilesen tabani\n  ```\n  </details>\n- [ ] Tekrar eden donusum/handler'i ortak yardimciya **cikar**: zarf donusumu (content/totalElements -> liste/kayitSayisi) toListeResponse'a, 404->snackbar interceptor'a; kardes apiSlice'lar injectEndpoints'e  — tek-nokta-degisim; tekrar sayisini PR aciklamasinda belirt  [Oncelik: Major]  ([01 §3.6.2 / AP-5](./01-react-code-review.md#s-362-kopyalama-karsiti-tekrar-eden-donusumhandleri-ortak-yardimciya-cikar)) Yasak: /(liste|kayitSayisi)\\s*:\\s*[\\w.?]*\\.(content|totalElements)/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ ayni zarf donusumu 6+ serviste kopyalanmis\n  const { content, totalElements, totalPages, number } = res.data;\n  return { liste: content, kayitSayisi: totalElements, sayfaSayisi: totalPages, sayfaNo: number };\n  // ✅ ortak yardimciya cikar (tek-nokta-degisim)\n  const toListeResponse = (p) => ({ liste: p.content, kayitSayisi: p.totalElements, sayfaSayisi: p.totalPages, sayfaNo: p.number });\n  ```\n  </details>\n- [ ] Cross-domain mantigi, feature icinde cogaltmadan, dogru konuma (islem-yonetimi-web shared/{hooks,lib,types}, taraf-web hooks/utils) **tasi**  [Oncelik: Minor]  ([01 §3.6.4](./01-react-code-review.md#s-364-paylasilan-hooklib-konumu)) Yasak: /from\\s+[\"\\']\\.\\.\\/\\.\\.\\/(features|modules)\\//\n- [ ] 6+ boolean prop / 3+ seviye prop-drilling yerine kompozisyon/Context (TreeContext deseni) **kullan**  [Oncelik: Minor]  ([01 §3.6.3](./01-react-code-review.md#s-363-propkompozisyon-tasarimi)) Yasak: /(\\s\\w+=\\{(true|false)\\}){4,}/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ cok sayida boolean prop + derin prop-drilling\n  <TreeNode selectedId={selectedId} expandedIds={expandedIds} onToggle={onToggle} showIcon hasChildren isLeaf disabled />\n  // ✅ paylasilan durumu Context'e tasi\n  const { selectedId, onToggle } = useContext(TreeContext);\n  <TreeNode node={node} />\n  ```\n  </details>\n\n## 7. TypeScript tipleme\n\n- [ ] `: any`/`as any`/`Promise<any>` yerine, gerekiyorsa `unknown` + tip-daraltma (`lowercaseKeys(obj: unknown)` deseni) **kullan**  — `no-explicit-any: warn` + `max-warnings 0`  [Oncelik: Major]  ([01 §3.5.2 / AP-3](./01-react-code-review.md#s-352-any-yasagi-ve-ts-strict))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ any tip guvenligini kaldirir\n  function lowercaseKeys(obj: any) { return Object.keys(obj)...; }\n  // ✅ unknown + tip-daraltma\n  function lowercaseKeys(obj: unknown) {\n    if (obj === null || typeof obj !== 'object') return obj;\n    return Object.keys(obj as Record<string, unknown>)...;\n  }\n  ```\n  </details>\n- [ ] `transformResponse`/Context tipleri icin somut interface **kullan** (`response: any` -> `VarlikPageResponse`; `kisi: any` -> `GercekKisiDto | null`)  [Oncelik: Major]  ([01 §3.5.2 / AP-3](./01-react-code-review.md#s-352-any-yasagi-ve-ts-strict))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ transformResponse/Context any\n  transformResponse: (response: any) => ({ tipVarlikListe: response?.content ?? [] });\n  // ✅ somut interface\n  interface VarlikPageResponse { content: VarlikDto[] }\n  transformResponse: (r: VarlikPageResponse) => ({ tipVarlikListe: r?.content ?? [] });\n  ```\n  </details>\n- [ ] Frontend DTO/sayfalama tiplerinin backend `client` modulu DTO'lariyla uyumlu oldugundan (zarf `content/totalElements` <-> Spring `Page`) **emin ol**  — kontrat tutarliligi  [Oncelik: Major]  ([01 §6 capraz dokuman](./01-react-code-review.md#6-ilgili-dosyalar--capraz-linkler))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ frontend tip backend Page zarfiyla uyumsuz\n  interface VarlikPageResponse { items: VarlikDto[]; total: number; }\n  // ✅ Spring Page alan adlariyla birebir\n  interface VarlikPageResponse { content: VarlikDto[]; totalElements: number; totalPages: number; number: number; }\n  ```\n  </details>\n- [ ] tsc'nin temiz oldugundan; strict/noUnusedLocals/noUnusedParameters/noFallthroughCasesInSwitch ihlali OLMADIGINDAN **emin ol**  [Oncelik: Major]  ([01 §3.5.2](./01-react-code-review.md#s-352-any-yasagi-ve-ts-strict)) Yasak: /@ts-(ignore|nocheck|expect-error)/\n  <details><summary>↳ örnek</summary>\n\n  ```json\n  // ✅ tsconfig.json — zorunlu strict bayraklar (ihlal = tsc kirmizi)\n  \"compilerOptions\": {\n    \"strict\": true,\n    \"noUnusedLocals\": true,\n    \"noUnusedParameters\": true,\n    \"noFallthroughCasesInSwitch\": true\n  }\n  ```\n  </details>\n\n## 8. golge-ui & Module Federation (singleton/surum)\n\n- [ ] Yeni remote shared blogunda cekirdek bagimliliklarin singleton+eager oldugundan **emin ol**: react, react-dom, react-router-dom, @mui/*, golge-ui, portal-ui*  — eksikse \"Invalid hook call\"/cift tema/bozuk auth  [Oncelik: Blocker]  ([04 §B.2](./04-golge-framework-frontend.md#review-kontrolleri-b2)) Yasak: /singleton\\s*:\\s*false/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ cekirdek bagimliliklar shared'da degil (cift React -> Invalid hook call)\n  shared: { react: {} }\n  // ✅ cekirdek bagimliliklar singleton + eager\n  shared: {\n    react:            { singleton: true, eager: true },\n    'react-dom':      { singleton: true, eager: true },\n    'react-router-dom': { singleton: true, eager: true },\n    '@mui/material':  { singleton: true, eager: true },\n    'golge-ui':       { singleton: true, eager: true, version: false, requiredVersion: false },\n  }\n  ```\n  </details>\n- [ ] Remote redux store/redux'i gercekten paylasiyorsa @reduxjs/toolkit+react-redux singleton'inin eksiksiz oldugundan (shell/zeminsorgu paylasir, taraf-web paylasmaz) ve shared blok farkliliklarinin **kasitli** oldugundan **emin ol**  — yoksa cift store  [Oncelik: Major]  ([04 §B.2](./04-golge-framework-frontend.md#shared--singleton-bagimliliklar)) Yasak: /[\"\\']\\s*(@reduxjs\\/toolkit|react-redux)[\"\\']\\s*:\\s*\\{(?:(?!singleton)[^}])*\\}/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ shell store'unu paylasan remote'ta sadece toolkit var, react-redux eksik -> cift store\n  shared: { '@reduxjs/toolkit': { singleton: true, eager: true } }\n  // ✅ store paylasiliyorsa ikisi de singleton (taraf-web paylasmiyorsa hicbiri olmaz — kasitli)\n  shared: {\n    '@reduxjs/toolkit': { singleton: true, eager: true },\n    'react-redux':      { singleton: true, eager: true },\n  }\n  ```\n  </details>\n- [ ] React/React-DOM/MUI/golge-ui surumlerinin remote ile shell arasinda **major** farkli OLMADIGINDAN ve golge-ui'nin 1.16.x'e cekildiginden (hala ^1.0.x/^1.2.x kullanan repo var) **emin ol**  — singleton tek surum yukleyince digeri kirilir  [Oncelik: Blocker]  ([04 §B.2 golge-ui surum uyumu](./04-golge-framework-frontend.md#golge-ui-surum-uyumu-risk)) Yasak: /[\"\\']golge-ui[\"\\']\\s*:\\s*[\"\\'][\\^~]?1\\.([0-9]|1[0-5])\\./\n  <details><summary>↳ örnek</summary>\n\n  ```json\n  // ❌ package.json — eski major (singleton 1.16.x yuklenince kayip export/API)\n  \"golge-ui\": \"^1.2.0\"\n  // ✅ tum repolar 1.16.x'e hizali\n  \"golge-ui\": \"1.16.10\"\n  ```\n  </details>\n- [ ] golge-ui/portal-ui* icin shared'da version: false, requiredVersion: false **kullan**  — surum uyumsuzlugunda hard-fail yerine tek instance zorlanir  [Oncelik: Minor]  ([04 §B.2](./04-golge-framework-frontend.md#shared--singleton-bagimliliklar)) Yasak: /[\"\\']golge-ui[\"\\']\\s*:\\s*\\{[^}]*requiredVersion\\s*:\\s*[\"\\']/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ surum uyumsuzlugunda hard-fail\n  'golge-ui': { singleton: true, eager: true }\n  // ✅ version: false ile tek instance zorlanir (hard-fail yok)\n  'golge-ui': { singleton: true, eager: true, version: false, requiredVersion: false }\n  ```\n  </details>\n- [ ] `dedupe`/`optimizeDeps.dedupe` listesinin standart (`react`, `react-dom`, `react-router-dom`, `@remix-run/router`, `@mui/*`, `@emotion/*`, `golge-ui`) ve remote'lar arasi tutarli oldugundan **emin ol**  — dev'de cift kopya onlenir  [Oncelik: Major]  ([04 §B.2 dedupe](./04-golge-framework-frontend.md#shared--singleton-bagimliliklar))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ dedupe listesi eksik -> dev'de cift kopya\n  resolve: { dedupe: ['react', 'react-dom'] }\n  // ✅ standart listenin tamami, remote'lar arasi tutarli\n  resolve: { dedupe: ['react', 'react-dom', 'react-router-dom', '@remix-run/router', '@mui/material', '@emotion/react', 'golge-ui'] }\n  ```\n  </details>\n- [ ] Remote'un kendi react-router'ini izole yuklemediginden (singleton) ve navigasyonun shell router context'inden kopmadigindan **emin ol**  [Oncelik: Major]  ([04 §B.2](./04-golge-framework-frontend.md#review-kontrolleri-b2)) Yasak: /[\"\\']react-router-dom[\"\\']\\s*:\\s*\\{(?:(?!singleton)[^}])*\\}/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ react-router-dom shared'da singleton degil -> izole router, navigasyon kopar\n  shared: { react: { singleton: true, eager: true } }\n  // ✅ react-router-dom singleton -> tek router context, shell ile baglanir\n  shared: {\n    react:              { singleton: true, eager: true },\n    'react-router-dom': { singleton: true, eager: true },\n  }\n  ```\n  </details>\n- [ ] Iki remote'ta ayni `name`/`remoteEntry.js` cakismasi OLMADIGINDAN ve `GolgeVitePlugin()` gerekliliginden **emin ol**  [Oncelik: Minor]  ([04 §B.2](./04-golge-framework-frontend.md#review-kontrolleri-b2))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ baska remote ile cakisan name + golge plugin yok\n  federation({ name: 'tarafApp', filename: 'remoteEntry.js', exposes: { ... } })\n  // ✅ benzersiz name + GolgeVitePlugin\n  plugins: [GolgeVitePlugin(), federation({ name: 'immovable_property_processes', filename: 'remoteEntry.js', exposes: { ... } })]\n  ```\n  </details>\n\n## 9. Form & dogrulama\n\n- [ ] Form alanlarini, global Redux store'a koymadan ekran-lokal useState/useReducer'da; submit'te ise RTK Query mutation/axios servisini **kullan**  [Oncelik: Minor]  ([01 §3.11.3](./01-react-code-review.md#s-3113-form-statei-lokal-tut)) Yasak: /dispatch\\(\\s*set(Form|Field)[A-Za-z]*\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ form alani global Redux store'da\n  const ad = useAppSelector((s) => s.form.ad);\n  dispatch(setFormAd(e.target.value));\n  // ✅ form lokal state; submit'te mutation\n  const [ad, setAd] = useState('');\n  const [ekleKisi] = useEkleKisiMutation();\n  const submit = () => ekleKisi({ ad });\n  ```\n  </details>\n- [ ] Sabit-format alanlari (11 hane TC, telefon, vergi no) maskele; serbest TextField + manuel replace/slice tekrari yerine (react-imask/libphonenumber-js) **kullan**  [Oncelik: Minor]  ([01 §3.11.1](./01-react-code-review.md#s-3111-maskelenmis-girdi-tc-kimlik-telefon-vergi-no)) Yasak: /\\.replace\\(\\/\\\\D\\/g/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ serbest TextField + elle replace/slice ile maskeleme\n  <TextField value={tc} onChange={(e) => setTc(e.target.value.replace(/\\D/g, '').slice(0, 11))} />\n  // ✅ maske bileseni (react-imask)\n  const TcMask = React.forwardRef((props, ref) => <IMaskInput {...props} mask=\"00000000000\" inputRef={ref} unmask />);\n  <TextField name=\"tcKimlikNo\" InputProps={{ inputComponent: TcMask }} />\n  ```\n  </details>\n- [ ] Istemci dogrulamasi olsa da kritik akista yalniz ona guvenme; **backend tek gercek kaynak** olsun (golge `*Constraint` + jakarta `@Valid`), hata zarfini (`message`/`error`) kullaniciya gosterdiginden **emin ol**  [Oncelik: Major]  ([01 §3.11.2](./01-react-code-review.md#s-3112-dogrulama-ve-gonderim))\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ yalniz istemci dogrulamasina guven; backend hatasi yutulur\n  if (!tcGecerli(tc)) return; await ekleKisi({ tc }).unwrap();\n  // ✅ backend hata zarfini (message/error) kullaniciya goster\n  try { await ekleKisi({ tc }).unwrap(); }\n  catch (e) { enqueueSnackbar((e as { data?: { message?: string } }).data?.message, { variant: 'error' }); }\n  ```\n  </details>\n\n## 10. i18n (yalniz `islem-yonetimi-web`)\n\n- [ ] i18n kullanan feature'da sabit string yerine const {t}=useTranslation('namespace'); t('anahtar') **kullan**  [Oncelik: Major]  ([01 §3.12.1](./01-react-code-review.md#s-3121-namespaceli-feature-bazli-kurulum)) Yasak: /(label|placeholder)=\"[A-Za-z]{4,}/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ sabit string (i18n kullanan feature'da)\n  <Button>Kaydet</Button>\n  // ✅ namespace'li t()\n  const { t } = useTranslation('kuralMotoru');\n  <Button>{t('kaydet')}</Button>\n  ```\n  </details>\n- [ ] Yeni metin icin hem `tr` hem `en` dosyasina, eksik birakmadan ve `fallbackLng: 'tr'` mevcutken, anahtar **ekle**  [Oncelik: Major]  ([01 §3.12.1](./01-react-code-review.md#s-3121-namespaceli-feature-bazli-kurulum))\n  <details><summary>↳ örnek</summary>\n\n  ```json\n  // ❌ anahtar yalniz tr/kuralMotoru.json'da, en eksik\n  { \"kaydet\": \"Kaydet\" }\n  // ✅ hem tr hem en dosyasina ekle\n  // tr/kuralMotoru.json: { \"kaydet\": \"Kaydet\" }\n  // en/kuralMotoru.json: { \"kaydet\": \"Save\" }\n  ```\n  </details>\n- [ ] Cevirileri, tek dev sozluk yerine feature namespace'ine (ns/defaultNS) **bol**  [Oncelik: Minor]  ([01 §3.12.1](./01-react-code-review.md#s-3121-namespaceli-feature-bazli-kurulum)) Yasak: /useTranslation\\(\\s*\\)/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ tek dev sozluk (namespace yok)\n  i18n.init({ resources: { tr: { translation: tumCeviriler } } });\n  // ✅ feature namespace'ine bol\n  i18n.init({ resources: { tr: { kuralMotoru: tr }, en: { kuralMotoru: en } },\n    ns: ['kuralMotoru'], defaultNS: 'kuralMotoru', fallbackLng: 'tr' });\n  ```\n  </details>\n\n## 11. Erisilebilirlik\n\n- [ ] Etkilesimli <div onClick> yerine MUI bilesenini (IconButton/Button); ham div ise tabIndex={0}+onKeyDown+role ve :focus-visible **kullan**  [Oncelik: Major]  ([01 §3.13.1](./01-react-code-review.md#s-3131-klavye-erisimi-ve-odak)) Yasak: /<div[^>]*onClick=/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ etkilesimli div, klavyeyle erisilemez\n  <div onClick={onSec}>Sec</div>\n  // ✅ MUI bileseni (klavye/odak hazir)\n  <Button onClick={onSec}>Sec</Button>\n  // ham div sart ise: <div role=\"button\" tabIndex={0} onClick={onSec} onKeyDown={...} />\n  ```\n  </details>\n- [ ] Sadece-ikon buton icin aria-label/Tooltip; TextField icin label/aria-label **ekle**  [Oncelik: Minor]  ([01 §3.13.2](./01-react-code-review.md#s-3132-etiket-ve-metin-alternatifleri)) Yasak: /<IconButton(?:(?!aria-label)[^>])*>/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ ikon buton etiketsiz (ekran okuyucu okuyamaz)\n  <IconButton onClick={sil}><DeleteIcon /></IconButton>\n  // ✅ Tooltip + aria-label\n  <Tooltip title=\"Sil\"><IconButton aria-label=\"Sil\" onClick={sil}><DeleteIcon /></IconButton></Tooltip>\n  ```\n  </details>\n- [ ] Modal odak yonetiminde acilinca odagin icine, kapaninca tetikleyiciye dondugunden (GolgeModal yonetir; ozel modalda davranis korunmus olmali) **emin ol**  [Oncelik: Minor]  ([01 §3.13.3](./01-react-code-review.md#s-3133-modal-odak-yonetimi)) Yasak: /disable(AutoFocus|EnforceFocus|RestoreFocus)/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ el yapimi overlay; odak tuzaklamasi/geri donus yok\n  {open && <div className=\"overlay\"><div className=\"dialog\">{children}</div></div>}\n  // ✅ GolgeModal odagi yonetir (acilinca ice, kapaninca tetikleyiciye)\n  <GolgeModal open={open} onClose={onClose}>{children}</GolgeModal>\n  ```\n  </details>\n\n## 12. Guvenlik (XSS / token)\n\n- [ ] Token'i elle localStorage/cookie'den okumaktan veya prop olarak gecmekten kacin; useGolgeSecurity().getToken() / golgeRtkApiHeaders / getShellAuthToken() standardini **kullan**  [Oncelik: Blocker]  ([04 §B.1 / §B.2](./04-golge-framework-frontend.md#review-kontrolleri-b1)) Yasak: /(localStorage|sessionStorage)\\.(get|set)Item\\(\\s*[\"\\'][^\"\\']*[Tt]oken/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ token elle localStorage'dan / prop olarak\n  const token = localStorage.getItem('access_token');\n  // ✅ golge guvenlik standardi\n  const token = await useGolgeSecurity().getToken(); // veya getShellAuthToken()\n  ```\n  </details>\n- [ ] apiSlice'ta prepareHeaders: golgeRtkApiHeaders kullan; elle Authorization header eklemekten **kacin**  — auth propagasyonu zorunlu  [Oncelik: Major]  ([01 §3.9.1](./01-react-code-review.md#s-391-standart-slice-kurulumu)) Yasak: /[\"\\']?Authorization[\"\\']?\\s*\\]?\\s*[:=]\\s*\\S/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ elle Authorization header\n  baseQuery: fetchBaseQuery({ baseUrl, prepareHeaders: (h) => { h.set('Authorization', `Bearer ${token}`); return h; } })\n  // ✅ golgeRtkApiHeaders ile otomatik auth propagasyonu\n  baseQuery: fetchBaseQuery({ baseUrl, prepareHeaders: golgeRtkApiHeaders })\n  ```\n  </details>\n- [ ] axios serviste header'i elle eklemekten ve fazla Accept/Content-Type'tan kacin; tekil tarafClient (auth/401/403/500 interceptor) uzerinden **kullan**  [Oncelik: Major]  ([01 §3.8.1-3.8.2](./01-react-code-review.md#s-381-merkezi-client-factory--interceptor)) Yasak: /axios\\.(get|post|put|patch|delete)\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ her cagrida elle header + ham axios\n  axios.get(url, { headers: { Accept: 'application/json', 'Content-Type': 'application/json', Authorization: `Bearer ${token}` } });\n  // ✅ tekil tarafClient (header + interceptor merkezi)\n  tarafClient.get(url);\n  ```\n  </details>\n- [ ] Korumali rotada useGolgeSecurity().hasAuthority(...) kullan; hasAuthority **async** oldugu icin yetki cozulmeden rota render etmekten kacin (yetkiliKullanici/routesReady guard); rol kodunu Permission sabitinde (backend IY_*/KDS_* ile uyumlu) **belirt**  [Oncelik: Blocker]  ([01 §3.7.2](./01-react-code-review.md#s-372-korumali-rota-yetki-deseni)) Yasak: /(?<!await\\s)hasAuthority\\([^)]*\\)\\s*(&&|\\?)/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ async hasAuthority cozulmeden rota render edilir (yetkisiz ekran gorunur)\n  if (hasAuthority(Permission.IY_GORUNTULE)) return <Routes>...</Routes>;\n  // ✅ yetki cozulene kadar guard (routesReady / yetkiliKullanici)\n  useEffect(() => { hasAuthority(Permission.IY_GORUNTULE).then(setYetkiliKullanici); }, [hasAuthority]);\n  if (yetkiliKullanici === false) return <UnauthorizedScreen />;\n  ```\n  </details>\n- [ ] Ham HTML enjeksiyonundan kacin: dangerouslySetInnerHTML kullanildiysa girdiyi sanitize ettiginden **emin ol**  — XSS  [Oncelik: Blocker] Yasak: /dangerouslySetInnerHTML/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ sanitize edilmemis ham HTML (XSS)\n  <div dangerouslySetInnerHTML={{ __html: aciklama }} />\n  // ✅ sanitize edilmis (mumkunse dangerouslySetInnerHTML'den tamamen kacin)\n  <div dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(aciklama) }} />\n  ```\n  </details>\n- [ ] react-router-dom'u tek kaynaktan (dogrudan veya golge-ui/router re-export) import et; iki kaynak karistirmaktan **kacin**  [Oncelik: Minor]  ([01 §3.7.1](./01-react-code-review.md#s-371-standart-yerlesim)) Yasak: /from\\s+[\"\\']react-router[\"\\']/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ ayni dosyada iki kaynak karistirilmis\n  import { useNavigate } from 'react-router-dom';\n  import { Routes } from 'golge-ui/router';\n  // ✅ tek kaynaktan\n  import { useNavigate, Routes } from 'golge-ui/router';\n  ```\n  </details>\n\n## 13. RTK Query & axios (veri katmani)\n\n- [ ] query vs mutation secimini dogru yaparak (salt-okumayi mutation yapmadan) salt-okuma icin builder.query+providesTags, yazma icin builder.mutation+invalidatesTags **kullan**  [Oncelik: Major]  ([01 §3.9.3 / AP-4](./01-react-code-review.md#s-393-query-vs-mutation-dogru-secimi)) Yasak: /mutation\\(\\{[^}]*method:\\s*[\"\\']GET/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ salt-okuma mutation ile (cache devre disi, gereksiz tekrar istek)\n  fetchTuzelKisiBilgileri: builder.mutation({ query: (b) => ({ url: '/mersis/...', method: 'POST', body: b }) })\n  // ✅ salt-okuma query + providesTags\n  getTuzelKisiBilgileri: builder.query({ query: (id) => `/mersis/${id}`, providesTags: ['TuzelKisi'] })\n  ```\n  </details>\n- [ ] Her `createApi` icin store'a hem `[x.reducerPath]: x.reducer` hem `.concat(x.middleware)`'i **ekle**  — eksik middleware cache/invalidation'i bozar  [Oncelik: Blocker]  ([01 §3.9.5](./01-react-code-review.md#s-395-store-kaydi-tamlik-kontrolu))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ reducer eklenmis ama middleware eksik (cache/invalidation bozulur)\n  reducer: { [varlikApi.reducerPath]: varlikApi.reducer },\n  middleware: (gDM) => gDM(),\n  // ✅ hem reducer hem middleware\n  reducer: { [varlikApi.reducerPath]: varlikApi.reducer },\n  middleware: (gDM) => gDM().concat(varlikApi.middleware),\n  ```\n  </details>\n- [ ] Kardes endpoint'ler icin ayri createApi yerine tek API + injectEndpoints ile genisletmeyi **kullan**  — ayri reducerPath/middleware store'u sisirir  [Oncelik: Major]  ([01 §3.9.2](./01-react-code-review.md#s-392-injectendpoints-ile-tek-api-genisletme-cogalmayi-onle)) Yasak: /=\\s*createApi\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ kardes endpoint'ler icin ayri createApi (ayri reducerPath/middleware)\n  export const varlikApiSlice = createApi({ reducerPath: 'varlikApi', baseQuery, endpoints: ... });\n  export const degerApiSlice = createApi({ reducerPath: 'degerApi', baseQuery, endpoints: ... });\n  // ✅ tek API + injectEndpoints\n  export const varlikApiSlice = tipDegerVarlikApi.injectEndpoints({ endpoints: (builder) => ({ ... }) });\n  ```\n  </details>\n- [ ] Gereksiz tag invalidation'dan (cift-render) kacin; lossy transformResponse'un (lowercaseKeys) tip tanimlariyla tutarli oldugundan **emin ol**  [Oncelik: Minor]  ([01 §3.9.4](./01-react-code-review.md#s-394-transformresponse-ve-tagleme)) Yasak: /lowercaseKeys/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ lossy transformResponse ama tip backend zarfina gore yazilmis (uyumsuz)\n  transformResponse: (r) => lowercaseKeys(r) as IslemTanim, // tip { Ad: ... } bekliyor\n  // ✅ tip lowercaseKeys ciktisina gore (gereksiz invalidation yerine lokal guncelleme)\n  interface IslemTanim { ad: string } // lowercase formla tutarli\n  transformResponse: (r: unknown): IslemTanim => lowercaseKeys(r) as IslemTanim,\n  ```\n  </details>\n- [ ] Arama/autocomplete'te `AbortController` ile istek iptali, effect cleanup'ta `.abort()` ve `catch`'te `AbortError` ayiklamasi **kullan**  [Oncelik: Major]  ([01 §3.8.4](./01-react-code-review.md#s-384-istek-iptali-cancellation))\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ iptal yok; eski istek yeni sonucu ezebilir\n  useEffect(() => { fetchOptions(text).then(setSecenekler); }, [text]);\n  // ✅ AbortController + cleanup'ta abort + AbortError ayikla\n  useEffect(() => {\n    const c = new AbortController();\n    fetchOptions(text, c.signal).then(setSecenekler).catch((e) => { if (e.name !== 'AbortError') throw e; });\n    return () => c.abort();\n  }, [text]);\n  ```\n  </details>\n- [ ] 404/genel hatayi, her serviste try/catch + if 404 showSnackBar kopyasindan kacinarak, axios response interceptor veya rtkQueryErrorLogger middleware ile merkezilestirmeyi **kullan**  [Oncelik: Major]  ([01 §3.8.3 / §3.9.6](./01-react-code-review.md#s-383-hata-isleme--tutarli-ve-merkezi)) Yasak: /(status|statusCode)\\s*===?\\s*404/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ her serviste 404 -> snackbar kopyasi\n  catch (error) { if (isAxiosError(error) && error.response?.status === 404) showSnackBar(error.response?.data?.message, TYPE.WARNING); }\n  // ✅ merkezi: axios response interceptor / rtkQueryErrorLogger middleware\n  client.interceptors.response.use((r) => r, (error) => { /* 404/500 tek yerde */ return Promise.reject(error); });\n  ```\n  </details>\n\n## 14. MUI 6 (tema/stil)\n\n- [ ] Tek tema kaynagi olarak GolgeThemeProvider'i (golge-ui/theme) ve tarih lokalizasyonunu (AdapterDayjs, tr/trTR) kullan; ayri createTheme eklemekten **kacin**  [Oncelik: Minor]  ([01 §3.10.1](./01-react-code-review.md#s-3101-tema-saglayicisi-ve-lokalizasyon)) Yasak: /createTheme\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ ayri createTheme + ThemeProvider (golge temasiyla cakisir)\n  <ThemeProvider theme={createTheme({ palette: { mode: 'light' } })}>...</ThemeProvider>\n  // ✅ tek kaynak GolgeThemeProvider + lokalizasyon\n  import { GolgeThemeProvider } from 'golge-ui/theme';\n  <GolgeThemeProvider><LocalizationProvider dateAdapter={AdapterDayjs} adapterLocale=\"tr\">...</LocalizationProvider></GolgeThemeProvider>\n  ```\n  </details>\n- [ ] Tema degeri (theme.spacing(), theme.palette.*, breakpoint objeleri) kullan; tema-disi sabit hex/px gommekten **kacin**  [Oncelik: Minor]  ([01 §3.10.2](./01-react-code-review.md#s-3102-sx-vs-styled-secimi)) Yasak: /(color|backgroundColor|background|border|borderColor)\\s*:\\s*[\"\\']#[0-9a-fA-F]{3,8}[\"\\']/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ tema-disi sabit hex/px\n  <Box sx={{ padding: '16px', color: '#1976d2' }} />\n  // ✅ tema degeri\n  <Box sx={{ p: 2, color: 'primary.main' }} />\n  ```\n  </details>\n- [ ] Basit tek-seferlik stil icin gereksiz styled'tan ve sx={... as any} (CSS var tip kacisi) kullanimindan kacinarak, tekrarlanan sx blogunu styled'a **cikar**  [Oncelik: Minor]  ([01 §3.10.2-3.10.3](./01-react-code-review.md#s-3103-as-any-ile-sx-tip-kacisi)) Yasak: /sx=\\{[^;]*as\\s+any/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ CSS var icin as any ile tip kacisi\n  <Box sx={{ '--header-sub-content-height': h } as any} />\n  // ✅ CSS custom property'i style ile dogru tiple ver\n  <Box style={{ '--header-sub-content-height': h } as React.CSSProperties} />\n  ```\n  </details>\n- [ ] MUI 6 Grid2 API'sini (<Grid size={{xs,md}}>) kullan; eski <Grid item xs> ile karistirmaktan (repo MUI surumune gore) **kacin**  [Oncelik: Minor]  ([01 §3.10.4](./01-react-code-review.md#s-3104-grid2-ve-responsive)) Yasak: /<Grid\\s+item\\b/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ eski Grid API (MUI 6'da deprecated)\n  <Grid item xs={12} md={6}>...</Grid>\n  // ✅ MUI 6 Grid2 API\n  import Grid from '@mui/material/Grid2';\n  <Grid size={{ xs: 12, md: 6 }}>...</Grid>\n  ```\n  </details>\n\n## 15. Test & lint (max-warnings 0)\n\n- [ ] npm run lint'in (eslint . --ext ts,tsx --report-unused-disable-directives --max-warnings 0) temiz oldugundan **emin ol**; yeni uyari = CI kirmizi  [Oncelik: Blocker]  ([01 §3.5.1](./01-react-code-review.md#s-351-eslint---max-warnings-0--uyarisiz-birlestirme)) Yasak: /\\/\\*\\s*eslint-disable\\b/\n  <details><summary>↳ örnek</summary>\n\n  ```bash\n  # ❌ uyari toleransli lint (CI'de gecer ama borc birikir)\n  eslint . --ext ts,tsx\n  # ✅ package.json lint script'i: sifir uyari + olu disable hata\n  eslint . --ext ts,tsx --report-unused-disable-directives --max-warnings 0\n  ```\n  </details>\n- [ ] Hangi ESLint config'in gecerli oldugunu **dogrula**: legacy `.eslintrc.cjs` (taraf-web) vs flat `eslint.config.js` (islem-yonetimi-web)  [Oncelik: Minor]  ([01 §2.1](./01-react-code-review.md#21-teknoloji-yigini-dogrulanmis-surumler))\n- [ ] Aktif kurallarin ihlal edilmediginden **emin ol**: `rules-of-hooks: error`, `exhaustive-deps: warn`, `no-explicit-any: warn`, `no-console: warn` (islem-yonetimi: `prefer-const`/`no-var`/`eqeqeq: error`)  [Oncelik: Major]  ([01 §3.5.1](./01-react-code-review.md#s-351-eslint---max-warnings-0--uyarisiz-birlestirme))\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ kuralin gevsetilmesi/kapatilmasi\n  rules: { 'react-hooks/rules-of-hooks': 'off' }\n  // ✅ aktif kural seti (max-warnings 0 ile warn de kirilir)\n  rules: {\n    'react-hooks/rules-of-hooks': 'error',\n    'react-hooks/exhaustive-deps': 'warn',\n    '@typescript-eslint/no-explicit-any': 'warn',\n    'no-console': 'warn',\n  }\n  ```\n  </details>\n- [ ] Yeni/degisen mantik icin, mevcut testler gecerken, test **ekle**  [Oncelik: Minor]\n\n---\n\n## 16. Guvenlik — Genel Iyi Pratikler (global)\n\n> Platformdaki TUM `<is-alani>-web` repolarina uygulanan, review/CI/config ile dogrulanabilir genel guvenlik kapilari. (Token/auth standardi icin Bolum 12'ye, sanitize edilmis `dangerouslySetInnerHTML` icin yine Bolum 12'ye atif.)\n\n- [ ] eval/new Function(...)/setTimeout('kod-string')/string-setInterval kullanimini **yasakla**; dinamik calistirma yerine veri-yonlu cozum kullan  — ham string yurutme XSS/RCE kapisidir; ESLint no-eval/no-implied-eval/no-new-func ile CI'da dogrulanabilir  [Oncelik: Blocker] Yasak: /(\\beval\\(|new\\s+Function\\(|set(Timeout|Interval)\\(\\s*[\"\\'])/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ kullanici/sunucu verisinden string kod yurutme (no-eval ihlali)\n  const sonuc = eval(entityDto.ifadeMetni);\n  // ✅ guvenli yorumlayici / lookup tablosu (string yurutme yok)\n  const sonuc = ifadeYorumlayici.degerlendir(entityDto.ifadeMetni);\n  ```\n  </details>\n- [ ] DOM API'leri ile ham HTML enjeksiyonundan **kacin**: element.innerHTML = .../outerHTML/document.write/insertAdjacentHTML ile sunucu-veya-kullanici verisi basma; React render veya textContent kullan  — dangerouslySetInnerHTML disinda kalan klasik XSS vektoru  [Oncelik: Blocker] Yasak: /(\\.(innerHTML|outerHTML)\\s*=[^=]|document\\.write\\(|insertAdjacentHTML\\()/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ ham DOM innerHTML ile veri basma (XSS)\n  containerRef.current.innerHTML = entityDto.aciklama;\n  // ✅ React render et veya textContent kullan (HTML yorumlanmaz)\n  containerRef.current.textContent = entityDto.aciklama; // ya da <div>{entityDto.aciklama}</div>\n  ```\n  </details>\n- [ ] Kullanici verisinden gelen href/src URL'lerinde javascript:/data:/vbscript: semasini **engelle**; yalniz http(s)/mailto/tel ve bilinen-iyi listeye izin ver  — <a href={kullaniciUrl}> ile script semasi XSS kapisidir  [Oncelik: Major] Yasak: /(href|src)\\s*=\\s*\\{?\\s*[\"\\']\\s*(javascript|vbscript|data):/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ sema dogrulanmamis href (javascript: -> XSS)\n  <a href={entityDto.disBaglanti}>Detay</a>\n  // ✅ guvenli sema kontrolu\n  const guvenli = /^(https?:|mailto:|tel:)/i.test(url) ? url : '#';\n  <a href={guvenli}>Detay</a>\n  ```\n  </details>\n- [ ] Yeni sekme acan target=\"_blank\" baglantilarda rel=\"noopener noreferrer\" (veya MUI Link) **kullan**  — noopener yoksa hedef sayfa window.opener ile reverse-tabnabbing yapabilir; review/lint (react/jsx-no-target-blank) ile dogrulanabilir  [Oncelik: Major] Yasak: /target=[\"\\']_blank[\"\\']\\s*(?![\\s\\S]*rel=)/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ opener acik birakilir (reverse tabnabbing)\n  <a href={url} target=\"_blank\">Ac</a>\n  // ✅ rel ile opener kapatilir\n  <a href={url} target=\"_blank\" rel=\"noopener noreferrer\">Ac</a>\n  ```\n  </details>\n- [ ] Kullanici-kontrollu redirect/returnUrl/next parametresiyle yonlendirmede acik-yonlendirmeyi (open redirect) **dogrula**: yalniz uygulama-ici goreli yol veya allowlist host'a izin ver  — kontrol edilmemis yonlendirme phishing/token sizdirma kapisidir  [Oncelik: Major] Yasak: /(navigate\\(|location\\.href\\s*=)[^;]*(searchParams\\.get|returnUrl|redirectUrl|redirect_uri)/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ query'den gelen mutlak URL'e dogrudan yonlendirme (open redirect)\n  navigate(searchParams.get('returnUrl')!);\n  // ✅ yalniz goreli ic yol; harici/protokol-goreli reddedilir\n  const hedef = returnUrl?.startsWith('/') && !returnUrl.startsWith('//') ? returnUrl : '/';\n  navigate(hedef);\n  ```\n  </details>\n- [ ] Client bundle'a gizli anahtar/parola/sertifika/private token **koyma**; yalniz public, gizli-olmayan `VITE_*` config degerleri gomulu olsun (Vite `VITE_` disi env'i bundle'a dahil etmez ama gizli degeri `VITE_`'e koymak onu public yapar)  — bundle herkese acik; grep/CI ile dogrulanabilir  [Oncelik: Blocker]\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ gizli anahtar VITE_ ile bundle'a sizar (public olur)\n  const apiKey = import.meta.env.VITE_GIZLI_API_KEY; // tarayicida acik\n  // ✅ yalniz public config; gizli is gateway/BFF tarafinda kalir\n  const apiTabani = import.meta.env.VITE_API_BASE_URL; // gizli degil\n  ```\n  </details>\n- [ ] Kaynak kodda gomulu sirr (token/parola/`Bearer ...`/private key) bulunmadigindan, secret-scan (gitleaks/trufflehog veya CI grep) ile **emin ol**  — sizan sirr geri alinamaz; CI gate ile dogrulanabilir  [Oncelik: Blocker]\n  <details><summary>↳ örnek</summary>\n\n  ```bash\n  # ❌ commit edilmis sirr\n  # const TOKEN = \"eyJhbGciOi...\";\n  # ✅ CI secret-scan gate (PR'i kirar)\n  gitleaks detect --source . --no-banner --redact\n  ```\n  </details>\n- [ ] Bagimlilik CVE'lerini **denetle**: `npm audit --audit-level=high` (veya `--omit=dev` ile prod set) CI'da calissin ve yuksek/kritik aciklarla merge engellensin; lockfile commit'li olsun  — bilinen-acikli paket en yaygin saldiri yuzeyidir  [Oncelik: Major]\n  <details><summary>↳ örnek</summary>\n\n  ```bash\n  # ❌ denetimsiz bagimlilik (bilinen CVE uretime gider)\n  npm ci\n  # ✅ CI gate: yuksek/kritik acik = kirmizi\n  npm ci && npm audit --audit-level=high\n  ```\n  </details>\n- [ ] Uretim build'inde kaynak harita (source map) yayinindan **kacin** veya erisimi kisitla (build.sourcemap: false ya da gizli/yetkili sunum)  — public source map ile tum kaynak ve ic mantik aciga cikar; vite.config ile dogrulanabilir  [Oncelik: Minor] Yasak: /sourcemap\\s*:\\s*true/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ public source map (orijinal kaynak aciga cikar)\n  build: { sourcemap: true }\n  // ✅ uretimde kapali (veya yalniz error-tracking'e gizli yuklenir)\n  build: { sourcemap: false }\n  ```\n  </details>\n- [ ] CSP / guvenli HTTP header'larin (Content-Security-Policy, X-Frame-Options/frame-ancestors, X-Content-Type-Options, Referrer-Policy) gateway/sunum katmaninda tanimli oldugundan **emin ol**; unsafe-inline/unsafe-eval'den kacin  — XSS/clickjacking icin son savunma hatti; gateway config ile dogrulanabilir  [Oncelik: Major] Yasak: /(unsafe-inline|unsafe-eval)/\n  <details><summary>↳ örnek</summary>\n\n  ```yaml\n  # ❌ CSP/güvenlik header yok (XSS/clickjacking acik)\n  # (header tanimsiz)\n  # ✅ gateway/nginx guvenli header seti\n  add_header Content-Security-Policy \"default-src 'self'; object-src 'none'; frame-ancestors 'self'\";\n  add_header X-Content-Type-Options \"nosniff\";\n  add_header Referrer-Policy \"strict-origin-when-cross-origin\";\n  ```\n  </details>\n- [ ] window.addEventListener('message', ...) ile gelen postMessage'ta event.origin'i (ve beklenen kaynagi) **dogrula**; dogrulanmamis mesaj govdesini state/DOM'a islemekten kacin  — Module Federation/iframe kurulumunda guvenilmeyen origin enjeksiyon kapisidir  [Oncelik: Major] Yasak: /postMessage\\([^)]*[\"\\']\\*[\"\\']\\s*\\)/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ origin dogrulanmadan mesaj islenir\n  window.addEventListener('message', (e) => setVeri(e.data));\n  // ✅ beklenen origin kontrolu\n  window.addEventListener('message', (e) => {\n    if (e.origin !== import.meta.env.VITE_SHELL_ORIGIN) return;\n    setVeri(e.data);\n  });\n  ```\n  </details>\n- [ ] Hata/exception detayini (stack trace, ic URL, sunucu mesaji ham hali) son kullaniciya **gosterme**; kullaniciya genel mesaj, detayi merkezi `logger`/ekolog'a gonder  — sizinti ic mimariyi ifsa eder (Bolum 5 merkezi `logger` ve Bolum 13 merkezi hata isleme ile uyumlu)  [Oncelik: Minor]\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ ham hata/stack kullaniciya basilir (ic detay sizar)\n  enqueueSnackbar(String(error), { variant: 'error' });\n  // ✅ kullaniciya genel mesaj; detay merkezi log'a\n  logger.error('Entity kaydi basarisiz', error);\n  enqueueSnackbar('Islem tamamlanamadi, lutfen tekrar deneyin', { variant: 'error' });\n  ```\n  </details>\n\n## 17. Performans & Kaynak (GC/RAM/CPU) — Genel Iyi Pratikler (global)\n\n> Platformdaki TUM `<is-alani>-web` repolarina uygulanan, somut kaynak etkisi (GC/RAM/CPU/bundle) belirten genel performans kapilari. (useEffect listener/interval/AbortController cleanup icin Bolum 3'e, react-window sanallastirma icin Bolum 4'e, AbortController istek iptali icin Bolum 13'e atif.)\n\n- [ ] RTK Query cache'inin sinirsiz buyumesini keepUnusedDataFor ile **sinirla** ve buyuk/sik-degisen sorgularda gerektiginde api.util.resetApiState() veya api.util.invalidateTags(...) ile temizle  — varsayilan 60 sn ablukasi disinda tutulan binlerce arama/parametre varyantli cache sonsuz birikir → RAM  [Oncelik: Major] Yasak: /keepUnusedDataFor\\s*:\\s*[1-9]\\d{3,}/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ her arama metni ayri cache girdisi olarak kalir (sinirsiz buyume → RAM)\n  export const entityApi = createApi({ baseQuery, endpoints: (b) => ({ ara: b.query({ query: (q) => `/entity?ara=${q}` }) }) });\n  // ✅ kullanilmayan veriyi kisa surede dusur\n  export const entityApi = createApi({ baseQuery, keepUnusedDataFor: 30, endpoints: (b) => ({ ... }) });\n  ```\n  </details>\n- [ ] Buyuk veri kumelerini / Blob / dosya icerigi / base64 string / genis dizileri Redux store veya Context'te **tutma**; ihtiyac aninda ureten kaynaktan oku, gerekirse useRef/yerel degiskende geciri tut  — store serialize edilir ve uzun yasar → RAM/GC (server verisi icin Bolum 2 RTK Query atfi)  [Oncelik: Major] Yasak: /:\\s*(Blob|File|ArrayBuffer|Uint8Array)(\\[\\])?\\s*[;,]/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ MB'larca dosya/base64 Redux state'te (store sislir → RAM/GC)\n  dispatch(setYuklenenDosya({ base64: await dosyayiBase64Yap(file) }));\n  // ✅ buyuk icerigi store disinda tut; yalniz referans/metadata sakla\n  const dosyaRef = useRef<File | null>(file);\n  dispatch(setDosyaMeta({ ad: file.name, boyut: file.size }));\n  ```\n  </details>\n- [ ] createObjectURL ile uretilen object URL'leri kullanim bittiginde / unmount'ta URL.revokeObjectURL(...) ile **serbest birak**  — revoke edilmeyen URL referans tuttugu Blob'u GC'den korur → RAM (PDF/gorsel onizleme indir/export akislari)  [Oncelik: Major] Yasak: /URL\\.createObjectURL\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ object URL revoke edilmez (Blob GC olmaz → RAM sizintisi)\n  const url = URL.createObjectURL(blob); setOnizleme(url);\n  // ✅ cleanup'ta revoke\n  useEffect(() => { const url = URL.createObjectURL(blob); setOnizleme(url);\n    return () => URL.revokeObjectURL(url); }, [blob]);\n  ```\n  </details>\n- [ ] Buyuk kutuphanelerden tam (barrel) import yerine named/alt-yol import **kullan**: lodash yerine lodash-es/lodash/debounce, import { Button } from '@mui/material' yerine gerektiginde @mui/material/Button, ikonlarda @mui/icons-material/X  — barrel import tum modulu agaca cekip parse ettirir → bundle/parse CPU + RAM  [Oncelik: Major] Yasak: /from\\s+[\"\\']\\s*(lodash|@mui\\/icons-material)[\"\\']/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ tam kutuphane / barrel import (kullanilmayan kod da gelir)\n  import _ from 'lodash';\n  import { Delete } from '@mui/icons-material'; // tum ikon barrel'i parse edilir\n  // ✅ alt-yol / named import (tree-shake + dusuk parse)\n  import debounce from 'lodash/debounce';\n  import DeleteIcon from '@mui/icons-material/Delete';\n  ```\n  </details>\n- [ ] Turetilmis store verisini bilesende her render hesaplamak yerine reselect/createSelector ile memoize edilmis selector **kullan**; selector icinde inline .filter/.map/.sort ile her cagrida yeni referans donmesinden kacin  — memoize edilmemis selector yeni referans uretip gereksiz re-render zinciri tetikler → CPU  [Oncelik: Major] Yasak: /useSelector\\([\\s\\S]*=>[\\s\\S]*\\.(filter|map|sort)\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ her render yeni dizi referansi → tum tuketiciler re-render\n  const aktifler = useAppSelector((s) => s.entity.liste.filter((e) => e.aktif));\n  // ✅ createSelector ile memoize (girdi degismedikce ayni referans)\n  const secAktifEntityler = createSelector((s: RootState) => s.entity.liste, (l) => l.filter((e) => e.aktif));\n  const aktifler = useAppSelector(secAktifEntityler);\n  ```\n  </details>\n- [ ] Pahali tek-seferlik nesneleri (Intl.NumberFormat/Intl.DateTimeFormat, RegExp, agir konfigurasyon) render govdesinde yeniden yaratmaktan **kacin**; modul-seviyesinde veya useMemo ile tek kez uret  — her render'da yeni Intl/RegExp allocate edip atmak → GC baskisi + CPU  [Oncelik: Minor] Yasak: /new\\s+Intl\\.\\w+\\([\\s\\S]*\\)\\.format\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ her render yeni Intl/RegExp (allocate + GC)\n  function fiyat({ deger }) { return new Intl.NumberFormat('tr-TR').format(deger); }\n  // ✅ modul-seviyesinde tek kez (paylasilan instance)\n  const trFormat = new Intl.NumberFormat('tr-TR');\n  function fiyat({ deger }) { return trFormat.format(deger); }\n  ```\n  </details>\n- [ ] setInterval/setTimeout/requestAnimationFrame/polling dongusunu unmount'ta clearInterval/clearTimeout/cancelAnimationFrame ile **iptal et**; ozellikle gorunmeyen sekme/komponentte polling birakma  — temizlenmemis zamanlayici state guncellemeye devam edip referans tutar → RAM sizintisi + CPU (Bolum 3 useEffect cleanup ilkesiyle uyumlu)  [Oncelik: Major] Yasak: /(setInterval\\(|requestAnimationFrame\\()/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ interval temizlenmez (unmount sonrasi calismaya devam → sizinti/CPU)\n  useEffect(() => { setInterval(() => refetch(), 5000); }, []);\n  // ✅ cleanup'ta clearInterval\n  useEffect(() => { const id = setInterval(() => refetch(), 5000); return () => clearInterval(id); }, [refetch]);\n  ```\n  </details>\n- [ ] Uzun-omurlu WebSocket/SSE/EventSource/harici SDK aboneliklerini bilesen unmount'ta close()/unsubscribe() ile **kapat**; her acilista yeni baglanti acip kapatmamaktan kacin  — kapanmayan baglanti hem soket/handle hem callback closure'unu tutar → RAM/baglanti sizintisi  [Oncelik: Major] Yasak: /new\\s+(WebSocket|EventSource)\\(/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ EventSource hic kapatilmaz (her mount yeni baglanti, eskiler sizar)\n  useEffect(() => { const es = new EventSource(url); es.onmessage = onMsg; }, [url]);\n  // ✅ cleanup'ta kapat\n  useEffect(() => { const es = new EventSource(url); es.onmessage = onMsg; return () => es.close(); }, [url]);\n  ```\n  </details>\n- [ ] Liste render'inda key olarak kararli benzersiz kimlik (item.id) **kullan**; array index'i veya her render degisen deger (rastgele/Date.now) key'i olarak kullanma  — kararsiz key React'i tum alt agaci yeniden olusturmaya zorlar (reconciliation cogalir) → CPU + gereksiz DOM allocate/GC  [Oncelik: Major] Yasak: /key=\\{\\s*(index|idx|i|Math\\.random\\(\\)|Date\\.now\\(\\))\\s*\\}/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ kararsiz key (her render yeni → tum satirlar yeniden olusur)\n  {liste.map((e, i) => <Row key={Math.random()} entity={e} />)}\n  // ✅ kararli kimlik key'i\n  {liste.map((e) => <Row key={e.id} entity={e} />)}\n  ```\n  </details>\n- [ ] CPU-yogun islemi (buyuk parse/sort/hesaplama, kripto, dosya isleme) ana thread'i kilitlemeden Web Worker'a veya parcalanmis/async isleme **tasi**; binlerce ogeyi senkron map/sort ile tek karede islemekten kacin  — uzun senkron is ana thread'i bloklar → CPU/jank (UI donar)  [Oncelik: Minor]\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ on binlerce kaydi render thread'inde senkron isle (UI donar)\n  const sonuc = devasaListe.map(agirDonusum).sort(karsilastir);\n  // ✅ agir isi worker'a tasi (ana thread serbest)\n  const worker = new Worker(new URL('./entity-isle.worker.ts', import.meta.url), { type: 'module' });\n  worker.postMessage(devasaListe);\n  ```\n  </details>\n- [ ] Gorsel/asset boyutunu **optimize et**: buyuk PNG/JPG yerine optimize/WebP, gerektiginde loading=\"lazy\", ikon icin SVG; ham yuksek-cozunurluklu gorseli src/'e gomup bundle'a katmaktan kacin  — buyuk asset hem indirme hem decode bellegi tuketir → RAM + ag/CPU (decode)  [Oncelik: Minor] Yasak: /from\\s+[\"\\'][^\"\\']*\\.(png|jpe?g)[\"\\']/\n  <details><summary>↳ örnek</summary>\n\n  ```tsx\n  // ❌ devasa ham gorsel, lazy yok (decode RAM + ilk yuk yavas)\n  <img src={buyukJpg} />\n  // ✅ optimize asset + lazy yukleme\n  <img src={optimizeWebp} loading=\"lazy\" width={320} height={200} />\n  ```\n  </details>\n- [ ] Bundle boyutu icin gozlem/butce **kur**: build'de rollup-plugin-visualizer/vite build --report ile chunk analizi yap, beklenmedik buyuk bagimliligi (moment, tum lodash, agir grafik kutuphanesi) tespit et ve gerektiginde lazy-load veya hafif alternatife gec  — kontrolsuz bundle ilk yuk parse/derleme suresi → CPU + RAM (mevcut React.lazy ile uyumlu)  [Oncelik: Minor] Yasak: /from\\s+[\"\\']moment[\"\\']/\n  <details><summary>↳ örnek</summary>\n\n  ```ts\n  // ❌ bundle boyutu izlenmiyor (regresyon fark edilmez)\n  // (analiz adimi yok)\n  // ✅ build'de gorsel chunk analizi\n  import { visualizer } from 'rollup-plugin-visualizer';\n  export default defineConfig({ plugins: [visualizer({ gzipSize: true })] });\n  ```\n  </details>\n\n---\n\n## Hizli ozet\n\n| Kategori | En kritik kontrol | Oncelik |\n|---|---|---|\n| Component & yapi | <300 satir, container/presentational ayrik | Major |\n| State yonetimi | Cift state-kaynagi (Context+Redux/state+modul-global) yok | Blocker |\n| Hook kullanimi | Hook'lar kosulsuz; rules-of-hooks disable yok | Blocker |\n| Performans | Provider value/memo'lu cocuga inline obj/fn yok; buyuk liste sanallastirilmis | Major |\n| Okunabilirlik | Sabit kodlu URL yok; console yerine logger | Major |\n| Tekrar kullanilabilirlik | golge-ui karsiligi varken elle yazma yok | Major |\n| TypeScript | `any`/`as any` yok; DTO backend kontratiyla uyumlu | Major |\n| golge-ui & MF | shared singleton tam + surum (golge-ui 1.16.x, major fark yok) | Blocker |\n| Form & dogrulama | Backend tek gercek kaynak; form lokal state | Major |\n| i18n | tr+en anahtar tam; sabit string yok | Major |\n| Erisilebilirlik | Etkilesimli div yerine MUI; klavye/aria | Major |\n| Guvenlik (XSS/token) | Token `useGolgeSecurity`/`golgeRtkApiHeaders`; korumali rota `hasAuthority`; dangerouslySetInnerHTML sanitize | Blocker |\n| Veri katmani | Her createApi reducer **ve** middleware kayitli | Blocker |\n| MUI 6 | Tema degeri; `sx as any` yok | Minor |\n| Test & lint | `lint --max-warnings 0` temiz | Blocker |\n| Guvenlik — genel (global) | `eval`/ham `innerHTML` yok; client'a sirr yok (yalniz public `VITE_`); `npm audit` gate; `target=_blank`→`rel=noopener`; open redirect dogrulama; CSP header | Blocker |\n| Performans & kaynak (global) | Unmount'ta timer/abone/object URL temizligi (→RAM); RTK Query `keepUnusedDataFor` (→RAM); barrel yerine alt-yol import (→bundle/CPU); memoize selector (→CPU); buyuk veri/blob store'da degil (→RAM) | Major |\n",
  "06-python-code-review.md": "# Python Code Review Standartları\n\n> Backend · **Python** (Django / Flask / FastAPI). Dosya deseni: `*.py`.\n> `- [ ]` maddeleri Portal Code Review tarafından kural olarak okunur.\n> ⚙️ = tarayıcıda otomatik (deterministik) denetlenir; diğerleri incelemede referans standardıdır.\n\n## 1. Genel Kod Kalitesi\n- [ ] print( ile çıktı alınmamalı — üretim kodunda logging modülü kullanılmalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı; iş bitirilmeli veya issue açılmalı ⚙️\n- [ ] Açıklayıcı olmayan gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] Fonksiyonlar tek bir işi yapmalı; 50 satırı aşan fonksiyonlar bölünmeli\n- [ ] Değişken/fonksiyon adları snake_case, sınıflar PascalCase, sabitler UPPER_CASE olmalı (PEP 8) — Yasak: /def\\s+[a-z_]+[A-Z]\\w*\\s*\\(/\n- [ ] Sihirli sabitler yerine adlandırılmış sabitler/Enum kullanılmalı — Yasak: /(if|elif|while)\\s[^:\\n]*[<>=!]=\\s*\\d{3,}/\n- [ ] Satır uzunluğu 88/100 karakteri aşmamalı; black/ruff ile biçimlendirilmeli\n- [ ] Kullanılmayan import ve değişkenler kaldırılmalı — Yasak: /^\\s*from\\s+[\\w.]+\\s+import\\s+\\*/\n\n## 2. Tip Güvenliği & Modern Python\n- [ ] Public fonksiyon/method imzalarında tip ipuçları (type hints) bulunmalı — Yasak: /def\\s+[a-zA-Z_]\\w*\\((?!\\s*(self|cls)\\s*[,)])\\s*\\*{0,2}[a-z_]\\w*\\s*[,)]/\n- [ ] Mutable default argüman (def f(x=[])) kullanılmamalı; None + içeride atama yapılmalı — Yasak: /def\\s+\\w+\\([^)\\n]*=\\s*(\\[\\]|\\{\\}|set\\(\\)|dict\\(\\)|list\\(\\))/\n- [ ] == None yerine is None kullanılmalı — Yasak: /[!=]=\\s*None\\b/\n- [ ] String biçimlendirmede % veya .format yerine f-string tercih edilmeli — Yasak: /(\\.format\\(|[\"']\\s*%\\s*[\\(\\w])/\n- [ ] Sözlük erişiminde KeyError riski için .get() veya in kontrolü yapılmalı — Yasak: /(request\\.(POST|GET|data|json)|payload|params|body)\\s*\\[\\s*[\"']/\n- [ ] Bağlam yöneticisi (with) ile dosya/bağlantı/lock kaynakları yönetilmeli — Yasak: /^\\s*\\w+\\s*=\\s*open\\s*\\(/\n\n## 3. Güvenlik\n- [ ] Parola, secret, token veya api key kaynak koda gömülmemeli; ortam değişkeni kullanılmalı ⚙️\n- [ ] eval( ve exec( kullanılmamalı — kod enjeksiyonu riski — Yasak: /(^|[^\\w.])(eval|exec)\\s*\\(/\n- [ ] SQL sorguları f-string/format ile değil parametreli (ORM/placeholder) yazılmalı — Yasak: /(execute|executemany|raw)\\s*\\(\\s*(f[\"']|[\"'][^\"'\\n]*[\"']\\s*[%+]|[\"'][^\"'\\n]*[\"']\\s*\\.format)/\n- [ ] subprocess çağrılarında shell=True ve doğrulanmamış girdi kullanılmamalı — Yasak: /shell\\s*=\\s*True/\n- [ ] pickle ile güvenilmeyen veri deserialize edilmemeli — Yasak: /(pickle|cPickle)\\.(load|loads)\\s*\\(/\n- [ ] Rastgelelik için `random` değil güvenlik gerektiren yerde `secrets` kullanılmalı\n- [ ] assert ile üretimde güvenlik/doğrulama kontrolü yapılmamalı (optimize modda atlanır) — Yasak: /^\\s*assert\\s[^\\n]*(user|token|auth|perm|role|admin|valid|secret|password)/\n\n## 4. Hata Yönetimi\n- [ ] Boş except bloğu ile istisna yutulmamalı; loglanmalı veya ele alınmalı ⚙️\n- [ ] Çıplak except: yerine belirli istisna tipleri yakalanmalı — Yasak: /except\\s*:/\n- [ ] die(/exit(/panic( gibi ani sonlandırma yapılmamalı ⚙️\n- [ ] İstisna yeniden fırlatılırken raise ... from err ile zincir korunmalı — Yasak: /\\braise\\s+\\w[^\\n]*\\bfrom\\s+None\\b/\n- [ ] except içinde pass yerine anlamlı işlem veya loglama yapılmalı — Yasak: /except[^\\n]*:\\s*pass\\b/\n\n## 5. Django\n- [ ] View içinde iş mantığı değil servis/manager katmanı çağrılmalı (fat model / thin view) — Yasak: /\\.objects\\.\\w+\\([^)\\n]*request\\./\n- [ ] DEBUG=True üretimde kapalı olmalı; ayarlar ortama göre gelmeli — Yasak: /DEBUG\\s*=\\s*True/\n- [ ] N+1 sorgu için select_related/prefetch_related kullanılmalı — Yasak: /for\\s+\\w+\\s+in\\s+[\\w.]*\\.objects\\.(all|filter)\\(/\n- [ ] QuerySet üzerinde döngüde tekrar sorgu (loop içinde .get) yapılmamalı — Yasak: /(for\\s[^\\n]*\\.objects\\.get\\(|\\.objects\\.get\\([^\\n]*\\bfor\\s)/\n- [ ] Ham SQL yerine ORM; gerekiyorsa params ile raw()/extra() kullanılmalı — Yasak: /(connection\\.cursor\\s*\\(\\s*\\)|\\.extra\\s*\\()/\n- [ ] CSRF/güvenlik ara katmanları devre dışı bırakılmamalı — Yasak: /(csrf_exempt|WTF_CSRF_ENABLED\\s*=\\s*False|CSRF_COOKIE_SECURE\\s*=\\s*False|SECURE_SSL_REDIRECT\\s*=\\s*False)/\n- [ ] Migration'lar el ile düzenlenip kod ile tutarsız bırakılmamalı — Yasak: /migrations\\.RunSQL\\s*\\(/\n\n## 6. Flask / FastAPI\n- [ ] Kullanıcı girdisi Pydantic/marshmallow şeması ile doğrulanmalı — Yasak: /(request\\.get_json\\s*\\(|await\\s+request\\.json\\s*\\(|request\\.form\\s*\\[)/\n- [ ] Bloklayan I/O async def endpoint içinde await edilmeden çağrılmamalı (FastAPI) — Yasak: /(time\\.sleep\\s*\\(|requests\\.(get|post|put|delete|patch)\\s*\\()/\n- [ ] Global mutable state yerine dependency injection (Depends) kullanılmalı — Yasak: /^[A-Za-z_]\\w*\\s*(:\\s*[^=\\n]+)?=\\s*(\\[\\]|\\{\\}|dict\\(\\)|list\\(\\)|set\\(\\))\\s*$/\n- [ ] Hatalar uygun HTTP status ve tutarlı hata gövdesiyle dönmeli — Yasak: /return\\s*\\{\\s*[\"']\\s*(error|hata|message)[\"']?\\s*:/\n- [ ] Uzun süren işler arka plan görevine (Celery/BackgroundTasks) taşınmalı\n\n## 7. Test & Bakım\n- [ ] Yeni davranış için birim testi eklenmeli; kritik yollar kapsanmalı\n- [ ] Testlerde gerçek ağ/DB yerine mock/fixture kullanılmalı — Yasak: /(requests\\.\\w+\\(\\s*[\"']https?:|socket\\.socket\\s*\\(|psycopg2\\.connect\\s*\\()/\n- [ ] Ölü kod (kullanılmayan fonksiyon/branch) bırakılmamalı — Yasak: /^\\s*(if|while)\\s+(False|0)\\s*:/\n",
  "07-go-code-review.md": "# Go (Golang) Code Review Standartları\n\n> Backend · **Go**. Dosya deseni: `*.go`.\n> `- [ ]` maddeleri Portal Code Review kuralı olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] fmt.Println / fmt.Printf ile çıktı alınmamalı — log/slog kullanılmalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] Değişken/paket adları kısa ve anlamlı; dışa açık isimler PascalCase olmalı — Yasak: /(func|type|var|const)\\s+[a-z]\\w*_\\w+/\n- [ ] Sihirli sabitler yerine adlandırılmış const/iota kullanılmalı — Yasak: /(if|for)\\s[^{\\n]*[<>=!]=\\s*\\d{3,}/\n- [ ] Kod gofmt/goimports ile biçimlendirilmeli; kullanılmayan import kalmamalı\n- [ ] Paket adları tekil, kısa ve küçük harf olmalı; util/common gibi çöp paketler olmamalı — Yasak: /^package\\s+(util|utils|common|helper|helpers|misc|shared|base)\\b/\n\n## 2. Hata Yönetimi (Go'ya özgü)\n- [ ] Dönen error değeri yok sayılmamalı; _ = err ile yutulmamalı — Yasak: /(_\\s*=\\s*err\\b|_\\s*=\\s*[\\w.]+\\([^)\\n]*\\)\\s*$)/\n- [ ] panic( üretim kodunda kullanılmamalı; hata değerle döndürülmeli ⚙️\n- [ ] Hatalar fmt.Errorf(\"...: %w\", err) ile sarmalanarak bağlam eklenmeli — Yasak: /fmt\\.Errorf\\((?![^\\n]*%w)[^\\n]*,\\s*err\\b/\n- [ ] Sentinel hata karşılaştırmasında errors.Is / errors.As kullanılmalı — Yasak: /err\\s*[!=]=\\s*[\\w.]*Err[A-Z]\\w*/\n- [ ] Hata mesajları küçük harfle başlamalı ve noktalama ile bitmemeli — Yasak: /(errors\\.New|fmt\\.Errorf)\\(\\s*\"([A-Z]|[^\"\\n]*[.!]\")/\n- [ ] recover yalnız gerçekten gerekli sınırlarda (goroutine tepesi) kullanılmalı — Yasak: /\\brecover\\s*\\(\\s*\\)/\n\n## 3. Eşzamanlılık\n- [ ] goroutine sızıntısı olmamalı; context ile iptal/timeout yönetilmeli — Yasak: /go\\s+func\\s*\\(\\s*\\)\\s*\\{/\n- [ ] Paylaşılan duruma erişimde mutex/kanal ile senkronizasyon yapılmalı; race olmamalı — Yasak: /go\\s+func\\s*\\([^)\\n]*\\)\\s*\\{[^\\n]*(\\+\\+|--|\\+=|\\]\\s*=)/\n- [ ] defer ile kaynak (file, rows, conn, mutex.Unlock) mutlaka kapatılmalı — Yasak: /_\\s*=\\s*[\\w.]*\\.Close\\s*\\(\\s*\\)/\n- [ ] Kanallar üretici tarafında kapatılmalı; kapalı kanala yazılmamalı — Yasak: /for\\s[^\\n]*range\\s+\\w+\\s*\\{[^\\n]*close\\s*\\(/\n- [ ] WaitGroup Add/Done dengesi korunmalı; sync primitive'leri kopyalanmamalı — Yasak: /\\(\\s*[^)*\\n]*\\bsync\\.(WaitGroup|Mutex|RWMutex)\\b/\n- [ ] context.Context fonksiyonun ilk parametresi olmalı; struct içinde saklanmamalı — Yasak: /func\\s+[^(\\n]*\\(\\s*[a-z]\\w*\\s+[\\w*.\\[\\]]+\\s*,\\s*\\w+\\s+context\\.Context/\n\n## 4. Güvenlik & Performans\n- [ ] Parola/secret/token/api key koda gömülmemeli ⚙️\n- [ ] SQL sorguları parametreli olmalı; string birleştirme ile yazılmamalı — Yasak: /(Query|QueryRow|Exec)(Context)?\\s*\\([^\\n]*(\"[^\"\\n]*\"\\s*\\+|fmt\\.Sprintf\\()/\n- [ ] Döngü içinde gereksiz tahsis (allocation) yapılmamalı; slice önceden cap ile ayrılmalı — Yasak: /=\\s*make\\(\\[\\][\\w.*\\[\\]]+,\\s*0\\s*\\)/\n- [ ] Büyük struct'lar değer yerine pointer ile geçirilmeli (gerektiğinde) — Yasak: /func\\s*\\(\\s*\\w+\\s+[A-Z]\\w*\\s*\\)\\s*[A-Z]/\n- [ ] defer sıcak döngü (hot loop) içinde kullanılmamalı — Yasak: /for\\s[^\\n]*\\{[^\\n]*\\bdefer\\s/\n- [ ] HTTP istemcisinde timeout ayarlanmalı; response body kapatılmalı — Yasak: /(http\\.(Get|Post|PostForm|Head)\\s*\\(|http\\.Client\\{\\s*\\})/\n\n## 5. API & Yapı\n- [ ] Interface'ler tüketici tarafında, küçük ve odaklı tanımlanmalı — Yasak: /type\\s+I[A-Z]\\w*\\s+interface\\b/\n- [ ] Dışa açık tipler/fonksiyonlar doc comment ile açıklanmalı\n- [ ] Test edilebilirlik için bağımlılıklar interface üzerinden enjekte edilmeli — Yasak: /^var\\s+\\w+\\s*=\\s*&?\\w*(Service|Repo|Repository|Client|Store)\\{/\n- [ ] Yeni davranış için `_test.go` altında test eklenmeli\n",
  "08-csharp-dotnet-code-review.md": "# C# / .NET Code Review Standartları\n\n> Backend · **C# / .NET** (ASP.NET Core / EF Core). Dosya deseni: `*.cs`.\n> `- [ ]` maddeleri kural olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] Console.WriteLine ile çıktı alınmamalı — ILogger kullanılmalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] Sınıf/method/property PascalCase, private alanlar _camelCase, parametreler camelCase olmalı — Yasak: /(?:private\\s+(?:readonly\\s+|static\\s+)*[A-Za-z_][\\w<>,\\?]*\\s+[a-z]\\w*\\s*[;=]|(?:public|protected|internal)\\s+(?:static\\s+)?(?:async\\s+)?[A-Za-z_][\\w<>,\\?]*\\s+[a-z]\\w*\\s*\\()/\n- [ ] Sihirli sabitler yerine const/enum kullanılmalı — Yasak: /(?:==|!=|>=|<=|>|<)\\s*[0-9]{3,}/\n- [ ] var yalnız tip sağdan açıkça belliyken kullanılmalı; belirsizse açık tip yazılmalı — Yasak: /\\bvar\\s+\\w+\\s*=\\s*(?!new\\b)[A-Za-z_][\\w.]*\\s*\\(/\n- [ ] Kullanılmayan using/alan/parametre kaldırılmalı\n\n## 2. Null Güvenliği & Modern C#\n- [ ] Nullable reference types (#nullable enable) etkin olmalı — Yasak: /#nullable\\s+disable/\n- [ ] Null kontrolünde ?. , ?? , is null kullanılmalı; gereksiz null-forgiving (!) yasak — Yasak: /[\\w\\]\\)]!\\s*[.;,)]/\n- [ ] String karşılaştırmasında kültür/duyarlılık (StringComparison) belirtilmeli — Yasak: /(?:ToLower|ToUpper|ToLowerInvariant|ToUpperInvariant)\\s*\\(\\s*\\)\\s*(?:==|!=|\\.(?:Equals|Contains|StartsWith|EndsWith))/\n- [ ] Değişmez veriler için record/readonly yapılar tercih edilmeli — Yasak: /public\\s+(?:string|int|long|decimal|double|bool|DateTime|Guid)\\??\\s+\\w+\\s*\\{\\s*get;\\s*set;\\s*\\}/\n- [ ] Pattern matching (switch expression) uygun yerde kullanılmalı — Yasak: /\\bis\\s+[A-Z]\\w*\\s*\\)|\\.GetType\\s*\\(\\s*\\)\\s*==\\s*typeof/\n\n## 3. Hata Yönetimi\n- [ ] Boş catch bloğu ile istisna yutulmamalı ⚙️\n- [ ] catch(Exception) ile genel yakalama yerine belirli tipler yakalanmalı — Yasak: /catch\\s*\\(\\s*(?:System\\.)?Exception\\b/\n- [ ] İstisna yeniden fırlatılırken throw; kullanılmalı, throw ex; değil (stack kaybolur) — Yasak: /throw\\s+\\w+\\s*;/\n- [ ] using / await using ile IDisposable kaynaklar serbest bırakılmalı — Yasak: /^\\s*(?:var|[A-Z]\\w*)\\s+\\w+\\s*=\\s*new\\s+(?:SqlConnection|SqlCommand|StreamReader|StreamWriter|FileStream|MemoryStream|HttpClient|HttpRequestMessage|HttpResponseMessage)\\s*\\(/\n- [ ] Akış kontrolü için istisna kullanılmamalı — Yasak: /catch\\s*(?:\\([^)]*\\))?\\s*\\{\\s*(?:return|break|continue)\\b/\n\n## 4. Async & Performans\n- [ ] async metotlarda .Result veya .Wait() ile bloklama yapılmamalı (deadlock) — Yasak: /\\.(?:Result\\b|Wait\\s*\\(\\s*\\)|GetAwaiter\\s*\\(\\s*\\)\\s*\\.\\s*GetResult)/\n- [ ] async metotlar Task döndürmeli; async void yalnız event handler'da — Yasak: /\\basync\\s+void\\s+\\w/\n- [ ] Kütüphane kodunda ConfigureAwait(false) kullanılmalı — Yasak: /ConfigureAwait\\s*\\(\\s*true\\s*\\)/\n- [ ] CancellationToken uygun şekilde alınıp iletilmeli — Yasak: /CancellationToken\\.None/\n- [ ] EF Core sorgularında N+1 için Include/projeksiyon kullanılmalı — Yasak: /(?:for|foreach|while)\\s*\\([^)]*\\)[^;]{0,80}\\.(?:First|Single|Where|Find|Any|Count|ToList)(?:OrDefault)?(?:Async)?\\s*\\(/\n- [ ] IQueryable üzerinde erken ToList() ile gereksiz materyalizasyon yapılmamalı — Yasak: /\\.To(?:List|Array)\\s*\\(\\s*\\)\\s*\\.\\s*(?:Where|Select|OrderBy|First|Single|Any|Count|Skip|Take)/\n- [ ] Döngü içinde string birleştirme yerine StringBuilder kullanılmalı — Yasak: /(?:for|foreach|while)\\s*\\([^)]*\\)[^;]{0,60}\\w+\\s*\\+=\\s*[^;]*\"/\n\n## 5. Güvenlik (ASP.NET Core)\n- [ ] Parola/secret/token/api key koda gömülmemeli; Configuration/User Secrets/Key Vault kullanılmalı ⚙️\n- [ ] SQL için parametreli sorgu/ORM kullanılmalı; string birleştirme yasak — Yasak: /\\$?@?\"\\s*(?:SELECT|INSERT|UPDATE|DELETE|select|insert|update|delete)\\b[^\"]*(?:\\{|\"\\s*\\+)/\n- [ ] Girdi model validation (DataAnnotations/FluentValidation) ile doğrulanmalı — Yasak: /Request\\.(?:Form|Query|Headers)\\s*\\[/\n- [ ] Controller'lar ince olmalı; iş mantığı service katmanında yer almalı\n- [ ] Yetkilendirme Authorize attribute ile yapılmalı; endpoint'ler açıkta bırakılmamalı — Yasak: /\\[AllowAnonymous\\]/\n- [ ] DI ile servisler doğru yaşam süresiyle (Scoped/Transient/Singleton) kaydedilmeli — Yasak: /AddSingleton\\s*<[^>]*(?:DbContext|Repository|UnitOfWork|HttpContext)[^>]*>/\n\n## 6. Test & Bakım\n- [ ] Yeni davranış için birim testi (xUnit/NUnit) eklenmeli — Yasak: /\\[Ignore[\\s(\\]]|Skip\\s*=\\s*\"/\n- [ ] Bağımlılıklar interface üzerinden mock'lanabilir olmalı — Yasak: /=\\s*new\\s+\\w*(?:Service|Repository|Client|Manager|Provider)\\s*\\(/\n- [ ] Ölü kod ve yorum satırına alınmış kod bloğu bırakılmamalı\n",
  "09-php-laravel-code-review.md": "# PHP / Laravel Code Review Standartları\n\n> Backend · **PHP** (Laravel / Symfony). Dosya deseni: `*.php`.\n> `- [ ]` maddeleri kural olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] var_dump / print_r / dd( gibi hata ayıklama çağrıları bırakılmamalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] Sınıf PascalCase, method camelCase, sabit UPPER_CASE olmalı (PSR-12) — Yasak: /(?:function\\s+[a-z0-9]+_[a-z0-9_]*\\s*\\(|\\bclass\\s+[a-z]\\w*|const\\s+[a-z]\\w*\\s*=)/\n- [ ] Sihirli sabitler yerine const/enum kullanılmalı — Yasak: /(?:===|!==|==|!=|>=|<=|>|<)\\s*[0-9]{3,}/\n- [ ] declare(strict_types=1) dosya başında bulunmalı — Yasak: /declare\\s*\\(\\s*strict_types\\s*=\\s*0\\s*\\)/\n- [ ] Fonksiyon parametreleri ve dönüş değerleri tiplenmeli (type hints) — Yasak: /function\\s+(?!__)\\w+\\s*\\([^)]*\\)\\s*\\{/\n\n## 2. Güvenlik\n- [ ] Parola/secret/token/api key koda gömülmemeli; .env/config kullanılmalı ⚙️\n- [ ] eval( kullanılmamalı; die(/exit( ile ani sonlandırma yapılmamalı ⚙️\n- [ ] SQL için Eloquent/Query Builder veya PDO parametreleri kullanılmalı; ham birleştirme yasak — Yasak: /(?:DB::(?:select|statement|unprepared|raw)|whereRaw|selectRaw|havingRaw|orderByRaw|mysqli_query|->query)\\s*\\(\\s*[\"'][^\"']*(?:\\$|[\"']\\s*\\.)/\n- [ ] Çıktı htmlspecialchars veya Blade süslü parantezi ile kaçışlanmalı (XSS); ham çıktı dikkatli kullanılmalı — Yasak: /\\{!!|echo\\s+\\$_(?:GET|POST|REQUEST)|print\\s+\\$_(?:GET|POST|REQUEST)/\n- [ ] Kullanıcı girdisiyle dosya yolu oluşturulmamalı (path traversal) — Yasak: /(?:file_get_contents|file_put_contents|fopen|readfile|unlink|include|include_once|require|require_once)\\s*\\(\\s*[^;)]{0,60}(?:\\$_(?:GET|POST|REQUEST)|\\$request->|request\\(\\)->)/\n- [ ] unserialize ile güvenilmeyen veri işlenmemeli — Yasak: /\\bunserialize\\s*\\(/\n- [ ] CSRF koruması form/istek katmanında etkin olmalı — Yasak: /(?:withoutMiddleware\\s*\\(|VerifyCsrfToken|withoutToken\\s*\\(|csrf_exempt)/\n\n## 3. Hata Yönetimi\n- [ ] Boş catch bloğu ile istisna yutulmamalı ⚙️\n- [ ] Hata bastırma operatörü (at işareti) kullanılmamalı — Yasak: /(?:=|\\(|,|;|\\s)@[a-z_]\\w*\\s*\\(/\n- [ ] Genel Exception yerine anlamlı özel istisna tipleri fırlatılmalı — Yasak: /throw\\s+new\\s+\\\\?Exception\\s*\\(/\n- [ ] Hatalar merkezi handler'da loglanmalı; kullanıcıya iç detay sızdırılmamalı — Yasak: /(?:echo|print|return|response\\s*\\(|json\\s*\\()[^;]{0,80}->getMessage\\s*\\(\\s*\\)/\n\n## 4. Laravel\n- [ ] Controller'da iş mantığı değil Service/Action katmanı çağrılmalı (thin controller)\n- [ ] Toplu atama (mass assignment) için fillable veya guarded tanımlanmalı — Yasak: /(?:create|update|fill|forceFill|forceCreate)\\s*\\(\\s*(?:\\$request->all\\s*\\(|request\\s*\\(\\s*\\)->all\\s*\\(|\\$_POST)/\n- [ ] N+1 sorgu için with() (eager loading) kullanılmalı — Yasak: /(?:foreach|for|while)\\s*\\([^)]*\\)[^;]{0,80}(?:::(?:where|find|first|all|get)\\s*\\(|->(?:where|find|first|get|count)\\s*\\()/\n- [ ] İstek doğrulaması Form Request veya validate() ile yapılmalı — Yasak: /\\$_(?:POST|GET|REQUEST|FILES)\\s*\\[/\n- [ ] env() yalnız config dosyalarında; kod içinde config() kullanılmalı — Yasak: /\\benv\\s*\\(\\s*[\"']/\n- [ ] Controller içinde ham DB::select yerine Eloquent tercih edilmeli — Yasak: /DB::(?:select|statement|unprepared|raw|insert|delete)\\s*\\(/\n- [ ] Uzun işlemler Queue/Job'a taşınmalı; senkron çalıştırılmamalı — Yasak: /(?:set_time_limit\\s*\\(|\\bsleep\\s*\\(|ini_set\\s*\\(\\s*[\"']max_execution_time|Mail::(?:send|raw)\\s*\\()/\n- [ ] Route kapanışları yerine controller method'ları kullanılmalı (route cache) — Yasak: /Route::\\w+\\s*\\([^)]*,\\s*(?:function\\s*\\(|fn\\s*\\()/\n- [ ] Yetkilendirme Policy/Gate ile yapılmalı — Yasak: /->(?:role|is_admin|isAdmin|user_type|isSuperAdmin)\\s*(?:===|==|!=|!==)\\s*[\"'0-9]/\n\n## 5. Test & Bakım\n- [ ] Yeni davranış için Pest/PHPUnit testi eklenmeli — Yasak: /(?:markTestSkipped|markTestIncomplete)\\s*\\(|->skip\\s*\\(/\n- [ ] Testlerde gerçek servis yerine mock/fake kullanılmalı — Yasak: /=\\s*new\\s+\\w*(?:Service|Repository|Client|Gateway|Api|Manager)\\s*\\(/\n- [ ] Ölü kod ve yorum satırına alınmış blok bırakılmamalı\n",
  "10-nodejs-backend-code-review.md": "# Node.js Backend Code Review Standartları\n\n> Backend · **Node.js** (Express / NestJS / TypeScript). Dosya deseni: `*.ts`.\n> `- [ ]` maddeleri kural olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] console.log/console.debug ile çıktı alınmamalı — pino/winston logger kullanılmalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] TypeScript `any` tipi kullanılmamalı; somut tip/unknown tercih edilmeli ⚙️\n- [ ] `var` yerine const/let kullanılmalı ⚙️\n- [ ] debugger ifadesi bırakılmamalı ⚙️\n- [ ] Gevşek eşitlik (==) yerine katı eşitlik (===) kullanılmalı ⚙️\n- [ ] Modül üstünde tsconfig strict açık olmalı; ts-ignore gelişigüzel kullanılmamalı — Yasak: /@ts-(ignore|nocheck|expect-error)\\b/\n\n## 2. Async & Hata Yönetimi\n- [ ] async fonksiyonlarda hatalar try/catch veya merkezi error middleware ile ele alınmalı — Yasak: /\\.(get|post|put|patch|delete)\\s*\\(\\s*[\"'][^\"']*[\"']\\s*,\\s*async\\s*\\(/\n- [ ] Boş catch bloğu ile hata yutulmamalı ⚙️\n- [ ] Promise'ler await edilmeli; floating promise bırakılmamalı — Yasak: /^\\s*(?!(await|return|const|let|var|export|import|yield)\\b)[A-Za-z_$][^;=\\n]*\\.then\\s*\\(/\n- [ ] Promise.all ile paralelleştirilebilir işler sırayla await edilmemeli — Yasak: /await\\s[^;\\n]{1,80};\\s*(const|let|var)[^;\\n]{0,60}=\\s*await\\s/\n- [ ] process.exit( ile ani sonlandırma yapılmamalı ⚙️\n- [ ] unhandledRejection/uncaughtException global olarak ele alınmalı — Yasak: /process\\.on\\s*\\(\\s*[\"']\\s*(uncaughtException|unhandledRejection)\\s*[\"']\\s*,\\s*(async\\s*)?\\(\\s*\\)\\s*=>/\n- [ ] Callback yerine async/await tercih edilmeli; callback hell olmamalı — Yasak: /,\\s*(async\\s*)?function\\s*\\(\\s*(err|error)\\b|,\\s*\\(\\s*(err|error)\\s*,\\s*[\\w$]+\\s*\\)\\s*=>/\n\n## 3. Güvenlik (Express/Nest)\n- [ ] Parola/secret/token/api key koda gömülmemeli; process.env kullanılmalı ⚙️\n- [ ] SQL/NoSQL sorguları parametreli olmalı; string birleştirme ile yazılmamalı — Yasak: /\\.(query|execute|raw|createQueryBuilder)\\s*\\([^)]*(\\$\\{|[\"']\\s*\\+\\s*[A-Za-z_$])/\n- [ ] Kullanıcı girdisi (DTO/zod/class-validator) ile doğrulanmalı — Yasak: /\\.(create|update|save|insert|findOne|delete)\\s*\\(\\s*req\\.(body|query|params)\\b/\n- [ ] eval( ve child_process ile doğrulanmamış komut çalıştırılmamalı — Yasak: /(^|[^.\\w])eval\\s*\\(|new\\s+Function\\s*\\(|require\\s*\\(\\s*[\"']child_process[\"']\\s*\\)|\\bexec\\s*\\(\\s*[^)]*\\$\\{/\n- [ ] helmet, rate-limit ve CORS politikaları yapılandırılmalı — Yasak: /origin\\s*:\\s*[\"']\\*[\"']|\\bcors\\s*\\(\\s*\\)|enableCors\\s*\\(\\s*\\)/\n- [ ] Hata yanıtlarında stack trace / iç detay dışarı sızdırılmamalı\n- [ ] JWT/secret doğrulaması sunucu tarafında yapılmalı; süre (exp) kontrol edilmeli\n\n## 4. Mimari & API Tasarımı\n- [ ] Controller ince olmalı; iş mantığı service katmanında yer almalı\n- [ ] HTTP durum kodları anlamlı kullanılmalı (200/201/400/401/404/409/500) — Yasak: /\\.status\\s*\\(\\s*(200|201)\\s*\\)\\s*\\.\\s*(json|send)\\s*\\(\\s*\\{\\s*(error|errors|errorCode|errorMessage)\\b/\n- [ ] Senkron ağır işlemler event loop'u bloklamamalı; worker/queue kullanılmalı — Yasak: /\\b(readFileSync|writeFileSync|appendFileSync|readdirSync|statSync|execSync|spawnSync|deflateSync|gzipSync|randomBytesSync|hashSync)\\s*\\(/\n- [ ] Bağımlılıklar DI ile enjekte edilmeli (Nest module/provider) — Yasak: /=\\s*new\\s+[A-Z][\\w$]*(Service|Repository|Client|Gateway|Handler|Manager)\\s*\\(/\n- [ ] Konfigürasyon merkezi config servisiyle yönetilmeli, dağınık process.env değil — Yasak: /process\\.env\\s*(\\.[A-Z_]{2,}|\\[\\s*[\"'][A-Z_]{2,})/\n- [ ] Girdi/çıktı sözleşmeleri (DTO) tanımlı ve tiplenmiş olmalı — Yasak: /@(Body|Query|Param)\\s*\\([^)]*\\)\\s*[\\w$]+\\s*:\\s*(any|object|Record\\s*<)|\\breq\\s*:\\s*any\\b/\n\n## 5. Performans & Bakım\n- [ ] DB bağlantısı havuzlanmalı (pool); her istekte yeni bağlantı açılmamalı — Yasak: /new\\s+(PrismaClient|MongoClient|Sequelize|Connection|DataSource)\\s*\\(|\\.(createConnection|connect)\\s*\\(\\s*\\)\\s*;?\\s*$/\n- [ ] Döngü içinde await ile seri DB çağrısı yerine toplu sorgu kullanılmalı — Yasak: /(for\\s*\\([^)]*\\)|while\\s*\\([^)]*\\))\\s*\\{?[^\\n]*\\bawait\\b|\\.forEach\\s*\\(\\s*async\\b/\n- [ ] Yeni davranış için birim/entegrasyon testi (jest) eklenmeli — Yasak: /\\b(describe|it|test)\\s*\\.\\s*(skip|only|todo)\\s*\\(|\\bx(it|describe)\\s*\\(|\\bfdescribe\\s*\\(/\n- [ ] Ölü kod ve kullanılmayan bağımlılıklar kaldırılmalı — Yasak: /^\\s*\\/\\/\\s*(const|let|var|function|class|import|export|return|await|if\\s*\\(|for\\s*\\()/\n",
  "11-vue-code-review.md": "# Vue.js Code Review Standartları\n\n> Frontend · **Vue 3** (Composition API / `<script setup>`). Dosya deseni: `*.vue`.\n> `- [ ]` maddeleri kural olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] console.log ile çıktı alınmamalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] TypeScript `any` tipi kullanılmamalı ⚙️\n- [ ] `var` yerine const/let kullanılmalı ⚙️\n- [ ] debugger ve alert( bırakılmamalı ⚙️\n- [ ] Sihirli sabitler yerine adlandırılmış sabit/enum kullanılmalı — Yasak: /(?:===|!==|>=|<=)\\s*-?\\d{2,}\\b/\n\n## 2. Vue Bileşen Standartları\n- [ ] <script setup> ve Composition API tercih edilmeli — Yasak: /^\\s*(?:methods|computed|watch)\\s*:\\s*\\{|^\\s*(?:data|created|mounted|beforeDestroy)\\s*\\(\\s*\\)\\s*\\{/\n- [ ] Prop'lar tip ve gereklilikleriyle tanımlanmalı; prop doğrudan mutasyona uğratılmamalı — Yasak: /defineProps\\s*\\(\\s*\\[|\\bprops\\.[A-Za-z0-9_]+\\s*=[^=>]/\n- [ ] v-for ile birlikte benzersiz ve stabil :key kullanılmalı (index key değil) — Yasak: /:key=\"(?:index|idx|i|[A-Za-z0-9_]*Index)\"/\n- [ ] v-if ve v-for aynı elemanda birlikte kullanılmamalı — Yasak: /v-for=[^>]*\\sv-if=|v-if=[^>]*\\sv-for=/\n- [ ] Ağır hesaplamalar için computed kullanılmalı; template içinde metot çağrısıyla tekrarlanmamalı — Yasak: /\\{\\{[^}]*\\.(?:filter|map|sort|reduce)\\s*\\(/\n- [ ] Yan etkiler watch/onMounted içinde; render sırasında yapılmamalı — Yasak: /computed\\s*\\(\\s*(?:async\\s*)?\\(\\s*\\)\\s*=>\\s*\\{[^}]*(?:await\\s|axios\\.|fetch\\s*\\(|\\.value\\s*=[^=])/\n- [ ] Bileşen tek sorumluluğa sahip olmalı; çok büyük bileşenler bölünmeli\n- [ ] Emit edilen event'ler defineEmits ile tiplenmeli — Yasak: /defineEmits\\s*\\(\\s*\\[/\n- [ ] ref/reactive doğru seçilmeli; reactive nesne destructuring ile reaktifliğini kaybetmemeli — Yasak: /(?:const|let)\\s*\\{[^}]*\\}\\s*=\\s*(?:reactive\\s*\\(|props\\b)/\n\n## 3. Durum Yönetimi & Veri Akışı\n- [ ] Global durum için Pinia kullanılmalı; prop drilling'ten kaçınılmalı — Yasak: /export\\s+const\\s+[A-Za-z0-9_]*[Ss]tore\\s*=\\s*reactive\\s*\\(/\n- [ ] Store mutasyonları action'lar üzerinden yapılmalı — Yasak: /\\b[A-Za-z0-9_]*[Ss]tore\\.[A-Za-z0-9_$]+(?:\\.[A-Za-z0-9_$]+)*\\s*=[^=>]/\n- [ ] API çağrıları bileşen içinde dağıtılmak yerine composable/servis katmanında toplanmalı — Yasak: /\\baxios\\s*\\.\\s*(?:get|post|put|patch|delete)\\s*\\(|\\bfetch\\s*\\(\\s*[\"']/\n- [ ] Async veri yüklemede loading/error durumları ele alınmalı\n\n## 4. Güvenlik & Performans\n- [ ] v-html ile doğrulanmamış/kaçışlanmamış içerik basılmamalı (XSS) — Yasak: /v-html\\s*=/\n- [ ] Parola/secret/token/api key bileşene gömülmemeli ⚙️\n- [ ] Büyük listelerde sanallaştırma/sayfalama kullanılmalı\n- [ ] Ağır bileşenler defineAsyncComponent ile lazy yüklenmeli — Yasak: /import\\s+[^;]*from\\s*[\"']{1}(?:echarts|chart\\.js|monaco-editor|pdfjs-dist|three|@fullcalendar)/\n- [ ] watch içinde gereksiz derin (deep) izleme yapılmamalı — Yasak: /deep\\s*:\\s*true/\n- [ ] Bellek sızıntısına karşı event listener/timer onUnmounted'da temizlenmeli\n",
  "12-angular-code-review.md": "# Angular Code Review Standartları\n\n> Frontend · **Angular** (TypeScript / RxJS). Dosya deseni: `*.ts`.\n> `- [ ]` maddeleri kural olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] console.log ile çıktı alınmamalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] TypeScript `any` tipi kullanılmamalı; model arayüzleri tanımlanmalı ⚙️\n- [ ] `var` yerine const/let kullanılmalı ⚙️\n- [ ] debugger ve alert( bırakılmamalı ⚙️\n\n## 2. Bileşen & Şablon\n- [ ] Bileşenler ince olmalı; iş mantığı servislere taşınmalı\n- [ ] Değişmeyen veriler için ChangeDetectionStrategy.OnPush kullanılmalı — Yasak: /changeDetection\\s*:\\s*ChangeDetectionStrategy\\s*\\.\\s*Default/\n- [ ] Şablonda ağır metot çağrısı yapılmamalı; pipe/computed tercih edilmeli — Yasak: /\\{\\{[^}]*[\\w$]\\s*\\([^)]*\\)[^}]*\\}\\}/\n- [ ] *ngFor ile trackBy kullanılmalı — Yasak: /\\*ngFor\\s*=\\s*[\"']\\s*(?:(?!trackBy)[^\"'])*[\"']/\n- [ ] DOM'a doğrudan erişim yerine Renderer2/Angular API kullanılmalı — Yasak: /document\\.(getElementById|querySelector|querySelectorAll|createElement|write)\\s*\\(|\\.nativeElement\\.(style|innerHTML|classList|appendChild|setAttribute)/\n- [ ] Şablona iç HTML basarken innerHTML sanitizasyonu ihmal edilmemeli (XSS) — Yasak: /\\[innerHTML\\]\\s*=|bypassSecurityTrust(Html|Script|Url|ResourceUrl|Style)\\s*\\(/\n\n## 3. RxJS & Async\n- [ ] Subscription'lar takeUntil/async pipe ile temizlenmeli; bellek sızıntısı olmamalı — Yasak: /\\.pipe\\s*\\((?:(?!takeUntil|takeUntilDestroyed|take\\s*\\(|first\\s*\\()[^\\n])*\\)\\s*\\.subscribe\\s*\\(/\n- [ ] İç içe subscribe yerine switchMap/mergeMap operatörleri kullanılmalı — Yasak: /\\.subscribe\\s*\\([^\\n]*\\.subscribe\\s*\\(/\n- [ ] Observable'lar bileşende manuel unsubscribe edilmeli veya async pipe ile bağlanmalı — Yasak: /^\\s*this\\.[\\w$][^;=\\n]*\\.subscribe\\s*\\(/\n- [ ] Gereksiz tekrar HTTP çağrısı için shareReplay/cache kullanılmalı\n\n## 4. Güvenlik & Mimari\n- [ ] Parola/secret/token/api key bileşene gömülmemeli; environment kullanılmalı ⚙️\n- [ ] HTTP çağrıları HttpClient ve interceptor ile merkezileştirilmeli — Yasak: /(^|[^.\\w])fetch\\s*\\(|\\baxios\\s*[.(]|new\\s+XMLHttpRequest\\s*\\(/\n- [ ] Servisler DI ile sağlanmalı; new ile elle örneklenmemeli — Yasak: /=\\s*new\\s+[A-Z][\\w$]*(Service|Store|Facade|Repository|Api)\\s*\\(/\n- [ ] Route'lar lazy loading ile modüllere bölünmeli\n- [ ] Form doğrulaması Reactive Forms ile yapılmalı — Yasak: /\\[\\(ngModel\\)\\]|\\bngModel\\s*=|\\bFormsModule\\b/\n- [ ] Yeni davranış için birim testi (Jasmine/Karma) eklenmeli — Yasak: /\\b(describe|it)\\s*\\.\\s*(skip|only)\\s*\\(|\\bx(it|describe)\\s*\\(|\\bfdescribe\\s*\\(|\\bfit\\s*\\(/\n",
  "13-ruby-rails-code-review.md": "# Ruby on Rails Code Review Standartları\n\n> Backend · **Ruby** (Rails). Dosya deseni: `*.rb`.\n> `- [ ]` maddeleri kural olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] print( / puts ile hata ayıklama çıktısı bırakılmamalı — Rails.logger kullanılmalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] Metod/değişken snake_case, sınıf/modül CamelCase olmalı — Yasak: /\\bdef\\s+[a-z_]*[A-Z]|\\b(class|module)\\s+[a-z]/\n- [ ] Sihirli sabitler yerine adlandırılmış sabit kullanılmalı — Yasak: /(==|>=|<=|>|<)\\s*\\d{3,}|\\.(limit|take|sleep)\\s*\\(?\\s*\\d{2,}/\n- [ ] Metotlar kısa ve tek sorumlu olmalı; RuboCop uyarıları giderilmeli — Yasak: /rubocop:disable/\n\n## 2. Güvenlik\n- [ ] Parola/secret/token/api key koda gömülmemeli; credentials/ENV kullanılmalı ⚙️\n- [ ] eval( / send ile doğrulanmamış girdi çalıştırılmamalı ⚙️ — Yasak: /\\b(eval|instance_eval|class_eval)\\s*\\(|\\.(send|public_send)\\s*\\(\\s*params\\[/\n- [ ] SQL için parametreli sorgu/ActiveRecord kullanılmalı; string interpolation yasak — Yasak: /(where|find_by_sql|execute|order|group|select)\\s*\\(?\\s*[\"'][^\"']*#\\{/\n- [ ] Toplu atama için strong parameters (permit) kullanılmalı — Yasak: /\\.(new|create|create!|update|update!|update_attributes)\\s*\\(\\s*params\\[/\n- [ ] Çıktı ERB'de otomatik kaçışlanmalı; html_safe / raw dikkatli kullanılmalı — Yasak: /\\.html_safe\\b|\\braw\\s*\\(|sanitize:\\s*false/\n- [ ] CSRF koruması (protect_from_forgery) etkin olmalı — Yasak: /skip_before_action\\s+:verify_authenticity_token|protect_from_forgery\\s+with:\\s*:null_session/\n\n## 3. Rails Standartları\n- [ ] Controller ince olmalı; iş mantığı model/service objesine taşınmalı (fat model, skinny controller)\n- [ ] N+1 sorgu için includes (eager loading) kullanılmalı — Yasak: /\\.all\\.each\\b|\\.where\\([^)]*\\)\\.each\\b|\\.each\\s*do\\s*\\|\\w+\\|\\s*\\w+\\.\\w+\\.(count|sum|first|where)/\n- [ ] Model callback'leri aşırı kullanılmamalı; karmaşık akış service objelerine alınmalı — Yasak: /^\\s*(after_save|after_create|after_commit|before_save|before_create)\\s+[:{]/\n- [ ] Uzun işlemler Active Job / Sidekiq'e taşınmalı — Yasak: /\\.deliver_now\\b|Net::HTTP\\.(get|post|start)|\\bsleep\\s+\\d/\n- [ ] Veritabanı sorguları scope/where ile yazılmalı; Ruby tarafında filtreleme yapılmamalı — Yasak: /\\.(all|to_a)\\.(select|reject|find_all|sort_by|detect|count)\\s*(\\{|do\\b)/\n- [ ] Migration'lar geri alınabilir (reversible) olmalı — Yasak: /^\\s*execute\\s+[\"']|^\\s*def\\s+down\\b/\n\n## 4. Hata Yönetimi & Test\n- [ ] Boş rescue ile istisna yutulmamalı ⚙️\n- [ ] rescue => e yerine belirli istisna sınıfları yakalanmalı — Yasak: /rescue\\s*=>\\s*\\w+|rescue\\s+(StandardError|Exception)\\b/\n- [ ] Yeni davranış için RSpec/Minitest testi eklenmeli — Yasak: /^\\s*(xit|xdescribe|xcontext|pending)\\b|^\\s*skip\\s+[\"']/\n- [ ] Ölü kod ve yorum satırına alınmış blok bırakılmamalı\n",
  "14-rust-code-review.md": "# Rust Code Review Standartları\n\n> Backend · **Rust**. Dosya deseni: `*.rs`.\n> `- [ ]` maddeleri kural olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] println! / dbg! ile hata ayıklama çıktısı bırakılmamalı — log/tracing kullanılmalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] İsimlendirme snake_case (fonksiyon/değişken), CamelCase (tip), UPPER_CASE (const) olmalı — Yasak: /\\bfn\\s+[a-z_]*[A-Z]|\\b(struct|enum|trait)\\s+[a-z]|\\bconst\\s+[a-z]/\n- [ ] cargo fmt ve cargo clippy uyarıları giderilmeli — Yasak: /#!?\\[allow\\(\\s*(clippy::|dead_code|unused)/\n- [ ] Sihirli sabitler yerine const/enum kullanılmalı — Yasak: /(==|>=|<=|>|<)\\s*\\d{3,}|from_(secs|millis)\\(\\s*\\d{2,}/\n\n## 2. Hata Yönetimi (Rust'a özgü)\n- [ ] .unwrap() / .expect() üretim kodunda gelişigüzel kullanılmamalı; ? ile yayılmalı — Yasak: /\\.(unwrap|expect)\\s*\\(/\n- [ ] panic!( üretim akışında kullanılmamalı ⚙️ — Yasak: /\\b(panic|unimplemented|unreachable|todo)!\\s*\\(/\n- [ ] Result/Option uygun şekilde ele alınmalı; hatalar yutulmamalı — Yasak: /^\\s*let\\s+_\\s*=\\s|\\.ok\\(\\)\\s*;|\\.unwrap_or_else\\(\\s*\\|_\\|/\n- [ ] Özel hata tipleri (thiserror/anyhow) ile bağlam eklenmeli — Yasak: /Box<dyn\\s+[^>]*Error|Err\\(\\s*\"|Err\\(\\s*format!/\n- [ ] `unsafe` blok yalnız gerekli ve gerekçeli kullanılmalı, yorumla açıklanmalı\n\n## 3. Sahiplik & Performans\n- [ ] Gereksiz .clone() ile kopyalama yapılmamalı; referans/borrow tercih edilmeli — Yasak: /\\.clone\\(\\)\\.clone\\(\\)|&[A-Za-z_]\\w*\\.clone\\(\\)|\\.to_vec\\(\\)\\.clone\\(\\)|\\.clone\\(\\)\\.(into|to_string)\\(\\)/\n- [ ] String yerine mümkünse &str, Vec yerine dilim parametre alınmalı — Yasak: /fn\\s+\\w+\\s*(<[^>]*>)?\\s*\\([^)]*:\\s*(String|Vec\\s*<)/\n- [ ] Döngüde gereksiz tahsis yapılmamalı; kapasite önceden ayrılmalı (with_capacity) — Yasak: /for\\s+\\w+\\s+in\\s+[^{]*\\{[^}]*(Vec::new|String::new|vec!|to_string\\(\\)|to_vec\\(\\))/\n- [ ] Blocking I/O async runtime içinde çağrılmamalı (tokio) — Yasak: /std::thread::sleep|std::fs::(read|write|File|remove|create)|reqwest::blocking|\\.blocking_(send|recv|lock|read|write)\\(/\n\n## 4. Güvenlik & Test\n- [ ] Parola/secret/token/api key koda gömülmemeli; env kullanılmalı ⚙️\n- [ ] SQL için parametreli sorgu (sqlx/diesel) kullanılmalı — Yasak: /(query|query_as|execute|sql_query)\\s*\\(\\s*&?format!|(SELECT|INSERT|UPDATE|DELETE)[^\"]*\\{\\}/\n- [ ] Public API öğeleri doc comment (///) ile belgelenmeli\n- [ ] Yeni davranış için test / entegrasyon testi eklenmeli — Yasak: /#\\[ignore\\]|#\\[cfg\\(ignore\\)\\]/\n",
  "15-kotlin-code-review.md": "# Kotlin Code Review Standartları\n\n> Backend · **Kotlin** (Spring Boot / Ktor / Android dışı sunucu). Dosya deseni: `*.kt`.\n> `- [ ]` maddeleri kural olarak okunur. ⚙️ = otomatik denetlenir.\n\n## 1. Genel Kod Kalitesi\n- [ ] println( ile çıktı alınmamalı — logger (SLF4J) kullanılmalı ⚙️\n- [ ] Kodda TODO/FIXME bırakılmamalı ⚙️\n- [ ] Gereksiz yorum satırı bulunmamalı ⚙️\n- [ ] İsimlendirme: fonksiyon/değişken camelCase, sınıf PascalCase, sabit UPPER_CASE — Yasak: /\\bfun\\s+[A-Z]|\\b(class|interface|object)\\s+[a-z]|\\b(val|var)\\s+\\w*_\\w/\n- [ ] ktlint/detekt uyarıları giderilmeli — Yasak: /@Suppress\\s*\\(|ktlint-disable/\n- [ ] Sihirli sabitler yerine const/enum kullanılmalı — Yasak: /(==|>=|<=|>|<)\\s*\\d{3,}|(delay|Thread\\.sleep)\\s*\\(\\s*\\d{3,}/\n\n## 2. Null Güvenliği & Deyimsel Kotlin\n- [ ] Not-null assertion (cift unlem) gelişigüzel kullanılmamalı; ?. , ?: , let ile ele alınmalı — Yasak: /[\\w\\)\\]]!!/\n- [ ] Değişmezlik için `val` tercih edilmeli; gereksiz `var` kullanılmamalı\n- [ ] Veri taşıyıcılar için data class kullanılmalı — Yasak: /^\\s*(open\\s+|internal\\s+|public\\s+)?class\\s+\\w*(Dto|DTO|Request|Response|Payload|Model)\\b/\n- [ ] when ifadesi enum/sealed için exhaustive olmalı — Yasak: /^\\s*else\\s*->/\n- [ ] Uzantı fonksiyonları uygun ve okunur biçimde kullanılmalı\n\n## 3. Hata Yönetimi & Coroutines\n- [ ] Boş catch bloğu ile istisna yutulmamalı ⚙️\n- [ ] Genel catch (e: Exception) yerine belirli tipler yakalanmalı — Yasak: /catch\\s*\\(\\s*\\w+\\s*:\\s*(Exception|Throwable|RuntimeException)\\s*\\)/\n- [ ] runBlocking üretim kodunda kullanılmamalı; suspend fonksiyon zinciri korunmalı — Yasak: /\\brunBlocking\\s*[({]|\\.getCompleted\\(\\)|Thread\\.sleep\\s*\\(/\n- [ ] Coroutine'ler yapılandırılmış eşzamanlılık (scope) ile başlatılmalı; GlobalScope kullanılmamalı — Yasak: /\\bGlobalScope\\s*\\.\\s*(launch|async|produce)|CoroutineScope\\s*\\(\\s*Dispatchers\\.\\w+\\s*\\)\\s*\\.\\s*launch/\n- [ ] Dispatcher (IO/Default) işe uygun seçilmeli — Yasak: /Dispatchers\\.(Unconfined|Main)|withContext\\s*\\(\\s*Dispatchers\\.Default\\s*\\)\\s*\\{[^}]*(File|Jdbc|jdbc|http|Http)/\n\n## 4. Güvenlik & Test\n- [ ] Parola/secret/token/api key koda gömülmemeli ⚙️\n- [ ] SQL için parametreli sorgu/ORM kullanılmalı — Yasak: /(createQuery|createNativeQuery|execSQL|rawQuery|executeQuery|@Query)\\s*\\(?\\s*\"[^\"]*\\$/\n- [ ] Controller/handler ince olmalı; iş mantığı service katmanında olmalı — Yasak: /class\\s+\\w+(Controller|Handler|Resource)\\s*\\([^)]*(Repository|EntityManager|JdbcTemplate|DataSource)/\n- [ ] Yeni davranış için birim testi (JUnit/Kotest) eklenmeli — Yasak: /@(Ignore|Disabled)\\b|\\bxit\\s*\\(/\n",
}
